local function ApplyLeafCardModel(model, unitToken)
  if not model or not unitToken then
    return
  end

  model:Show()
  if model.SetAlpha then
    model:SetAlpha(1)
  end
  model:ClearModel()
  if model.SetUnit then
    model:SetUnit(unitToken)
  end
  if model.SetCamera then
    model:SetCamera(0)
  end
  if model.SetPortraitZoom then
    model:SetPortraitZoom(0)
  end
  if model.SetCamDistanceScale then
    model:SetCamDistanceScale(1.22)
  end
  if model.SetModelScale then
    model:SetModelScale(1.0)
  end
  if model.SetPosition then
    model:SetPosition(0, 0, 0)
  end
  if model.SetFacing then
    model:SetFacing(0.4)
  end
  if model.RefreshUnit then
    model:RefreshUnit()
  end
end

local function QueueLeafCardModelRetry(ui, unitToken)
  if not ui or not ui.cardModel or not unitToken then
    return
  end

  ui.cardModelPendingUnit = unitToken
  ui.cardModel:SetScript("OnUpdate", function()
    this:SetScript("OnUpdate", nil)
    if not ui.cardModelPendingUnit or ui.cardModelPendingUnit ~= unitToken then
      return
    end
    ui.cardModelPendingUnit = nil
    pcall(function()
      ApplyLeafCardModel(this, unitToken)
    end)
  end)
end

LeafVE.uiMinWidth = 1040
LeafVE.uiMaxWidth = 1400
LeafVE.uiDefaultWidth = 1120
LeafVE.uiMinHeight = 760
LeafVE.uiMaxHeight = 1000
LeafVE.uiDefaultHeight = 780

function LeafVE:ClampUISize(width, height)
  local w = tonumber(width) or self.uiDefaultWidth
  local h = tonumber(height) or self.uiDefaultHeight
  if w < self.uiMinWidth then w = self.uiMinWidth end
  if w > self.uiMaxWidth then w = self.uiMaxWidth end
  if h < self.uiMinHeight then h = self.uiMinHeight end
  if h > self.uiMaxHeight then h = self.uiMaxHeight end
  return w, h
end

function LeafVE:ApplyUISize(width, height)
  if not LeafVE_DB then LeafVE_DB = {} end
  if not LeafVE_DB.ui then LeafVE_DB.ui = {} end
  local w, h = self:ClampUISize(width, height)
  LeafVE_DB.ui.w = w
  LeafVE_DB.ui.h = h
  if self.UI and self.UI.frame then
    self.UI.frame:SetWidth(w)
    self.UI.frame:SetHeight(h)
  end
  if self.UI and self.UI.RefreshOptions then
    self.UI:RefreshOptions()
  end
  return w, h
end

function LeafVE:ResetUISize()
  return self:ApplyUISize(self.uiDefaultWidth, self.uiDefaultHeight)
end

function LeafVE:HideStaleUIFrames(activeFrame)
  if type(EnumerateFrames) ~= "function" then
    return
  end

  local frame = EnumerateFrames()
  while frame do
    if frame ~= activeFrame and frame.Hide and frame.IsShown and frame:IsShown() then
      local isLeafFrame = frame.leafVEFrame == true
      if not isLeafFrame and frame.panels and frame.shellSearchBox and frame.dragHandle then
        isLeafFrame = true
      end
      if isLeafFrame then
        frame:Hide()
      end
    end
    frame = EnumerateFrames(frame)
  end
end

local function MakeResizeHandle(f)
  if f._resize then return end
  if f.SetResizable then f:SetResizable(true) end
  if f.SetMinResize then f:SetMinResize(LeafVE.uiMinWidth, LeafVE.uiMinHeight) end
  if f.SetMaxResize then f:SetMaxResize(LeafVE.uiMaxWidth, LeafVE.uiMaxHeight) end
  if f.SetClampedToScreen then f:SetClampedToScreen(true) end
  local grip = CreateFrame("Button", nil, f)
  SetSize(grip, 22, 22)
  grip:SetPoint("BOTTOMRIGHT", f, "BOTTOMRIGHT", -4, 4)
  grip:SetNormalTexture("Interface\\ChatFrame\\UI-ChatIM-SizeGrabber-Up")
  grip:SetHighlightTexture("Interface\\ChatFrame\\UI-ChatIM-SizeGrabber-Highlight")
  grip:SetPushedTexture("Interface\\ChatFrame\\UI-ChatIM-SizeGrabber-Down")
  grip:SetScript("OnMouseDown", function() if f.StartSizing then f:StartSizing("BOTTOMRIGHT") end end)
  grip:SetScript("OnMouseUp", function()
    if f.StopMovingOrSizing then 
      f:StopMovingOrSizing()
      LeafVE:ApplyUISize(f:GetWidth(), f:GetHeight())
    end 
  end)
  f._resize = grip
end

local function GetLeafButtonFontString(btn)
  if not btn then
    return nil
  end
  if btn.GetFontString and btn:GetFontString() then
    return btn:GetFontString()
  end
  return btn.text
end

local function ApplyLeafButtonSkin(btn, style)
  if not btn then
    return
  end

  style = style or "dialog"

  if btn._leafButtonSkin == style then
    return
  end

  local normalTexture = LEAFVE_TEXTURES.buttonUp
  local pushedTexture = LEAFVE_TEXTURES.buttonDown
  local highlightTexture = LEAFVE_TEXTURES.buttonHighlight
  local disabledTexture = LEAFVE_TEXTURES.buttonDisabled
  local normalAlpha = 0.60
  local pushedAlpha = 0.72
  local highlightAlpha = 0.28
  local disabledAlpha = 0.55

  if style == "mode" then
    normalTexture = LEAFVE_TEXTURES.panelButtonUp
    pushedTexture = LEAFVE_TEXTURES.panelButtonDown
    highlightTexture = LEAFVE_TEXTURES.panelButtonHighlight
    disabledTexture = LEAFVE_TEXTURES.panelButtonDisabled
    normalAlpha = 0.44
    pushedAlpha = 0.58
    highlightAlpha = 0.24
    disabledAlpha = 0.42
  end

  btn:SetNormalTexture(normalTexture)
  btn:SetPushedTexture(pushedTexture)
  btn:SetHighlightTexture(highlightTexture)
  btn:SetDisabledTexture(disabledTexture)

  if btn.GetNormalTexture and btn:GetNormalTexture() then
    btn:GetNormalTexture():SetAllPoints(btn)
    btn:GetNormalTexture():SetTexCoord(0, 1, 0, 1)
    btn:GetNormalTexture():SetVertexColor(1, 1, 1, normalAlpha)
  end
  if btn.GetPushedTexture and btn:GetPushedTexture() then
    btn:GetPushedTexture():SetAllPoints(btn)
    btn:GetPushedTexture():SetTexCoord(0, 1, 0, 1)
    btn:GetPushedTexture():SetVertexColor(1, 1, 1, pushedAlpha)
  end
  if btn.GetHighlightTexture and btn:GetHighlightTexture() then
    btn:GetHighlightTexture():SetAllPoints(btn)
    btn:GetHighlightTexture():SetTexCoord(0, 1, 0, 1)
    btn:GetHighlightTexture():SetBlendMode("ADD")
    btn:GetHighlightTexture():SetVertexColor(1, 1, 1, highlightAlpha)
  end
  if btn.GetDisabledTexture and btn:GetDisabledTexture() then
    btn:GetDisabledTexture():SetAllPoints(btn)
    btn:GetDisabledTexture():SetTexCoord(0, 1, 0, 1)
    btn:GetDisabledTexture():SetVertexColor(0.55, 0.55, 0.55, disabledAlpha)
  end

  if not btn._leafSelectionFill then
    local fill = btn:CreateTexture(nil, "BACKGROUND")
    fill:SetTexture(LEAFVE_TEXTURES.listHighlight2)
    fill:SetBlendMode("ADD")
    fill:SetPoint("TOPLEFT", btn, "TOPLEFT", 3, -3)
    fill:SetPoint("BOTTOMRIGHT", btn, "BOTTOMRIGHT", -3, 3)
    fill:Hide()
    btn._leafSelectionFill = fill
  end

  if not btn._leafGlow then
    local glow = btn:CreateTexture(nil, "ARTWORK")
    glow:SetTexture(LEAFVE_TEXTURES.panelButtonGlow)
    glow:SetBlendMode("ADD")
    glow:SetPoint("TOPLEFT", btn, "TOPLEFT", -14, 10)
    glow:SetPoint("BOTTOMRIGHT", btn, "BOTTOMRIGHT", 14, -10)
    glow:SetVertexColor(THEME.leaf[1], THEME.leaf[2], THEME.leaf[3], style == "mode" and 0.34 or 0.46)
    glow:Hide()
    btn._leafGlow = glow
  end

  if not btn._leafOutline then
    local outline = btn:CreateTexture(nil, "OVERLAY")
    outline:SetTexture(LEAFVE_TEXTURES.buttonOutline)
    outline:SetBlendMode("ADD")
    outline:SetPoint("TOPLEFT", btn, "TOPLEFT", -2, 2)
    outline:SetPoint("BOTTOMRIGHT", btn, "BOTTOMRIGHT", 2, -2)
    outline:SetVertexColor(0.88, 0.78, 0.50, style == "mode" and 0.12 or 0.18)
    btn._leafOutline = outline
  end

  btn._leafButtonSkin = style
end

local function SkinButtonAccent(btn)
  if not btn then return end

  ApplyLeafButtonSkin(btn, btn.leafButtonStyle or "dialog")

  if btn._leafButtonAccentBound then
    return
  end

  local function UpdateButtonText(isHovering)
    local fs = GetLeafButtonFontString(btn)
    if not fs then
      return
    end

    if isHovering then
      if btn.leafHoverTextR then
        fs:SetTextColor(btn.leafHoverTextR, btn.leafHoverTextG or btn.leafHoverTextR, btn.leafHoverTextB or btn.leafHoverTextR)
      else
        fs:SetTextColor(THEME.leaf[1], THEME.leaf[2], THEME.leaf[3])
      end
      if btn._leafGlow and not btn.isSelected then
        btn._leafGlow:Show()
      end
    else
      if btn.leafTextR then
        fs:SetTextColor(btn.leafTextR, btn.leafTextG or btn.leafTextR, btn.leafTextB or btn.leafTextR)
      else
        fs:SetTextColor(1, 1, 1)
      end
      if btn._leafGlow and not btn.isSelected then
        btn._leafGlow:Hide()
      end
    end
  end

  if btn.HookScript then
    btn:HookScript("OnEnter", function() UpdateButtonText(true) end)
    btn:HookScript("OnLeave", function() UpdateButtonText(false) end)
  else
    local prevEnter = btn:GetScript("OnEnter")
    local prevLeave = btn:GetScript("OnLeave")
    btn:SetScript("OnEnter", function()
      if prevEnter then prevEnter() end
      UpdateButtonText(true)
    end)
    btn:SetScript("OnLeave", function()
      if prevLeave then prevLeave() end
      UpdateButtonText(false)
    end)
  end

  btn._leafButtonAccentBound = true
  UpdateButtonText(false)
end

local function SetLeafButtonTextColor(btn, normalR, normalG, normalB, hoverR, hoverG, hoverB)
  if not btn then return end
  btn.leafTextR = normalR
  btn.leafTextG = normalG
  btn.leafTextB = normalB
  btn.leafHoverTextR = hoverR or normalR
  btn.leafHoverTextG = hoverG or normalG
  btn.leafHoverTextB = hoverB or normalB

  local fs = GetLeafButtonFontString(btn)
  if fs then
    fs:SetTextColor(normalR, normalG, normalB)
  end
end

