    LeafVE_GlobalDB.guildBankRequests = nil
    LeafVE_GlobalDB.guildBankHighValueItems = nil
    LeafVE_GlobalDB.guildBankCategoryOverrides = nil
  end
  if not LeafVE_GlobalDB.guildEvents then LeafVE_GlobalDB.guildEvents = {} end
  if not LeafVE_GlobalDB.guildEventRSVPs then LeafVE_GlobalDB.guildEventRSVPs = {} end
  if LeafVE.raidSignupsEnabled == true then
    if not LeafVE_GlobalDB.raidEvents then LeafVE_GlobalDB.raidEvents = {} end
    if not LeafVE_GlobalDB.raidSignups then LeafVE_GlobalDB.raidSignups = {} end
  else
    LeafVE_GlobalDB.raidEvents = nil
    LeafVE_GlobalDB.raidSignups = nil
  end
  if not LeafVE_GlobalDB.fullWipeVersion then LeafVE_GlobalDB.fullWipeVersion = 0 end
  if not LeafVE_DB.badgesArchive then LeafVE_DB.badgesArchive = {} end
  -- Badge bucket follows full-wipe version so manual resets start a fresh badge season.
  local currentBadgeBucket = tonumber(LeafVE_GlobalDB.fullWipeVersion) or 0
  local storedBadgeBucket = tonumber(LeafVE_DB.badgeBucketVersion)
  if LeafVE_DB.badgeBucketMigrated ~= true then
    -- One-time migration for clients that had pre-bucket badge data.
    if currentBadgeBucket > 0 and type(LeafVE_DB.badges) == "table" and next(LeafVE_DB.badges) then
      LeafVE_DB.badgesArchive["legacy"] = LeafVE_DB.badges
      LeafVE_DB.badges = {}
      LeafVE_DB.badgesAnnounced = {}
    end
    LeafVE_DB.badgeBucketVersion = currentBadgeBucket
    LeafVE_DB.badgeBucketMigrated = true
  elseif storedBadgeBucket == nil then
    LeafVE_DB.badgeBucketVersion = currentBadgeBucket
  elseif storedBadgeBucket ~= currentBadgeBucket then
    if type(LeafVE_DB.badges) == "table" and next(LeafVE_DB.badges) then
      LeafVE_DB.badgesArchive[tostring(storedBadgeBucket)] = LeafVE_DB.badges
    end
    LeafVE_DB.badges = {}
    LeafVE_DB.badgesAnnounced = {}
    LeafVE_DB.badgeBucketVersion = currentBadgeBucket
  end
  -- Migration/safety: "__fw" is a transport marker, never a real badge entry.
  for _, badgeMap in pairs(LeafVE_DB.badges or {}) do
    if type(badgeMap) == "table" then
      badgeMap["__fw"] = nil
    end
  end
  PurgeRemovedBadgesFromContainer(LeafVE_DB.badges)
  for _, archivedSeason in pairs(LeafVE_DB.badgesArchive or {}) do
    PurgeRemovedBadgesFromContainer(archivedSeason)
  end
  for announcedKey in pairs(LeafVE_DB.badgesAnnounced or {}) do
    if announcedKey == "first_login" or (type(announcedKey) == "string" and string.sub(announcedKey, -12) == ":first_login") then
      LeafVE_DB.badgesAnnounced[announcedKey] = nil
    end
  end
  if LeafVE_DB.options.groupPoints == nil then LeafVE_DB.options.groupPoints = GROUP_POINTS end
  if LeafVE_DB.options.loginPoints == nil then LeafVE_DB.options.loginPoints = 20 end
  if not LeafVE_DB.raidProfile then LeafVE_DB.raidProfile = {} end
  if LeafVE_DB.raidProfile.defaultRole == nil then LeafVE_DB.raidProfile.defaultRole = "" end
end

local function LboardEntryTotal(entry)
  return entry and ((entry.L or 0) + (entry.G or 0) + (entry.S or 0)) or 0
end

local function SamePlayerName(a, b)
  local an = ShortName(a)
  local bn = ShortName(b)
  if not an or not bn then return false end
  return Lower(an) == Lower(bn)
end

function LeafVE:GetAllianceChannelName()
  return LeafVE.allianceChat.name
end

function LeafVE:GetAllianceChannelPassword()
  return LeafVE.allianceChat.password
end

function LeafVE:GetAllianceDisplayLabel()
  return LeafVE.allianceChat.label
end

function LeafVE:GetAllianceChannelId()
  local channelId = 0
  if type(GetChannelName) == "function" then
    local lookupId = GetChannelName(self:GetAllianceChannelName())
    channelId = tonumber(lookupId) or 0
  end
  if channelId > 0 then
    self.allianceChannelId = channelId
  end
  return channelId
end

function LeafVE:IsAllianceMessageChannel(channelString, channelName, channelNumber)
  local desiredName = Lower(self:GetAllianceChannelName())
  local normalizedString = Lower(Trim(channelString or ""))
  local normalizedName = Lower(Trim(channelName or ""))
  local activeChannelId = self:GetAllianceChannelId()

  if normalizedName ~= "" then
    if normalizedName == desiredName then
      return true
    end
    if string.find(normalizedName, desiredName, 1, true) then
      return true
    end
  end

  if normalizedString ~= "" and string.find(normalizedString, desiredName, 1, true) then
    return true
  end

  if activeChannelId > 0 and tonumber(channelNumber) == activeChannelId then
    return true
  end

  return false
end

function LeafVE:IsAllianceOutgoingChannel(channelTarget)
  local activeChannelId = self:GetAllianceChannelId()
  local desiredName = Lower(self:GetAllianceChannelName())
  local normalizedTarget = Lower(Trim(tostring(channelTarget or "")))

  if normalizedTarget == "" then
    return false
  end
  if normalizedTarget == desiredName then
    return true
  end
  if string.find(normalizedTarget, desiredName, 1, true) then
    return true
  end
  if activeChannelId > 0 and tonumber(channelTarget) == activeChannelId then
    return true
  end

  return false
end

function LeafVE:BuildAllianceOutgoingPrefix()
  return LeafVE.allianceChat.prefixColor .. "[" .. self:GetAllianceDisplayLabel() .. "]|r " .. LeafVE.allianceChat.messageColor
end

function LeafVE:BuildAlliancePlainOutgoingPrefix()
  return "[" .. self:GetAllianceDisplayLabel() .. "] "
end

function LeafVE:StripAllianceChatDecorators(message)
  local text = tostring(message or "")
  local prefix = self:BuildAllianceOutgoingPrefix()
  local plainPrefix = self:BuildAlliancePlainOutgoingPrefix()
  local legacyPlainPrefix = "[Alliance] "

  if string.sub(text, 1, string.len(prefix)) == prefix then
    text = string.sub(text, string.len(prefix) + 1)
    if string.sub(text, -2) == "|r" then
      text = string.sub(text, 1, -3)
    end
  end

  if string.sub(text, 1, string.len(plainPrefix)) == plainPrefix then
    text = string.sub(text, string.len(plainPrefix) + 1)
  end

  if string.sub(text, 1, string.len(legacyPlainPrefix)) == legacyPlainPrefix then
    text = string.sub(text, string.len(legacyPlainPrefix) + 1)
  end

  text = string.gsub(text, "^%[" .. EscapePattern(self:GetAllianceDisplayLabel()) .. "%]%s*", "")
  text = string.gsub(text, "^%[Alliance%]%s*", "")
  return text
end

function LeafVE:BuildAllianceFormattedLine(author, message)
  local displayAuthor = ShortName(author) or Trim(author or "")
  local displayMessage = self:StripAllianceChatDecorators(message)

  if displayAuthor == nil or displayAuthor == "" then
    displayAuthor = "Unknown"
  end

  return LeafVE.allianceChat.prefixColor .. "[" .. self:GetAllianceDisplayLabel() .. "]|r [" .. displayAuthor .. "]: " .. LeafVE.allianceChat.messageColor .. displayMessage .. "|r"
end

function LeafVE:ShouldSuppressAllianceSystemMessage(message)
  local text = Lower(Trim(message or ""))
  local desiredName = Lower(self:GetAllianceChannelName())

  if text == "" or desiredName == "" then
    return false
  end
  if string.find(text, desiredName, 1, true) == nil then
    return false
  end

  return string.find(text, "owner changed to", 1, true) ~= nil
    or string.find(text, "changed owner to", 1, true) ~= nil
    or string.find(text, "joined channel", 1, true) ~= nil
    or string.find(text, "left channel", 1, true) ~= nil
end

function LeafVE:ShouldSuppressAllianceRenderedText(text)
  local rendered = tostring(text or "")
  local hiddenPrefix = LeafVE.allianceChat and LeafVE.allianceChat.hiddenPrefix or ""
  if hiddenPrefix ~= "" and string.find(rendered, hiddenPrefix, 1, true) ~= nil then
    return true
  end
  return self:ShouldSuppressAllianceSystemMessage(rendered)
end

function LeafVE:StripAllianceRenderedMarkup(text)
  local cleaned = tostring(text or "")
  cleaned = string.gsub(cleaned, "|c%x%x%x%x%x%x%x%x", "")
  cleaned = string.gsub(cleaned, "|r", "")
  cleaned = string.gsub(cleaned, "|H.-|h", "")
  cleaned = string.gsub(cleaned, "|h", "")
  return cleaned
end

function LeafVE:TryFormatAllianceRenderedText(text)
  local rendered = tostring(text or "")
  if rendered == "" then
    return nil
  end
  if string.find(rendered, LeafVE.allianceChat.prefixColor, 1, true) ~= nil
    and string.find(rendered, "[" .. self:GetAllianceDisplayLabel() .. "]", 1, true) ~= nil then
    return nil
  end

  local renderedPlain = self:StripAllianceRenderedMarkup(rendered)
  local channelTag, author = string.match(renderedPlain, "^%[([^%]]+)%]%s*%[([^%]]+)%]:")
  if not channelTag then
    channelTag, author = string.match(renderedPlain, "^%[([^%]]+)%]%s*([^:]+):")
  end
  if not channelTag or not author then
    return nil
  end
  if string.find(Lower(channelTag), Lower(self:GetAllianceChannelName()), 1, true) == nil then
    return nil
  end

  local separatorStart, separatorEnd = string.find(rendered, ": ", 1, true)
  local message = ""
  if separatorEnd then
    message = string.sub(rendered, separatorEnd + 1)
  end

  author = Trim(string.gsub(author, "^%[", ""))
  author = Trim(string.gsub(author, "%]$", ""))

  return self:BuildAllianceFormattedLine(author, message)
end

function LeafVE:WrapAllianceChatFrame(frame)
  if not frame or type(frame.AddMessage) ~= "function" or frame.leafVEAllianceWrapped then
    return false
  end

  frame.leafVEAllianceOriginalAddMessage = frame.AddMessage
  frame.AddMessage = function(selfFrame, text, r, g, b, chatTypeID, holdTime, accessID, lineID)
    if LeafVE and LeafVE.ShouldSuppressAllianceRenderedText and LeafVE:ShouldSuppressAllianceRenderedText(text) then
      return
    end
    if LeafVE and LeafVE.TryFormatAllianceRenderedText then
      local formatted = LeafVE:TryFormatAllianceRenderedText(text)
      if formatted then
        return selfFrame.leafVEAllianceOriginalAddMessage(selfFrame, formatted, r, g, b, chatTypeID, holdTime, accessID, lineID)
      end
    end
    return selfFrame.leafVEAllianceOriginalAddMessage(selfFrame, text, r, g, b, chatTypeID, holdTime, accessID, lineID)
  end

  frame.leafVEAllianceWrapped = true
  return true
end

function LeafVE:InstallAllianceRenderedMessageSuppression()
  if self.allianceRenderedSuppressionInstalled then
    return
  end

  self.allianceRenderedSuppressionInstalled = true

  local totalFrames = tonumber(NUM_CHAT_WINDOWS) or 7
  for i = 1, totalFrames do
    self:WrapAllianceChatFrame(_G["ChatFrame" .. tostring(i)])
  end
  self:WrapAllianceChatFrame(DEFAULT_CHAT_FRAME)
  self:WrapAllianceChatFrame(SELECTED_CHAT_FRAME)
end

function LeafVE:HandleAllianceChatFrameMessage(chatFrame, eventName, message, author, languageName, channelString, target, flags, unknown1, channelNumber, channelName, unknown2, counter)
  if eventName == "CHAT_MSG_CHANNEL_NOTICE" or eventName == "CHAT_MSG_CHANNEL_NOTICE_USER" then
    if self:ShouldSuppressAllianceSystemMessage(message) then
      return true
    end
  end

  if eventName == "CHAT_MSG_SYSTEM" and self:ShouldSuppressAllianceSystemMessage(message) then
    return true
  end

  if eventName == "CHAT_MSG_CHANNEL" and self:IsAllianceMessageChannel(channelString, channelName, channelNumber) then
    local formatted = self:BuildAllianceFormattedLine(author, message)
    if chatFrame and chatFrame.AddMessage then
      chatFrame:AddMessage(formatted)
    elseif DEFAULT_CHAT_FRAME and DEFAULT_CHAT_FRAME.AddMessage then
      DEFAULT_CHAT_FRAME:AddMessage(formatted)
    end
    return true
  end

  return false
end

function LeafVE:InstallAllianceChatHandler()
  if self.allianceChatHandlerInstalled and ChatFrame_MessageEventHandler == self.wrappedAllianceMessageEventHandler then
    return
  end
  if type(ChatFrame_MessageEventHandler) ~= "function" then
    return
  end

  self.allianceChatHandlerInstalled = true
  self.originalAllianceMessageEventHandler = ChatFrame_MessageEventHandler
  self.wrappedAllianceMessageEventHandler = function(a1, a2, a3, a4, a5, a6, a7, a8, a9, a10, a11, a12, a13)
    local chatFrame
    local eventName
    local message
    local author
    local languageName
    local channelString
    local target
    local flags
    local unknown1
    local channelNumber
    local channelName
    local unknown2
    local counter

    if type(a1) == "table" and a1.AddMessage then
      chatFrame = a1
      eventName = a2
      message = a3
      author = a4
      languageName = a5
      channelString = a6
      target = a7
      flags = a8
      unknown1 = a9
      channelNumber = a10
      channelName = a11
      unknown2 = a12
      counter = a13
    else
      chatFrame = (type(this) == "table" and this.AddMessage and this) or DEFAULT_CHAT_FRAME
      eventName = a1
      message = a2
      author = a3
      languageName = a4
      channelString = a5
      target = a6
      flags = a7
      unknown1 = a8
      channelNumber = a9
      channelName = a10
      unknown2 = a11
      counter = a12
    end

    if LeafVE and LeafVE.HandleAllianceChatFrameMessage then
      local ok, handled = pcall(
        LeafVE.HandleAllianceChatFrameMessage,
        LeafVE,
        chatFrame,
        eventName,
        message,
        author,
        languageName,
        channelString,
        target,
        flags,
        unknown1,
        channelNumber,
        channelName,
        unknown2,
        counter
      )
      if ok and handled then
        return
      end
      if not ok then
        Print("Alliance chat handler error: " .. tostring(handled))
      end
    end

    return LeafVE.originalAllianceMessageEventHandler(a1, a2, a3, a4, a5, a6, a7, a8, a9, a10, a11, a12, a13)
  end

  ChatFrame_MessageEventHandler = self.wrappedAllianceMessageEventHandler
end

function LeafVE:InstallAllianceSendHook()
  if self.allianceSendHookInstalled and SendChatMessage == self.wrappedAllianceSendChatMessage then
    return
  end
  if type(SendChatMessage) ~= "function" then
    return
  end

  self.allianceSendHookInstalled = true
  self.originalAllianceSendChatMessage = SendChatMessage
  self.wrappedAllianceSendChatMessage = function(msg, chatType, language, channel)
    local outgoing = msg
    if LeafVE and chatType == "CHANNEL" and type(msg) == "string" and msg ~= "" and string.sub(msg, 1, 1) ~= "/" then
      if LeafVE:IsAllianceOutgoingChannel(channel) then
        outgoing = LeafVE:BuildAlliancePlainOutgoingPrefix() .. LeafVE:StripAllianceChatDecorators(msg)
      end
    end
    return LeafVE.originalAllianceSendChatMessage(outgoing, chatType, language, channel)
  end

  SendChatMessage = self.wrappedAllianceSendChatMessage
end

function LeafVE:InstallAllianceChatSupport()
  self:InstallAllianceRenderedMessageSuppression()
  self:InstallAllianceChatHandler()
end

function LeafVE:ApplyAllianceChannelColor(channelId)
  channelId = tonumber(channelId) or self:GetAllianceChannelId()
  if channelId <= 0 then
    return false
  end

  local channelKey = "CHANNEL" .. tostring(channelId)
  local color = LeafVE.allianceChat.color

  if ChatTypeInfo and ChatTypeInfo[channelKey] then
    ChatTypeInfo[channelKey].r = color[1]
    ChatTypeInfo[channelKey].g = color[2]
    ChatTypeInfo[channelKey].b = color[3]
  end

  if type(ChangeChatColor) == "function" then
    pcall(ChangeChatColor, channelKey, color[1], color[2], color[3])
  end
  if type(ChangeChatColorByID) == "function" then
    pcall(ChangeChatColorByID, channelId, color[1], color[2], color[3])
  end

  return true
end

function LeafVE:EnsureAllianceChannelVisible(channelName)
  channelName = channelName or self:GetAllianceChannelName()
  if type(ChatFrame_AddChannel) == "function" then
    if DEFAULT_CHAT_FRAME then
      pcall(ChatFrame_AddChannel, DEFAULT_CHAT_FRAME, channelName)
    end
    if SELECTED_CHAT_FRAME and SELECTED_CHAT_FRAME ~= DEFAULT_CHAT_FRAME then
      pcall(ChatFrame_AddChannel, SELECTED_CHAT_FRAME, channelName)
    end
  end
end

function LeafVE:OpenAllianceChatInput()
  local channelId = self:GetAllianceChannelId()
  if channelId <= 0 then
    return false
  end
  if type(ChatFrame_OpenChat) == "function" then
    ChatFrame_OpenChat("/" .. tostring(channelId) .. " ")
    return true
  end
  return false
end

function LeafVE:FinalizeAllianceChannelJoin(channelId, announce, openInput)
  channelId = tonumber(channelId) or self:GetAllianceChannelId()
  if channelId <= 0 then
    return false
  end

  self.allianceChannelId = channelId
  self.lastAllianceAutoJoinAttemptAt = Now()
  self:EnsureAllianceChannelVisible(self:GetAllianceChannelName())
  self:ApplyAllianceChannelColor(channelId)
  self:InstallAllianceChatSupport()

  if announce then
    Print("Joined alliance chat: [" .. self:GetAllianceChannelName() .. "]")
  end

  if openInput then
    self:OpenAllianceChatInput()
  end

  return true
end

function LeafVE:JoinAllianceChannel(openInput, announce)
  EnsureDB()
  self:InstallAllianceChatSupport()

  local channelName = self:GetAllianceChannelName()
  local channelId = self:GetAllianceChannelId()
  if channelId > 0 then
    return self:FinalizeAllianceChannelJoin(channelId, announce, openInput)
  end

  if type(JoinChannelByName) ~= "function" then
    return false
  end

  JoinChannelByName(channelName, self:GetAllianceChannelPassword() ~= "" and self:GetAllianceChannelPassword() or nil)

  self.pendingAllianceOpenInput = openInput and true or false
  self.pendingAllianceAnnounceJoin = announce and true or false

  if announce then
    Print("Joining alliance chat [" .. channelName .. "]...")
  end

  self:ScheduleDeferred("leafve_alliance_join_retry", 0.7, function()
    local retryChannelId = LeafVE:GetAllianceChannelId()
    local shouldOpenInput = LeafVE.pendingAllianceOpenInput and true or false
    local shouldAnnounce = LeafVE.pendingAllianceAnnounceJoin and true or false
    LeafVE.pendingAllianceOpenInput = nil
    LeafVE.pendingAllianceAnnounceJoin = nil

    if retryChannelId > 0 then
      LeafVE:FinalizeAllianceChannelJoin(retryChannelId, shouldAnnounce, shouldOpenInput)
    elseif shouldAnnounce then
      Print("Unable to join alliance chat [" .. channelName .. "].")
    end
  end)

  return true
end

function LeafVE:MaybeAutoJoinAlliance(force)
  EnsureDB()

  if LeafVE_DB.options.allianceAutoJoin ~= true then
    return false
  end

  local guildName = GetGuildInfo and GetGuildInfo("player") or nil
  if Trim(guildName or "") == "" then
    return false
  end

  local now = Now()
  local channelId = self:GetAllianceChannelId()
  if channelId > 0 then
    self.allianceChannelId = channelId
    self.lastAllianceAutoJoinAttemptAt = now
    self:EnsureAllianceChannelVisible(self:GetAllianceChannelName())
    self:ApplyAllianceChannelColor(channelId)
    self:InstallAllianceChatSupport()
    return true
  end

  self.lastAllianceAutoJoinAttemptAt = now
  return self:JoinAllianceChannel(false, false)
end

local function CurrentWipeVersion()
  return (LeafVE_GlobalDB and tonumber(LeafVE_GlobalDB.fullWipeVersion)) or 0
end

local function PointBucketForEntry(entry)
  if type(entry) ~= "table" then return 0 end
  return tonumber(entry._b) or 0
end

local function IsPointEntryInCurrentBucket(entry)
  return PointBucketForEntry(entry) == CurrentWipeVersion()
end

local function EnsurePointEntryCurrentBucket(container, key)
  if type(container) ~= "table" then
    return {L = 0, G = 0, S = 0, _b = CurrentWipeVersion()}
  end
  local entry = container[key]
  local bucket = CurrentWipeVersion()
  if type(entry) ~= "table" or PointBucketForEntry(entry) ~= bucket then
    entry = {L = 0, G = 0, S = 0, _b = bucket}
    container[key] = entry
    return entry
  end
  if entry.L == nil then entry.L = 0 end
  if entry.G == nil then entry.G = 0 end
  if entry.S == nil then entry.S = 0 end
  entry._b = bucket
  return entry
end

local function SetWeeklyEntryWipeVersion(wk, name, wipeVersion)
  EnsureDB()
  wk = wk or WeekKey()
  name = ShortName(name)
  if not name then return end
  if type(LeafVE_DB.lboard.weeklyVersion[wk]) ~= "table" then
    LeafVE_DB.lboard.weeklyVersion[wk] = {}
  end
  LeafVE_DB.lboard.weeklyVersion[wk][name] = tonumber(wipeVersion) or CurrentWipeVersion()
end

local function GetWeeklyEntryWipeVersion(wk, name)
  wk = wk or WeekKey()
  name = ShortName(name)
  if not name then return nil end
  local wkMap = LeafVE_DB and LeafVE_DB.lboard and LeafVE_DB.lboard.weeklyVersion and LeafVE_DB.lboard.weeklyVersion[wk]
  if type(wkMap) ~= "table" then return nil end
  return tonumber(wkMap[name])
end

local function ClearWeeklyEntryWipeVersion(wk, name)
  wk = wk or WeekKey()
  name = ShortName(name)
  if not name then return end
  local wkMap = LeafVE_DB and LeafVE_DB.lboard and LeafVE_DB.lboard.weeklyVersion and LeafVE_DB.lboard.weeklyVersion[wk]
  if type(wkMap) == "table" then
    wkMap[name] = nil
  end
end

local function PruneLeaderboardForCurrentWipe()
  EnsureDB()
  local currentVersion = CurrentWipeVersion()
  if currentVersion <= 0 then return end

  for name, _ in pairs(LeafVE_DB.lboard.alltime or {}) do
    local meta = LeafVE_DB.lboard.updatedAt[name]
    local entryVersion = type(meta) == "table" and tonumber(meta.lifetimeWipeVersion) or nil
    if entryVersion ~= currentVersion then
      LeafVE_DB.lboard.alltime[name] = nil
      if LeafVE_GlobalDB.lboardCache and LeafVE_GlobalDB.lboardCache.alltime then
        LeafVE_GlobalDB.lboardCache.alltime[name] = nil
      end
    end
  end

  for wk, wkData in pairs(LeafVE_DB.lboard.weekly or {}) do
    if type(wkData) == "table" then
      local wkVersions = type(LeafVE_DB.lboard.weeklyVersion[wk]) == "table" and LeafVE_DB.lboard.weeklyVersion[wk] or {}
      for name, _ in pairs(wkData) do
        local entryVersion = tonumber(wkVersions[name])
        if entryVersion ~= currentVersion then
          wkData[name] = nil
          wkVersions[name] = nil
        end
      end
    end
  end
end

local function StoreLifetimeSnapshot(name, L, G, S, sourceName, authoritative, overwriteSharedCache)
  EnsureDB()
  name = ShortName(name)
  if not name then return end

  L = tonumber(L) or 0
  G = tonumber(G) or 0
  S = tonumber(S) or 0
  if (L + G + S) <= 0 then return end

  LeafVE_DB.lboard.alltime[name] = {L = L, G = G, S = S}
  if type(LeafVE_DB.lboard.updatedAt[name]) ~= "table" then
    LeafVE_DB.lboard.updatedAt[name] = {}
  end
  LeafVE_DB.lboard.updatedAt[name].lifetime = Now()
  LeafVE_DB.lboard.updatedAt[name].lifetimeSource = ShortName(sourceName) or sourceName or name
  LeafVE_DB.lboard.updatedAt[name].lifetimeAuthoritative = authoritative and true or false
  LeafVE_DB.lboard.updatedAt[name].lifetimeWipeVersion = CurrentWipeVersion()

  if overwriteSharedCache then
    if not LeafVE_GlobalDB.lboardCache then
      LeafVE_GlobalDB.lboardCache = { alltime = {}, weekly = {} }
    end
    if not LeafVE_GlobalDB.lboardCache.alltime then
      LeafVE_GlobalDB.lboardCache.alltime = {}
    end
    LeafVE_GlobalDB.lboardCache.alltime[name] = {L = L, G = G, S = S}
  end
end

local function ClearLifetimeSnapshot(name, sourceName, authoritative)
  EnsureDB()
  name = ShortName(name)
  if not name then return end

  LeafVE_DB.lboard.alltime[name] = nil
  if type(LeafVE_DB.lboard.updatedAt[name]) ~= "table" then
    LeafVE_DB.lboard.updatedAt[name] = {}
  end
  LeafVE_DB.lboard.updatedAt[name].lifetime = Now()
  LeafVE_DB.lboard.updatedAt[name].lifetimeSource = ShortName(sourceName) or sourceName or name
  LeafVE_DB.lboard.updatedAt[name].lifetimeAuthoritative = authoritative and true or false
  LeafVE_DB.lboard.updatedAt[name].lifetimeWipeVersion = CurrentWipeVersion()

  if LeafVE_GlobalDB.lboardCache and LeafVE_GlobalDB.lboardCache.alltime then
    LeafVE_GlobalDB.lboardCache.alltime[name] = nil
  end
end

local function GetBadgeProgressCacheEntry(playerName, createIfMissing)
  EnsureDB()
  local name = ShortName(playerName)
  if not name then return nil, nil end

  if not LeafVE_GlobalDB.badgeProgressCache then
    LeafVE_GlobalDB.badgeProgressCache = {}
  end

  local entry = LeafVE_GlobalDB.badgeProgressCache[name]
  if type(entry) ~= "table" then
    if not createIfMissing then
      return name, nil
    end
    entry = {}
    LeafVE_GlobalDB.badgeProgressCache[name] = entry
  end

  return name, entry
end

local function GetCachedProgressNumber(playerName, field)
  local _, cache = GetBadgeProgressCacheEntry(playerName, false)
  if type(cache) ~= "table" then return 0 end
  if (tonumber(cache.bucket) or 0) ~= CurrentWipeVersion() then return 0 end
  return tonumber(cache[field]) or 0
end

local function GetBestLifetimeEntry(playerName)
  EnsureDB()
  local name = ShortName(playerName)
  if not name then return {L = 0, G = 0, S = 0} end

  local best = nil
  local function Consider(entry)
    if type(entry) ~= "table" then return end
    local normalized = {
      L = tonumber(entry.L) or 0,
      G = tonumber(entry.G) or 0,
      S = tonumber(entry.S) or 0,
    }
    if LboardEntryTotal(normalized) <= 0 then return end
    if not best or LboardEntryTotal(normalized) > LboardEntryTotal(best) then
      best = normalized
    end
  end

  local localAlltime = LeafVE_DB.alltime and LeafVE_DB.alltime[name]
  if IsPointEntryInCurrentBucket(localAlltime) then
    Consider(localAlltime)
  end
  Consider(LeafVE_DB.lboard and LeafVE_DB.lboard.alltime and LeafVE_DB.lboard.alltime[name])
  Consider(LeafVE_GlobalDB.lboardCache and LeafVE_GlobalDB.lboardCache.alltime and LeafVE_GlobalDB.lboardCache.alltime[name])
  local progressCache = LeafVE_GlobalDB.badgeProgressCache and LeafVE_GlobalDB.badgeProgressCache[name]
  if type(progressCache) == "table" and (tonumber(progressCache.bucket) or 0) == CurrentWipeVersion() then
    Consider(progressCache.alltime)
  end

  return best or {L = 0, G = 0, S = 0}
end

local function GetBestGuildieGroupHours(playerName)
  local name = ShortName(playerName)
  if not name then return 0 end

  local localHours = (LeafVE_DB.guildieGroupHours and LeafVE_DB.guildieGroupHours[name]) or 0
  local cachedHours = GetCachedProgressNumber(name, "guildieGroupHours")
  if cachedHours > localHours then
    if not LeafVE_DB.guildieGroupHours then LeafVE_DB.guildieGroupHours = {} end
    LeafVE_DB.guildieGroupHours[name] = cachedHours
    return cachedHours
  end
  return localHours
end

local function GetBestAttendanceCount(playerName)
  local name = ShortName(playerName)
  if not name then return 0 end

  local attendance = (LeafVE_DB.attendance and LeafVE_DB.attendance[name]) or {}
  local localCount = table.getn(attendance)
  local cachedCount = GetCachedProgressNumber(name, "attendance")
  if cachedCount > localCount then
    if not LeafVE_DB.attendance then LeafVE_DB.attendance = {} end
    if not LeafVE_DB.attendance[name] then LeafVE_DB.attendance[name] = {} end
    while table.getn(LeafVE_DB.attendance[name]) < cachedCount do
      table.insert(LeafVE_DB.attendance[name], {})
    end
    return cachedCount
  end
  return localCount
end

local function GetBestLoginStreak(playerName)
  local name = ShortName(playerName)
  if not name then return 0 end

  local localStreak = (LeafVE_DB.loginStreaks and LeafVE_DB.loginStreaks[name] and LeafVE_DB.loginStreaks[name].current) or 0
  local cachedStreak = GetCachedProgressNumber(name, "loginStreak")
  if cachedStreak > localStreak then
    if not LeafVE_DB.loginStreaks then LeafVE_DB.loginStreaks = {} end
    if not LeafVE_DB.loginStreaks[name] then
      LeafVE_DB.loginStreaks[name] = {current = 0}
    end
    LeafVE_DB.loginStreaks[name].current = cachedStreak
    return cachedStreak
  end
  return localStreak
end

local function GetBestGuildJoinDate(playerName)
  local name = ShortName(playerName)
  if not name then return 0 end

  local localJoinDate = (LeafVE_DB.guildJoinDate and LeafVE_DB.guildJoinDate[name]) or 0
  local cachedJoinDate = GetCachedProgressNumber(name, "guildJoinDate")

  if localJoinDate > 0 and cachedJoinDate > 0 then
    local earliest = math.min(localJoinDate, cachedJoinDate)
    if not LeafVE_DB.guildJoinDate then LeafVE_DB.guildJoinDate = {} end
    LeafVE_DB.guildJoinDate[name] = earliest
    return earliest
  elseif cachedJoinDate > 0 then
    if not LeafVE_DB.guildJoinDate then LeafVE_DB.guildJoinDate = {} end
    LeafVE_DB.guildJoinDate[name] = cachedJoinDate
    return cachedJoinDate
  end

  return localJoinDate
end

local function AggregateGlobalTotalsForPlayer(playerName)
  EnsureDB()
  local name = ShortName(playerName)
  if not name then return {L = 0, G = 0, S = 0} end

  local totals = {L = 0, G = 0, S = 0}
  local bucket = CurrentWipeVersion()
  for _, dayData in pairs(LeafVE_DB.global or {}) do
    if type(dayData) == "table" then
      local entry = dayData[name]
      if type(entry) == "table" and PointBucketForEntry(entry) == bucket then
        totals.L = totals.L + (tonumber(entry.L) or 0)
        totals.G = totals.G + (tonumber(entry.G) or 0)
        totals.S = totals.S + (tonumber(entry.S) or 0)
      end
    end
  end

  return totals
end

local function ResolveLifetimeEntryForDisplay(playerName)
  EnsureDB()
  local name = ShortName(playerName)
  if not name then return {L = 0, G = 0, S = 0} end

  local me = ShortName(UnitName("player"))
  local wk = WeekKey()
  local syncedWeek = (type(LeafVE_DB.lboard.weekly[wk]) == "table") and LeafVE_DB.lboard.weekly[wk] or {}
  local localWeek = AggForThisWeek()

  local localPts  = LeafVE_DB.alltime[name]
  if not IsPointEntryInCurrentBucket(localPts) then
    localPts = nil
  end
  local syncedPts = LeafVE_DB.lboard.alltime[name]
  local lifeMeta = LeafVE_DB.lboard.updatedAt[name]
  local syncedIsAuthoritative = (type(lifeMeta) == "table" and lifeMeta.lifetimeAuthoritative == true)
  local pts = syncedIsAuthoritative and syncedPts or nil
  if not SamePlayerName(name, me) then
    localPts = nil
  end
  if LboardEntryTotal(localPts) > LboardEntryTotal(pts) then
    pts = localPts
  end
  local weekPts = syncedWeek[name] or localWeek[name]
  if LboardEntryTotal(weekPts) > LboardEntryTotal(pts) then
    pts = weekPts
  end

  return {
    L = pts and (pts.L or 0) or 0,
    G = pts and (pts.G or 0) or 0,
    S = pts and (pts.S or 0) or 0,
  }
end

-- Builds the exact snapshot used for leaderboard self-broadcasts.
-- This mirrors My Stats reconciliation so refresh requests pull the same totals.
local function BuildMyStatsSnapshotForPlayer(playerName)
  EnsureDB()
  local name = ShortName(playerName)
  if not name then
    return {L = 0, G = 0, S = 0}, {L = 0, G = 0, S = 0}
  end

  local weekAgg = AggForThisWeek()
  local weekT = weekAgg[name] or {L = 0, G = 0, S = 0}

  local globalSum = AggregateGlobalTotalsForPlayer(name)
  local leaderboardAlltime = ResolveLifetimeEntryForDisplay(name)
  local bestAlltime = GetBestLifetimeEntry(name)
  local alltimeT = {
    L = math.max(leaderboardAlltime.L or 0, bestAlltime.L or 0, globalSum.L or 0),
    G = math.max(leaderboardAlltime.G or 0, bestAlltime.G or 0, globalSum.G or 0),
    S = math.max(leaderboardAlltime.S or 0, bestAlltime.S or 0, globalSum.S or 0),
  }

  return alltimeT, {
    L = weekT.L or 0,
    G = weekT.G or 0,
    S = weekT.S or 0,
  }
end

function LeafVE:CacheBadgeProgress(playerName)
  EnsureDB()
  local name, cache = GetBadgeProgressCacheEntry(playerName, true)
  if not name or type(cache) ~= "table" then return end
  cache.bucket = CurrentWipeVersion()

  local alltime = GetBestLifetimeEntry(name)
  cache.alltime = {
    L = alltime.L or 0,
    G = alltime.G or 0,
    S = alltime.S or 0,
  }

  local groupSessions = (LeafVE_DB.groupSessions and LeafVE_DB.groupSessions[name]) or 0
  if groupSessions > (cache.groupSessions or 0) then
    cache.groupSessions = groupSessions
  end

  local guildieHours = (LeafVE_DB.guildieGroupHours and LeafVE_DB.guildieGroupHours[name]) or 0
  if guildieHours > (cache.guildieGroupHours or 0) then
    cache.guildieGroupHours = guildieHours
  end

  local attendanceCount = table.getn((LeafVE_DB.attendance and LeafVE_DB.attendance[name]) or {})
  if attendanceCount > (cache.attendance or 0) then
    cache.attendance = attendanceCount
  end

  local streak = (LeafVE_DB.loginStreaks and LeafVE_DB.loginStreaks[name] and LeafVE_DB.loginStreaks[name].current) or 0
  if streak > (cache.loginStreak or 0) then
    cache.loginStreak = streak
  end

  local joinDate = (LeafVE_DB.guildJoinDate and LeafVE_DB.guildJoinDate[name]) or 0
  if joinDate > 0 then
    if not cache.guildJoinDate or cache.guildJoinDate <= 0 or joinDate < cache.guildJoinDate then
      cache.guildJoinDate = joinDate
    end
  end

  cache.updatedAt = Now()
end

function LeafVE:UpsertSharedLeaderboard(name, lifetimeEntry, weeklyEntry, wk, forceReplace)
  EnsureDB()
  name = ShortName(name)
  if not name then return end
  if not LeafVE_GlobalDB.lboardCache then
    LeafVE_GlobalDB.lboardCache = { alltime = {}, weekly = {} }
  end
  if not LeafVE_GlobalDB.lboardCache.alltime then LeafVE_GlobalDB.lboardCache.alltime = {} end
  if not LeafVE_GlobalDB.lboardCache.weekly then LeafVE_GlobalDB.lboardCache.weekly = {} end
  wk = wk or WeekKey()

  if lifetimeEntry then
    local existing = LeafVE_GlobalDB.lboardCache.alltime[name]
    if forceReplace or LboardEntryTotal(lifetimeEntry) > LboardEntryTotal(existing) then
      LeafVE_GlobalDB.lboardCache.alltime[name] = {
        L = lifetimeEntry.L or 0,
        G = lifetimeEntry.G or 0,
        S = lifetimeEntry.S or 0,
      }
    end
  end

  if weeklyEntry then
    if type(LeafVE_GlobalDB.lboardCache.weekly[wk]) ~= "table" then
      LeafVE_GlobalDB.lboardCache.weekly[wk] = {}
    end
    local existingW = LeafVE_GlobalDB.lboardCache.weekly[wk][name]
    if forceReplace or LboardEntryTotal(weeklyEntry) > LboardEntryTotal(existingW) then
      LeafVE_GlobalDB.lboardCache.weekly[wk][name] = {
        L = weeklyEntry.L or 0,
        G = weeklyEntry.G or 0,
        S = weeklyEntry.S or 0,
      }
    end
  end
end

function LeafVE:MergeSharedLeaderboardIntoLocal()
  EnsureDB()
  PruneLeaderboardForCurrentWipe()
  local cache = LeafVE_GlobalDB.lboardCache
  if not cache then return end
  local wk = WeekKey()

  for name, entry in pairs(cache.alltime or {}) do
    if LboardEntryTotal(entry) > LboardEntryTotal(LeafVE_DB.lboard.alltime[name]) then
      LeafVE_DB.lboard.alltime[name] = {
        L = entry.L or 0,
        G = entry.G or 0,
        S = entry.S or 0,
      }
      if type(LeafVE_DB.lboard.updatedAt[name]) ~= "table" then
        LeafVE_DB.lboard.updatedAt[name] = {}
      end
      LeafVE_DB.lboard.updatedAt[name].lifetimeWipeVersion = CurrentWipeVersion()
    end
  end

  if type(LeafVE_DB.lboard.weekly[wk]) ~= "table" then
    LeafVE_DB.lboard.weekly[wk] = {}
  end
  local weekCache = type(cache.weekly[wk]) == "table" and cache.weekly[wk] or {}
  for name, entry in pairs(weekCache) do
    if LboardEntryTotal(entry) > LboardEntryTotal(LeafVE_DB.lboard.weekly[wk][name]) then
      LeafVE_DB.lboard.weekly[wk][name] = {
        L = entry.L or 0,
        G = entry.G or 0,
        S = entry.S or 0,
      }
      SetWeeklyEntryWipeVersion(wk, name, CurrentWipeVersion())
    end
  end
end

function LeafVE:AddToHistory(playerName, pointType, amount, reason)
  EnsureDB() playerName = ShortName(playerName) if not playerName then return end
  if not LeafVE_DB.pointHistory[playerName] then LeafVE_DB.pointHistory[playerName] = {} end
  local now = Now()
  local dateStr = date("%m/%d %H:%M", now)
  table.insert(LeafVE_DB.pointHistory[playerName], {timestamp = now, type = pointType, amount = amount, reason = reason or "Unknown", dateStr = dateStr})
  while table.getn(LeafVE_DB.pointHistory[playerName]) > 500 do table.remove(LeafVE_DB.pointHistory[playerName], 1) end

  -- Keep currently-visible history/leaderboard views up to date immediately.
  if LeafVE.UI and LeafVE.UI.panels then
    if LeafVE.UI.panels.liveHistory and LeafVE.UI.panels.liveHistory:IsVisible() and LeafVE.UI.RefreshLiveHistory then
      LeafVE.UI:RefreshLiveHistory()
    end
    if LeafVE.UI.panels.leaderLife and LeafVE.UI.panels.leaderLife:IsVisible() and LeafVE.UI.RefreshLeaderboard then
      LeafVE.UI:RefreshLeaderboard("leaderLife")
    end
    if LeafVE.UI.panels.leaderWeek and LeafVE.UI.panels.leaderWeek:IsVisible() and LeafVE.UI.RefreshLeaderboard then
      LeafVE.UI:RefreshLeaderboard("leaderWeek")
    end
  end

  -- Broadcast this transaction to all online guild members
  local me = ShortName(UnitName("player"))
  if me and playerName == me and InGuild() then
    local truncReason = reason or "Unknown"
    if string.len(truncReason) > 80 then truncReason = string.sub(truncReason, 1, 80) end
    SendAddonMessage("LeafVE", "PTXN:"..playerName..SEP..tostring(amount)..SEP..tostring(now)..SEP..(pointType or "")..SEP..truncReason, "GUILD")
  end
end

local function FindBadgeMapForPlayer(badgeTable, playerName)
  if type(badgeTable) ~= "table" then return nil end
  local shortName = ShortName(playerName)
  if not shortName then return nil end

  local direct = badgeTable[shortName]
  if type(direct) == "table" then
    return direct
  end

  local targetLower = Lower(shortName)
  for name, badgeMap in pairs(badgeTable) do
    if type(name) == "string" and type(badgeMap) == "table" then
      local short = ShortName(name)
      if short and Lower(short) == targetLower then
        return badgeMap
      end
    end
  end
  return nil
end

local function HadBadgeInArchivedSeason(playerName, badgeId)
  if type(LeafVE_DB) ~= "table" or type(LeafVE_DB.badgesArchive) ~= "table" then
    return false
  end
  for _, seasonBadges in pairs(LeafVE_DB.badgesArchive) do
    local playerBadges = FindBadgeMapForPlayer(seasonBadges, playerName)
    if type(playerBadges) == "table" and playerBadges[badgeId] then
      return true
    end
  end
  return false
end

local function ShouldAnnounceBadgeInGuild(playerName, badgeId)
  if not InGuild() then return false end
  if not badgeId or badgeId == "" then return false end
  if not LeafVE_DB.badgesAnnounced then LeafVE_DB.badgesAnnounced = {} end

  local bucketKey = tostring(CurrentWipeVersion())..":"..badgeId
  -- Respect legacy keying while migrating to bucket-scoped flags.
  if LeafVE_DB.badgesAnnounced[bucketKey] or LeafVE_DB.badgesAnnounced[badgeId] then
    return false
  end

  LeafVE_DB.badgesAnnounced[bucketKey] = true
  LeafVE_DB.badgesAnnounced[badgeId] = true

  -- Suppress season-reset spam for badges already earned in archived seasons.
  if HadBadgeInArchivedSeason(playerName, badgeId) then
    return false
  end
  return true
end

function LeafVE:AwardBadge(playerName, badgeId)
  EnsureDB()
  playerName = ShortName(playerName)
  
  if not playerName then
    Print("ERROR: Invalid player name")
    return
  end
  
  -- Check if badge exists
  local badge = nil
  for i = 1, table.getn(BADGES) do
    if BADGES[i].id == badgeId then
      badge = BADGES[i]
      break
    end
  end

  if not badge then
    Print("ERROR: Badge '"..badgeId.."' does not exist")
    return
  end

  -- Initialize player badges table if needed
  if not LeafVE_DB.badges[playerName] then
    LeafVE_DB.badges[playerName] = {}
  end

  -- Check if already earned
  if LeafVE_DB.badges[playerName][badgeId] then
    Print(playerName.." already has badge: "..badgeId)
    return
  end

  -- Award the badge
  LeafVE_DB.badges[playerName][badgeId] = time()
  Print("Badge awarded to "..playerName..": "..badgeId)

  -- Show notification if this is the current player
  local me = ShortName(UnitName("player"))
  if me and playerName == me then
    local badgeQuality = badge.quality or BADGE_QUALITY.COMMON
    local qr, qg, qb = GetBadgeQualityColor(badgeQuality)
    local qualityLabel = GetBadgeQualityLabel(badgeQuality)
    if LeafVE_DB.options.enableNotifications ~= false and LeafVE_DB.options.enableBadgeNotifications ~= false then
      self:ShowNotification("Badge Earned! ["..qualityLabel.."]", badge.name..": "..badge.desc, badge.icon, {qr, qg, qb, 1})
    end
    Print("|cFF"..RGBToHex(qr, qg, qb).."["..qualityLabel.."] Badge Earned:|r "..badge.name.." - "..badge.desc)
  end

  -- Send guild chat announcement (only once per badge, never re-announce)
  if ShouldAnnounceBadgeInGuild(playerName, badgeId) then
      local badgeQuality = badge.quality or BADGE_QUALITY.COMMON
      local qr, qg, qb = GetBadgeQualityColor(badgeQuality)
      local badgeLink = "|cFF"..RGBToHex(qr, qg, qb).."|Hleafve_badge:"..badge.id.."|h["..badge.name.."]|h|r"
      local titleStr = ""
      local equippedTitle = GetLegacyAchievementEquippedTitle(playerName)
      if equippedTitle then
        titleStr = "|cFFFF8000[" .. equippedTitle .. "]|r"
      end
      SendChatMessage(titleStr.."[LeafVE Note] received "..badgeLink.." for contributing to the guild!", "GUILD")
  end

  -- Broadcast badges immediately after awarding
  if me and playerName == me then
    self:BroadcastBadges()
  end
  
  -- Refresh UI if player card is showing this player
  if LeafVE.UI.cardCurrentPlayer == playerName then
    LeafVE.UI:UpdateCardRecentBadges(playerName)
  end
  
  -- Refresh badges tab if open
  if LeafVE.UI.panels and LeafVE.UI.panels.badges and LeafVE.UI.panels.badges:IsVisible() then
    LeafVE.UI:RefreshBadges()
  end
end

function LeafVE:AwardRandomBadge(playerName)
  EnsureDB()
  playerName = ShortName(playerName)
  if not playerName then
    Print("ERROR: Invalid player name")
    return
  end
  if not LeafVE_DB.badges[playerName] then LeafVE_DB.badges[playerName] = {} end
  local unearned = {}
  for i = 1, table.getn(BADGES) do
    if not LeafVE_DB.badges[playerName][BADGES[i].id] then
      table.insert(unearned, BADGES[i].id)
    end
  end
  if table.getn(unearned) == 0 then
    Print(playerName.." already has all badges.")
    return
  end
  local idx = math.random(1, table.getn(unearned))
  self:AwardBadge(playerName, unearned[idx])
end

-- Wipes all saved data for the current player (account-wide).
-- Clears both the per-character DB and all per-player entries in the shared DB,
-- then broadcasts a removal notice to online guild members so their caches are
-- also cleaned up, preventing polluted data from entering the leaderboards.
function LeafVE:ResetMyData()
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me then
    Print("|cFFFF4444Error: Could not determine your character name.|r")
    return
  end

  -- Clear all point and tracking data keyed by the player's name.
  LeafVE_DB.alltime[me]            = nil
  LeafVE_DB.season[me]             = nil
  LeafVE_DB.loginStreaks[me]       = nil
  LeafVE_DB.loginTracking[me]      = nil
  LeafVE_DB.groupSessions[me]      = nil
  LeafVE_DB.groupPointsToday[me]   = nil
  LeafVE_DB.guildieGroupHours[me]  = nil
  if LeafVE_DB.guildJoinDate then LeafVE_DB.guildJoinDate[me] = nil end
  LeafVE_DB.attendance[me]         = nil
  LeafVE_DB.pointHistory[me]       = nil
  LeafVE_DB.instanceTracking[me]   = nil
  LeafVE_DB.questTracking[me]      = nil
  LeafVE_DB.questCompletions[me]   = nil
  LeafVE_DB.badges[me]             = nil
  LeafVE_DB.badgesAnnounced[me]    = nil
  -- Remove from leaderboard caches.
  LeafVE_DB.lboard.alltime[me]     = nil
  LeafVE_DB.lboard.updatedAt[me]   = nil
  for _, wkData in pairs(LeafVE_DB.lboard.weekly) do
    if type(wkData) == "table" then wkData[me] = nil end
  end
  if LeafVE_DB.lboard.season then
    LeafVE_DB.lboard.season[me] = nil
  end
  -- Remove from daily global point tables.
  for _, dayData in pairs(LeafVE_DB.global) do
    if type(dayData) == "table" then dayData[me] = nil end
  end
  -- Remove shoutouts sent by this player and shoutouts targeting this player.
  LeafVE_DB.shoutouts[me] = nil
  for _, targets in pairs(LeafVE_DB.shoutouts) do
    if type(targets) == "table" then targets[me] = nil end
  end
  -- Clear account-wide (GlobalDB) entries for this player.
  if LeafVE_GlobalDB.achievementCache then
    LeafVE_GlobalDB.achievementCache[me] = nil
  end
  if LeafVE_GlobalDB.lboardCache then
    if LeafVE_GlobalDB.lboardCache.alltime then
      LeafVE_GlobalDB.lboardCache.alltime[me] = nil
    end
    if LeafVE_GlobalDB.lboardCache.weekly then
      for _, wkData in pairs(LeafVE_GlobalDB.lboardCache.weekly) do
        if type(wkData) == "table" then wkData[me] = nil end
      end
    end
  end
  if LeafVE_GlobalDB.badgeProgressCache then
    LeafVE_GlobalDB.badgeProgressCache[me] = nil
  end
  if LeafVE_GlobalDB.gearCache then
    LeafVE_GlobalDB.gearCache[Lower(me)] = nil
  end
  if LeafVE_GlobalDB.specCache then
    LeafVE_GlobalDB.specCache[Lower(me)] = nil
  end
  if LeafVE_GlobalDB.talentCache then
    LeafVE_GlobalDB.talentCache[Lower(me)] = nil
  end
  if LeafVE.talentSyncBuffer then
    LeafVE.talentSyncBuffer[Lower(me)] = nil
  end
  if LeafVE_GlobalDB.playerNotes then
    LeafVE_GlobalDB.playerNotes[me] = nil
  end
  if LeafVE_GlobalDB.professionDesignations then
    LeafVE_GlobalDB.professionDesignations[Lower(me)] = nil
  end

  -- Broadcast so online guild members remove this player from their caches.
  if InGuild() then
    SendAddonMessage("LeafVE", "LVE_PLAYER_DATA_RESET:"..me, "GUILD")
  end

  Print("|cFF2DD35CYour saved data has been reset. Guild members have been notified to remove your entries from their leaderboard caches.|r")
  if LeafVE.UI and LeafVE.UI.Refresh then
    LeafVE.UI:Refresh()
  end
end

-- Wipes ALL addon SavedVariables for this client (daily/weekly/season/lifetime
-- points, history, badges, leaderboard cache, gear cache, notes, etc.) and then
-- reloads the UI so the addon starts from a completely clean slate.
function LeafVE:ResetAllData_Local()
  LeafVE_DB       = {}
  LeafVE_GlobalDB = {}
  ReloadUI()
end

-- Resets point/history/leaderboard fields on the local player's LeafVE_DB while
-- preserving badge structures and lastWipeApplied so full-wipe bucket transitions
-- can rotate cleanly without losing archived badge seasons.
function LVE_ResetPlayerDB()
  local wipeApplied = (LeafVE_DB and LeafVE_DB.lastWipeApplied) or 0
  local preservedBadges = (LeafVE_DB and LeafVE_DB.badges) or nil
  local preservedBadgesAnnounced = (LeafVE_DB and LeafVE_DB.badgesAnnounced) or nil
  local preservedBadgeBucketVersion = (LeafVE_DB and LeafVE_DB.badgeBucketVersion) or nil
  local preservedBadgesArchive = (LeafVE_DB and LeafVE_DB.badgesArchive) or nil
  if LeafVE_DB then
    for k in pairs(LeafVE_DB) do
      LeafVE_DB[k] = nil
    end
  else
    LeafVE_DB = {}
  end
  LeafVE_DB.lastWipeApplied = wipeApplied
  if type(preservedBadges) == "table" then
    LeafVE_DB.badges = preservedBadges
  end
  if type(preservedBadgesAnnounced) == "table" then
    LeafVE_DB.badgesAnnounced = preservedBadgesAnnounced
  end
  if preservedBadgeBucketVersion ~= nil then
    LeafVE_DB.badgeBucketVersion = preservedBadgeBucketVersion
  end
  if type(preservedBadgesArchive) == "table" then
    LeafVE_DB.badgesArchive = preservedBadgesArchive
  end
  EnsureDB()
end

-- After a full wipe, prevent the same day's auto-login grant from immediately
-- repopulating all-time with +20 L points on the next login refresh.
local function LVE_StampTodayLoginAsHandled()
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me then return end
  local today = DayKey()
  if not LeafVE_DB.loginTracking[me] then
    LeafVE_DB.loginTracking[me] = {}
  end
  LeafVE_DB.loginTracking[me][today] = true
end

local function LVE_ApplyFullWipeVersion(wipeVersion, announceMessage)
  wipeVersion = tonumber(wipeVersion) or 0
  if wipeVersion <= 0 then return false end

  LVE_ResetGlobalDB(wipeVersion)
  local appliedVersion = (LeafVE_GlobalDB and tonumber(LeafVE_GlobalDB.fullWipeVersion)) or wipeVersion
  LVE_ResetPlayerDB()
  LeafVE_DB.lastWipeApplied = appliedVersion
  LVE_StampTodayLoginAsHandled()
  if announceMessage and announceMessage ~= "" then
    Print(announceMessage)
  end
  if LeafVE.UI and LeafVE.UI.Refresh then
    LeafVE.UI:Refresh()
  end
  return true
end

local function ShouldApplyIncomingWipeVersion(incomingVersion)
  incomingVersion = tonumber(incomingVersion) or 0
  if incomingVersion <= 0 then return false end
  local localVersion = (LeafVE_GlobalDB and tonumber(LeafVE_GlobalDB.fullWipeVersion)) or 0
  local lastApplied = (LeafVE_DB and tonumber(LeafVE_DB.lastWipeApplied)) or 0
  local effectiveLocalVersion = math.max(localVersion, lastApplied)
  return incomingVersion > effectiveLocalVersion
end

function LeafVE:BroadcastFullWipeVersion(wipeVersion)
  if not InGuild() then return end
  local version = tonumber(wipeVersion) or ((LeafVE_GlobalDB and LeafVE_GlobalDB.fullWipeVersion) or 0)
  if version and version > 0 then
    SendAddonMessage("LeafVE", "FULL_WIPE:"..version, "GUILD")
  end
end

local function ParseGuildWipeMarkerVersion(infoText)
  if type(infoText) ~= "string" then return 0 end
  local markerVersion = string.match(infoText, FULL_WIPE_GUILD_MARKER_PATTERN)
  return tonumber(markerVersion) or 0
end

local function BuildGuildInfoTextWithWipeMarker(infoText, wipeVersion)
  local cleanInfo = string.gsub(tostring(infoText or ""), FULL_WIPE_GUILD_MARKER_STRIP_PATTERN, " ")
  cleanInfo = Trim(cleanInfo)
  local marker = "["..FULL_WIPE_GUILD_MARKER..":"..tostring(wipeVersion).."]"
  if cleanInfo == "" then
    return marker
  end
  return cleanInfo.." "..marker
end

function LeafVE:PublishGuildWipeMarker(wipeVersion)
  if not wipeVersion or wipeVersion <= 0 then return false, "invalid_version" end
  if not InGuild() then return false, "not_in_guild" end
  if not GetGuildInfoText or not SetGuildInfoText then
    return false, "guild_info_api_unavailable"
  end

  local currentInfo = GetGuildInfoText() or ""
  local currentMarkerVersion = ParseGuildWipeMarkerVersion(currentInfo)
  if currentMarkerVersion >= wipeVersion then
    return true, "already_current"
  end

  local updatedInfo = BuildGuildInfoTextWithWipeMarker(currentInfo, wipeVersion)
  SetGuildInfoText(updatedInfo)
  return true, "set_requested"
end

function LeafVE:ApplyGuildWipeMarkerIfNeeded()
  EnsureDB()
  if not InGuild() then return false end
  if not GetGuildInfoText then return false end

  local guildMarkerVersion = ParseGuildWipeMarkerVersion(GetGuildInfoText() or "")
  if guildMarkerVersion <= 0 then return false end

  local localVersion = (LeafVE_GlobalDB and LeafVE_GlobalDB.fullWipeVersion) or 0
  local lastApplied = (LeafVE_DB and LeafVE_DB.lastWipeApplied) or 0
  local effectiveLocalVersion = math.max(localVersion, lastApplied)
  if guildMarkerVersion <= effectiveLocalVersion then
    return false
  end

  local applied = LVE_ApplyFullWipeVersion(
    guildMarkerVersion,
    "|cFFFFD700[LVL]|r Detected guild wipe marker; local data reset applied."
  )
  if applied then
    self:BroadcastFullWipeVersion(guildMarkerVersion)
  end
  return applied
end

-- Clears all account-wide caches and stamps fullWipeVersion.
-- When targetVersion is nil, this uses epoch seconds (monotonic fallback) and
-- returns the new version.
function LVE_ResetGlobalDB(targetVersion)
  local currentVersion = (LeafVE_GlobalDB and LeafVE_GlobalDB.fullWipeVersion) or 0
  local newVersion = tonumber(targetVersion)
  if not newVersion or newVersion <= 0 then
    -- Use epoch seconds so each admin wipe is globally monotonic across clients.
    newVersion = Now()
    if newVersion <= currentVersion then
      newVersion = currentVersion + 1
    end
  elseif newVersion < currentVersion then
    -- Never move backward; older relays must not downgrade local wipe state.
    newVersion = currentVersion
  end
  if LeafVE_GlobalDB then
    for k in pairs(LeafVE_GlobalDB) do
      LeafVE_GlobalDB[k] = nil
    end
  else
    LeafVE_GlobalDB = {}
  end
  LeafVE_GlobalDB.fullWipeVersion = newVersion
  EnsureDB()
  return newVersion
end

-- Admin-only full wipe. This is the sole guild-wide reset path.
function LeafVE:ExecuteAdminFullDataWipe()
  if not self:HasTrueAdminRank() then
    Print("|cFFFF4444Access denied: only Anbu / Sannin / Hokage can perform a full data wipe.|r")
    return
  end

  EnsureDB()
  local wipeVersion = LVE_ResetGlobalDB()
  LVE_ResetPlayerDB()
  LeafVE_DB.lastWipeApplied = wipeVersion
  LVE_StampTodayLoginAsHandled()
  local markerPublished, markerReason = self:PublishGuildWipeMarker(wipeVersion)
  if not markerPublished then
    Print("|cFFFFAA00[LVL]|r Could not publish guild wipe marker ("..tostring(markerReason).."). Offline clients will reset once they receive live guild sync.")
  end

  self:BroadcastFullWipeVersion(wipeVersion)

  if LeafVE.UI and LeafVE.UI.Refresh then
    LeafVE.UI:Refresh()
  end
  Print("|cFFFF2222[LVL]|r Full data wipe complete for all guild members.")
end

