function LeafVE:CanPlayerRequestGuildBankItem(playerName, itemId)
  playerName = ShortName(playerName or UnitName("player"))
  if not playerName then return false end
  if not self:IsGuildBankItemHighValue(itemId) then
    return true
  end
  return self:IsHighValueGuildBankRequester(playerName)
end

function GetWeeklyResetCountdownText()
  local weekStart = WeekStartTS(Now())
  local weekEnd = weekStart + (7 * SECONDS_PER_DAY)
  local timeLeft = weekEnd - Now()
  if timeLeft <= 0 then
    return "Resetting now!"
  end

  local days = math.floor(timeLeft / SECONDS_PER_DAY)
  local hours = math.floor((timeLeft - (days * SECONDS_PER_DAY)) / SECONDS_PER_HOUR)
  local minutes = math.floor((timeLeft - (days * SECONDS_PER_DAY) - (hours * SECONDS_PER_HOUR)) / 60)
  return tostring(days) .. "d " .. tostring(hours) .. "h " .. tostring(minutes) .. "m"
end

function LeafVE:StoreGuildBankRequestRecord(request)
  local store = self:GetGuildBankRequestsDB()
  if type(request) ~= "table" then return nil, false end

  local requester = ShortName(request.requester)
  local itemId = tonumber(request.itemId)
  if not requester or not itemId or itemId < 1 then
    return nil, false
  end

  local createdAt = tonumber(request.createdAt) or Now()
  local updatedAt = tonumber(request.updatedAt) or createdAt
  if updatedAt < createdAt then
    updatedAt = createdAt
  end

  local status = NormalizeGuildBankRequestStatus(request.status)
  local handledBy = ShortName(request.handledBy)
  if status == "open" then
    handledBy = nil
  end

  local quantity = tonumber(request.quantity) or 1
  if quantity < 1 then quantity = 1 end
  if quantity > 99 then quantity = 99 end

  local itemName = Trim(tostring(request.itemName or self:GetWorkOrderItemName(itemId) or ("Item #" .. tostring(itemId))))
  if itemName == "" then
    itemName = "Item #" .. tostring(itemId)
  end

  local icon = NormalizeIconPath(request.icon)
  if not icon then
    icon = self:ResolveIconForItemID(itemId) or LEAF_FALLBACK
  end

  local record = {
    id = tostring(request.id or (requester .. ":" .. tostring(itemId))),
    requester = requester,
    itemId = itemId,
    itemName = itemName,
    icon = icon,
    quantity = quantity,
    createdAt = createdAt,
    updatedAt = updatedAt,
    status = status,
    handledBy = handledBy,
  }

  local existing = store[record.id]
  local existingUpdatedAt = existing and (tonumber(existing.updatedAt or existing.createdAt or 0) or 0) or 0
  if existing and existingUpdatedAt > record.updatedAt then
    return existing, false
  end

  store[record.id] = record
  if not existing then
    return record, true
  end

  local changed = false
  if existingUpdatedAt < record.updatedAt then
    changed = true
  elseif NormalizeGuildBankRequestStatus(existing.status) ~= record.status then
    changed = true
  elseif tonumber(existing.quantity or 1) ~= record.quantity then
    changed = true
  elseif Lower(existing.handledBy or "") ~= Lower(record.handledBy or "") then
    changed = true
  end
  return record, changed
end

function LeafVE:FindOpenGuildBankRequest(requesterName, itemId)
  requesterName = ShortName(requesterName)
  itemId = tonumber(itemId)
  if not requesterName or not itemId then return nil end

  local weekStart = WeekStartTS(Now())
  for _, request in pairs(self:GetGuildBankRequestsDB()) do
    if type(request) == "table"
      and request.itemId == itemId
      and (tonumber(request.createdAt) or 0) >= weekStart
      and NormalizeGuildBankRequestStatus(request.status) == "open"
      and Lower(request.requester or "") == Lower(requesterName) then
      return request
    end
  end
  return nil
end

function LeafVE:GetGuildBankRequestCountThisWeek(requesterName)
  requesterName = ShortName(requesterName)
  if not requesterName then return 0 end

  local count = 0
  local weekStart = WeekStartTS(Now())
  for _, request in pairs(self:GetGuildBankRequestsDB()) do
    if type(request) == "table"
      and Lower(request.requester or "") == Lower(requesterName)
      and (tonumber(request.createdAt) or 0) >= weekStart then
      count = count + 1
    end
  end
  return count
end

function LeafVE:GetGuildBankActiveRequests()
  local requests = {}
  local weekStart = WeekStartTS(Now())
  for _, request in pairs(self:GetGuildBankRequestsDB()) do
    if type(request) == "table"
      and NormalizeGuildBankRequestStatus(request.status) == "open"
      and (tonumber(request.createdAt) or 0) >= weekStart then
      table.insert(requests, request)
    end
  end

  table.sort(requests, function(a, b)
    local aUpdated = tonumber(a.updatedAt or a.createdAt or 0) or 0
    local bUpdated = tonumber(b.updatedAt or b.createdAt or 0) or 0
    if aUpdated ~= bUpdated then
      return aUpdated > bUpdated
    end
    local aName = Lower(a.itemName or "")
    local bName = Lower(b.itemName or "")
    if aName ~= bName then
      return aName < bName
    end
    return Lower(a.requester or "") < Lower(b.requester or "")
  end)

  return requests
end

function LeafVE:GetGuildBankRequestSignature()
  local count = 0
  local totalQuantity = 0
  local latest = 0
  local weekStart = WeekStartTS(Now())
  for _, request in pairs(self:GetGuildBankRequestsDB()) do
    if type(request) == "table"
      and NormalizeGuildBankRequestStatus(request.status) == "open"
      and (tonumber(request.createdAt) or 0) >= weekStart then
      count = count + 1
      totalQuantity = totalQuantity + (tonumber(request.quantity) or 0)
      local updatedAt = tonumber(request.updatedAt or request.createdAt or 0) or 0
      if updatedAt > latest then
        latest = updatedAt
      end
    end
  end
  return tostring(count) .. ":" .. tostring(totalQuantity) .. ":" .. tostring(latest)
end

function LeafVE:GetGuildBankReservedRequestMap()
  local signature = self:GetGuildBankRequestSignature()
  if self.guildBankReservedRequestCacheKey == signature and type(self.guildBankReservedRequestCache) == "table" then
    return self.guildBankReservedRequestCache
  end

  local reservedByItem = {}
  local weekStart = WeekStartTS(Now())
  for _, request in pairs(self:GetGuildBankRequestsDB()) do
    if type(request) == "table"
      and NormalizeGuildBankRequestStatus(request.status) == "open"
      and (tonumber(request.createdAt) or 0) >= weekStart then
      local itemId = tonumber(request.itemId)
      if itemId and itemId > 0 then
        reservedByItem[itemId] = (reservedByItem[itemId] or 0) + (tonumber(request.quantity) or 0)
      end
    end
  end

  self.guildBankReservedRequestCacheKey = signature
  self.guildBankReservedRequestCache = reservedByItem
  return reservedByItem
end

function LeafVE:GetGuildBankReservedRequestQuantity(itemId, excludeRequesterName)
  itemId = tonumber(itemId)
  if not itemId then return 0 end

  local reservedMap = self:GetGuildBankReservedRequestMap()
  local reserved = tonumber(reservedMap[itemId]) or 0
  local excludeName = ShortName(excludeRequesterName)
  if not excludeName then
    return reserved
  end

  local weekStart = WeekStartTS(Now())
  local excludeLower = Lower(excludeName)
  for _, request in pairs(self:GetGuildBankRequestsDB()) do
    if type(request) == "table"
      and request.itemId == itemId
      and NormalizeGuildBankRequestStatus(request.status) == "open"
      and (tonumber(request.createdAt) or 0) >= weekStart
      and Lower(request.requester or "") == excludeLower then
      reserved = reserved - (tonumber(request.quantity) or 0)
    end
  end
  if reserved < 0 then
    reserved = 0
  end
  return reserved
end

function LeafVE:BroadcastGuildBankRequest(request, messageType)
  if not request or not request.id or not InGuild() then return end

  local payload = table.concat({
    EncodeTalentField(request.id),
    EncodeTalentField(request.requester or ""),
    tostring(request.itemId or 0),
    tostring(request.quantity or 1),
    tostring(request.createdAt or Now()),
    tostring(request.updatedAt or request.createdAt or Now()),
    EncodeTalentField(NormalizeGuildBankRequestStatus(request.status)),
    EncodeTalentField(request.handledBy or ""),
    EncodeTalentField(request.itemName or ""),
    EncodeTalentField(request.icon or ""),
  }, SEP)
  SendAddonMessage("LeafVE", (messageType or "GBANKITEMREQ:") .. payload, "GUILD")
end

function LeafVE:BroadcastGuildBankRequestSnapshot(force)
  if not InGuild() then return end

  local now = Now()
  local weekStart = WeekStartTS(now)
  if not force and (now - (self.lastGuildBankRequestSyncRespondAt or 0)) < 20 then
    return
  end
  self.lastGuildBankRequestSyncRespondAt = now

  for _, request in pairs(self:GetGuildBankRequestsDB()) do
    if type(request) == "table" then
      local status = NormalizeGuildBankRequestStatus(request.status)
      local updatedAt = tonumber(request.updatedAt or request.createdAt or 0) or 0
      local createdAt = tonumber(request.createdAt or 0) or 0
      if (status == "open" and createdAt >= weekStart) or updatedAt >= (now - (7 * SECONDS_PER_DAY)) then
        self:BroadcastGuildBankRequest(request, "GBANKITEMREQSYNC:")
      end
    end
  end
end

function LeafVE:RequestGuildBankItemRequestSync(force)
  if not InGuild() then return end

  local now = Now()
  if not force and (now - (self.lastGuildBankRequestSyncAt or 0)) < 20 then
    return
  end
  self.lastGuildBankRequestSyncAt = now
  SendAddonMessage("LeafVE", force and "GBANKITEMREQREQ_FORCE" or "GBANKITEMREQREQ", "GUILD")
end

function LeafVE:HandleIncomingGuildBankRequestMessage(payload)
  local fields = SplitByLiteralSep(payload or "", SEP)
  local request = {
    id = DecodeTalentField(fields[1] or ""),
    requester = ShortName(DecodeTalentField(fields[2] or "")),
    itemId = tonumber(fields[3]),
    quantity = tonumber(fields[4]) or 1,
    createdAt = tonumber(fields[5]) or Now(),
    updatedAt = tonumber(fields[6]) or tonumber(fields[5]) or Now(),
    status = DecodeTalentField(fields[7] or "open"),
    handledBy = ShortName(DecodeTalentField(fields[8] or "")),
    itemName = DecodeTalentField(fields[9] or ""),
    icon = NormalizeIconPath(DecodeTalentField(fields[10] or "")),
  }

  local stored, changed = self:StoreGuildBankRequestRecord(request)
  if changed and LeafVE.UI and LeafVE.UI.RefreshVisibleGuildBankUI then
    LeafVE.UI:RefreshVisibleGuildBankUI(true)
  end
  return stored
end

function LeafVE:SubmitGuildBankItemRequest(itemId, quantity)
  local me = ShortName(UnitName("player"))
  if not me then
    return nil, "Your player name could not be determined."
  end

  itemId = tonumber(itemId)
  local requestedQuantity = ClampGuildBankRequestQuantity(quantity, 99)
  if not itemId or itemId < 1 then
    return nil, "Item not found."
  end
  if not self:CanPlayerRequestGuildBankItem(me, itemId) then
    return nil, "High value items can only be requested by Jonin, Anbu, Sannin, or Hokage."
  end

  local now = Now()
  local existing = self:FindOpenGuildBankRequest(me, itemId)
  if existing and tonumber(existing.quantity or 1) == requestedQuantity then
    return existing
  end
  if not existing and self:GetGuildBankRequestCountThisWeek(me) >= 3 then
    return nil, "You have already used all 3 guild bank requests for this week."
  end

  local snapshot = self:GetGuildBankSnapshot()
  local totalCount = tonumber(snapshot.counts and snapshot.counts[tostring(itemId)] or 0) or 0
  local reservedByOthers = self:GetGuildBankReservedRequestQuantity(itemId, me)
  local requestableCount = totalCount - reservedByOthers
  if requestableCount < 0 then
    requestableCount = 0
  end
  if requestableCount < 1 then
    return nil, "No unreserved stock is available for that item right now."
  end
  if requestedQuantity > requestableCount then
    return nil, "Only " .. tostring(requestableCount) .. " unreserved remain for that item."
  end

  local updatedAt = now
  if existing then
    local priorUpdatedAt = tonumber(existing.updatedAt or existing.createdAt or 0) or 0
    if updatedAt <= priorUpdatedAt then
      updatedAt = priorUpdatedAt + 1
    end
  end

  local request = {
    id = existing and tostring(existing.id) or (tostring(me) .. ":" .. tostring(itemId) .. ":" .. tostring(updatedAt)),
    requester = me,
    itemId = itemId,
    quantity = requestedQuantity,
    createdAt = existing and (tonumber(existing.createdAt) or now) or now,
    updatedAt = updatedAt,
    status = "open",
    handledBy = nil,
    itemName = self:GetWorkOrderItemName(itemId),
    icon = self:ResolveIconForItemID(itemId) or LEAF_FALLBACK,
  }

  local stored = self:StoreGuildBankRequestRecord(request)
  if not stored then
    return nil, "Unable to store request."
  end
  self:BroadcastGuildBankRequest(stored)
  return stored
end

function LeafVE:CancelGuildBankItemRequest(requestId)
  local me = ShortName(UnitName("player"))
  if not me then
    return nil, "Your player name could not be determined."
  end

  local request = self:GetGuildBankRequestsDB()[requestId]
  if type(request) ~= "table" then
    return nil, "Request not found."
  end
  if NormalizeGuildBankRequestStatus(request.status) ~= "open" then
    return nil, "Request is already closed."
  end
  if Lower(request.requester or "") ~= Lower(me) then
    return nil, "You can only cancel your own requests."
  end

  local updatedAt = Now()
  local priorUpdatedAt = tonumber(request.updatedAt or request.createdAt or 0) or 0
  if updatedAt <= priorUpdatedAt then
    updatedAt = priorUpdatedAt + 1
  end

  request.status = "cancelled"
  request.handledBy = me
  request.updatedAt = updatedAt
  local stored = self:StoreGuildBankRequestRecord(request)
  if not stored then
    return nil, "Unable to cancel request."
  end
  self:BroadcastGuildBankRequest(stored)
  return stored
end

function LeafVE:FulfillGuildBankItemRequest(requestId)
  local me = ShortName(UnitName("player"))
  if not me then
    return nil, "Your player name could not be determined."
  end
  if not self:IsGuildBankOwner(me) and not self:IsAdminRank() then
    return nil, "Only the guild bank alt or admin ranks can mark requests filled."
  end

  local request = self:GetGuildBankRequestsDB()[requestId]
  if type(request) ~= "table" then
    return nil, "Request not found."
  end
  if NormalizeGuildBankRequestStatus(request.status) ~= "open" then
    return nil, "Request is already closed."
  end

  local updatedAt = Now()
  local priorUpdatedAt = tonumber(request.updatedAt or request.createdAt or 0) or 0
  if updatedAt <= priorUpdatedAt then
    updatedAt = priorUpdatedAt + 1
  end

  request.status = "fulfilled"
  request.handledBy = me
  request.updatedAt = updatedAt
  local stored = self:StoreGuildBankRequestRecord(request)
  if not stored then
    return nil, "Unable to mark request filled."
  end
  self:BroadcastGuildBankRequest(stored)
  return stored
end

function NormalizeRaidRole(value)
  local role = Lower(Trim(value or ""))
  if role == "tank" then return "tank" end
  if role == "healer" or role == "heal" then return "healer" end
  if role == "melee" or role == "mdps" then return "melee" end
  if role == "ranged" or role == "range" or role == "caster" or role == "rdps" then return "ranged" end
  if role == "flex" then return "flex" end
  return "flex"
end

function NormalizeRaidSignupStatus(value)
  local status = Lower(Trim(value or ""))
  if status == "going" then return "going" end
  if status == "tentative" then return "tentative" end
  if status == "late" then return "late" end
  if status == "cant_make_it" or status == "cantmakeit" or status == "unavailable" or status == "no" then
    return "unavailable"
  end
  return "going"
end

function NormalizeRaidRosterStatus(value)
  local status = Lower(Trim(value or ""))
  if status == "confirmed" then return "confirmed" end
  if status == "bench" then return "bench" end
  if status == "declined" then return "declined" end
  return "signed"
end

function NormalizeRaidEventStatus(value)
  local status = Lower(Trim(value or ""))
  if status == "locked" then return "locked" end
  if status == "completed" then return "completed" end
  if status == "cancelled" then return "cancelled" end
  if status == "archived" then return "archived" end
  return "open"
end

function GetRaidRoleLabel(role)
  role = NormalizeRaidRole(role)
  if role == "tank" then return "Tank" end
  if role == "healer" then return "Healer" end
  if role == "melee" then return "Melee" end
  if role == "ranged" then return "Ranged" end
  return "Flex"
end

function GetRaidSignupStatusLabel(status)
  status = NormalizeRaidSignupStatus(status)
  if status == "tentative" then return "Tentative" end
  if status == "late" then return "Late" end
  if status == "unavailable" then return "Can't Make It" end
  return "Going"
end

function GetRaidRosterStatusLabel(status)
  status = NormalizeRaidRosterStatus(status)
  if status == "confirmed" then return "Confirmed" end
  if status == "bench" then return "Bench" end
  if status == "declined" then return "Declined" end
  return "Signed"
end

function GetRaidEventStatusLabel(status)
  status = NormalizeRaidEventStatus(status)
  if status == "locked" then return "Locked" end
  if status == "completed" then return "Completed" end
  if status == "cancelled" then return "Cancelled" end
  if status == "archived" then return "Archived" end
  return "Open"
end

function LeafVE:GetRaidEventsDB()
  EnsureDB()
  return LeafVE_GlobalDB.raidEvents
end

function LeafVE:GetRaidSignupsDB()
  EnsureDB()
  return LeafVE_GlobalDB.raidSignups
end

function LeafVE:IsRaidOrganizerRank(playerName)
  if LEAFVE_IGNORE_RANK_REQUIREMENTS then
    return true
  end
  playerName = ShortName(playerName or UnitName("player"))
  if not playerName then return false end
  self:UpdateGuildRosterCache()
  local info = self.guildRosterCache and self.guildRosterCache[Lower(playerName)] or nil
  local rank = info and info.rank and Lower(Trim(info.rank)) or ""
  return rank == "jonin" or rank == "anbu" or rank == "sannin" or rank == "hokage"
end

function LeafVE:IsRaidEventCreatorRank(playerName)
  if LEAFVE_IGNORE_RANK_REQUIREMENTS then
    return true
  end
  playerName = ShortName(playerName or UnitName("player"))
  if not playerName then return false end
  self:UpdateGuildRosterCache()
  local info = self.guildRosterCache and self.guildRosterCache[Lower(playerName)] or nil
  local rank = info and info.rank and Lower(Trim(info.rank)) or ""
  return ADMIN_RANKS[rank] == true
end

function LeafVE:CanManageRaidEvent(eventRecord, playerName)
  playerName = ShortName(playerName or UnitName("player"))
  if not playerName then return false end
  if self:IsRaidOrganizerRank(playerName) then
    return true
  end
  return type(eventRecord) == "table" and SamePlayerName(eventRecord.postedBy, playerName)
end

function LeafVE:GetRaidCatalog()
  if self.raidCatalog and self.raidCatalogOrder then
    return self.raidCatalog, self.raidCatalogOrder
  end

  self.raidCatalog = {}
  self.raidCatalogOrder = {}
  if type(LeafVE_RaidCatalogSource) ~= "table" then
    return self.raidCatalog, self.raidCatalogOrder
  end

  for _, source in ipairs(LeafVE_RaidCatalogSource) do
    if type(source) == "table" and source.key and source.name then
      local entry = {
        key = tostring(source.key),
        name = tostring(source.name),
        raidSize = tonumber(source.raidSize) or 20,
        roleTargets = {
          tank = tonumber(source.roleTargets and source.roleTargets.tank) or 2,
          healer = tonumber(source.roleTargets and source.roleTargets.healer) or 5,
          melee = tonumber(source.roleTargets and source.roleTargets.melee) or 6,
          ranged = tonumber(source.roleTargets and source.roleTargets.ranged) or 7,
          flex = tonumber(source.roleTargets and source.roleTargets.flex) or 0,
        },
        bosses = {},
      }
      for _, boss in ipairs(source.bosses or {}) do
        if type(boss) == "table" and boss.key and boss.name then
          table.insert(entry.bosses, {
            key = tostring(boss.key),
            name = tostring(boss.name),
            kind = Lower(Trim(boss.kind or "boss")),
          })
        end
      end
      self.raidCatalog[entry.key] = entry
      table.insert(self.raidCatalogOrder, entry)
    end
  end

  return self.raidCatalog, self.raidCatalogOrder
end

function LeafVE:GetRaidCatalogEntry(raidKey)
  local catalog = self:GetRaidCatalog()
  return catalog[tostring(raidKey or "")]
end

function LeafVE:GetRaidDefaultRoleTargets(raidKey, raidSize)
  local catalog = self:GetRaidCatalogEntry(raidKey)
  if catalog and type(catalog.roleTargets) == "table" then
    return {
      tank = tonumber(catalog.roleTargets.tank) or 2,
      healer = tonumber(catalog.roleTargets.healer) or 5,
      melee = tonumber(catalog.roleTargets.melee) or 6,
      ranged = tonumber(catalog.roleTargets.ranged) or 7,
      flex = tonumber(catalog.roleTargets.flex) or 0,
    }
  end

  raidSize = tonumber(raidSize) or 20
  if raidSize <= 10 then
    return { tank = 2, healer = 3, melee = 2, ranged = 3, flex = 0 }
  elseif raidSize <= 20 then
    return { tank = 2, healer = 5, melee = 6, ranged = 7, flex = 0 }
  end
  return { tank = 4, healer = 10, melee = 13, ranged = 13, flex = 0 }
end

function LeafVE:GetSuggestedRaidRoleForPlayer(playerName, classTag, specName)
  classTag = string.upper(classTag or self:GetClassTagForPlayer(playerName) or "UNKNOWN")
  local spec = specName or (self:GetSpecSnapshotForPlayer(playerName, classTag) or {}).name or ""
  local lspec = Lower(spec)

  if classTag == "WARRIOR" then
    if string.find(lspec, "protection", 1, true) then return "tank" end
    return "melee"
  elseif classTag == "PALADIN" then
    if string.find(lspec, "holy", 1, true) then return "healer" end
    if string.find(lspec, "protection", 1, true) then return "tank" end
    return "melee"
  elseif classTag == "PRIEST" then
    if string.find(lspec, "holy", 1, true) or string.find(lspec, "discipline", 1, true) then return "healer" end
    return "ranged"
  elseif classTag == "SHAMAN" then
    if string.find(lspec, "restoration", 1, true) then return "healer" end
    if string.find(lspec, "enhancement", 1, true) then return "melee" end
    return "ranged"
  elseif classTag == "DRUID" then
    if string.find(lspec, "restoration", 1, true) then return "healer" end
    if string.find(lspec, "balance", 1, true) then return "ranged" end
    if string.find(lspec, "feral", 1, true) then return "tank" end
    return "flex"
  elseif classTag == "ROGUE" then
    return "melee"
  elseif classTag == "MAGE" or classTag == "WARLOCK" or classTag == "HUNTER" then
    return "ranged"
  end
  return "flex"
end

function LeafVE:FindRaidSignupRecord(eventId, playerName)
  local eventSignups = self:GetRaidSignupsDB()[tostring(eventId or "")]
  if type(eventSignups) ~= "table" then return nil end
  playerName = ShortName(playerName)
  if not playerName then return nil end
  return eventSignups[Lower(playerName)]
end

function LeafVE:GetRaidSignupsForEvent(eventId, includeUnavailable)
  local rows = {}
  local eventSignups = self:GetRaidSignupsDB()[tostring(eventId or "")]
  if type(eventSignups) ~= "table" then
    return rows
  end

  for _, signup in pairs(eventSignups) do
    if type(signup) == "table" then
      local signupStatus = NormalizeRaidSignupStatus(signup.signupStatus)
      if includeUnavailable or signupStatus ~= "unavailable" then
        table.insert(rows, signup)
      end
    end
  end

  table.sort(rows, function(a, b)
    local aRole = NormalizeRaidRole(a.preferredRole)
    local bRole = NormalizeRaidRole(b.preferredRole)
    if aRole == bRole then
      local aRoster = NormalizeRaidRosterStatus(a.rosterStatus)
      local bRoster = NormalizeRaidRosterStatus(b.rosterStatus)
      if aRoster == bRoster then
        return Lower(a.player or "") < Lower(b.player or "")
      end
      return aRoster < bRoster
    end
    return aRole < bRole
  end)

  return rows
end

function LeafVE:GetVisibleRaidEvents(mode)
  local rows = {}
  local me = ShortName(UnitName("player"))
  local now = Now()

  for _, eventRecord in pairs(self:GetRaidEventsDB()) do
    if type(eventRecord) == "table" then
      local status = NormalizeRaidEventStatus(eventRecord.status)
      local isVisible = status ~= "archived"
      if mode == "mine" then
        local mySignup = me and self:FindRaidSignupRecord(eventRecord.id, me) or nil
        isVisible = isVisible and mySignup ~= nil and NormalizeRaidSignupStatus(mySignup.signupStatus) ~= "unavailable"
      else
        isVisible = isVisible and status ~= "cancelled"
      end
      if isVisible and ((tonumber(eventRecord.startAt) or 0) + (7 * SECONDS_PER_DAY)) >= now then
        table.insert(rows, eventRecord)
      end
    end
  end

  table.sort(rows, function(a, b)
    local aStart = tonumber(a.startAt or 0) or 0
    local bStart = tonumber(b.startAt or 0) or 0
    if aStart == bStart then
      return Lower(a.title or "") < Lower(b.title or "")
    end
    return aStart < bStart
  end)

  return rows
end

function LeafVE:GetRaidRosterCounts(eventId)
  local counts = {
    total = 0,
    tank = 0,
    healer = 0,
    melee = 0,
    ranged = 0,
    flex = 0,
    confirmed = 0,
    bench = 0,
  }

  for _, signup in ipairs(self:GetRaidSignupsForEvent(eventId, false)) do
    local rosterStatus = NormalizeRaidRosterStatus(signup.rosterStatus)
    if rosterStatus ~= "declined" then
      counts.total = counts.total + 1
      local role = NormalizeRaidRole(signup.preferredRole)
      counts[role] = (counts[role] or 0) + 1
      if rosterStatus == "confirmed" then
        counts.confirmed = counts.confirmed + 1
      elseif rosterStatus == "bench" then
        counts.bench = counts.bench + 1
      end
    end
  end

  return counts
end

function LeafVE:GetRaidNeedSummary(eventRecord)
  if type(eventRecord) ~= "table" then return "No raid selected." end

  local counts = self:GetRaidRosterCounts(eventRecord.id)
  local needs = {}
  local roleTargets = eventRecord.roleTargets or {}
  local roleOrder = {"tank", "healer", "melee", "ranged", "flex"}
  for _, role in ipairs(roleOrder) do
    local target = tonumber(roleTargets[role]) or 0
    local current = tonumber(counts[role]) or 0
    local missing = target - current
    if missing > 0 then
      table.insert(needs, tostring(missing) .. " " .. GetRaidRoleLabel(role))
    end
  end

  if table.getn(needs) == 0 then
    return "Roster targets filled."
  end
  return "Need " .. table.concat(needs, ", ")
end

function LeafVE:GetRaidBossListText(raidKey)
  local catalog = self:GetRaidCatalogEntry(raidKey)
  if not catalog then
    return "No boss list available."
  end

  local lines = {}
  for _, boss in ipairs(catalog.bosses or {}) do
    if boss.kind == "boss" then
      table.insert(lines, "- " .. tostring(boss.name))
    end
  end
  if table.getn(lines) == 0 then
    return "No bosses configured."
  end
  return table.concat(lines, "\n")
end

function NormalizeRaidSoftReserveCount(value)
  if value == nil then
    return 0
  end
  local count = tonumber(value) or 0
  if count >= 2 then
    return 2
  end
  if count >= 1 then
    return 1
  end
  return 0
end

function LeafVE:GetRaidBossName(raidKey, bossKey)
  local catalog = self:GetRaidCatalogEntry(raidKey)
  if not catalog then
    return tostring(bossKey or "")
  end
  for _, boss in ipairs(catalog.bosses or {}) do
    if type(boss) == "table" and tostring(boss.key or "") == tostring(bossKey or "") then
      return tostring(boss.name or bossKey or "")
    end
  end
  return tostring(bossKey or "")
end

function LeafVE:GetRaidSoftReserveLootForBoss(bossKey)
  local source = LeafVE_RaidSoftReserveLootSource
  local rows = source and source[tostring(bossKey or "")]
  if type(rows) ~= "table" then
    return {}
  end
  return rows
end

function LeafVE:GetRaidSoftReserveBosses(eventRecord)
  local rows = {}
  if type(eventRecord) ~= "table" then
    return rows
  end
  local catalog = self:GetRaidCatalogEntry(eventRecord.raidKey)
  if not catalog then
    return rows
  end
  for _, boss in ipairs(catalog.bosses or {}) do
    if type(boss) == "table" and boss.kind == "boss" then
      table.insert(rows, {
        key = tostring(boss.key),
        name = tostring(boss.name or boss.key or "Boss"),
      })
    end
  end
  return rows
end

function LeafVE:GetEffectiveRaidSoftReserveCount(eventRecord)
  local count = NormalizeRaidSoftReserveCount(eventRecord and eventRecord.softReserveCount)
  if count <= 0 then
    return 0
  end
  if type(eventRecord) ~= "table" then
    return 0
  end
  return table.getn(self:GetRaidSoftReserveBosses(eventRecord)) > 0 and count or 0
end

function LeafVE:FindRaidSoftReserveLootItem(bossKey, itemId)
  itemId = tonumber(itemId)
  if not itemId or itemId <= 0 then
    return nil
  end
  local rows = self:GetRaidSoftReserveLootForBoss(bossKey)
  for _, row in ipairs(rows) do
    if type(row) == "table" and tonumber(row.itemId) == itemId then
      return row
    end
  end
  return nil
end

function LeafVE:NormalizeRaidSoftReserveEntries(eventRecord, reserves, limit)
  local rows = {}
  if type(reserves) ~= "table" then
    return rows
  end

  local maxCount = NormalizeRaidSoftReserveCount(limit)
  if maxCount <= 0 then
    maxCount = self:GetEffectiveRaidSoftReserveCount(eventRecord)
  end
  if maxCount <= 0 then
    maxCount = 2
  end

  local allowedBosses = nil
  if type(eventRecord) == "table" then
    allowedBosses = {}
    for _, boss in ipairs(self:GetRaidSoftReserveBosses(eventRecord)) do
      allowedBosses[tostring(boss.key)] = tostring(boss.name or boss.key or "Boss")
    end
  end

  local seen = {}
  for i = 1, table.getn(reserves) do
    local reserve = reserves[i]
    if type(reserve) == "table" then
      local bossKey = Trim(tostring(reserve.bossKey or ""))
      local itemId = tonumber(reserve.itemId)
      if bossKey ~= "" and itemId and itemId > 0 then
        local bossName = ""
        if allowedBosses then
          bossName = tostring(allowedBosses[bossKey] or "")
          if bossName == "" then
            bossKey = ""
          end
        else
          bossName = Trim(tostring(reserve.bossName or ""))
        end
        if bossKey ~= "" then
          local dedupeKey = Lower(bossKey) .. ":" .. tostring(itemId)
          if not seen[dedupeKey] then
            local lootRow = self:FindRaidSoftReserveLootItem(bossKey, itemId)
            local itemName = Trim(tostring((lootRow and lootRow.name) or reserve.itemName or ""))
            if itemName ~= "" then
              table.insert(rows, {
                bossKey = bossKey,
                bossName = string.sub((bossName ~= "" and bossName or self:GetRaidBossName(eventRecord and eventRecord.raidKey, bossKey)), 1, 48),
                itemId = itemId,
                itemName = string.sub(itemName, 1, 64),
                icon = tostring((lootRow and lootRow.icon) or reserve.icon or "INV_Misc_QuestionMark"),
                quality = tonumber((lootRow and lootRow.quality) or reserve.quality) or 0,
                slot = string.sub(tostring((lootRow and lootRow.slot) or reserve.slot or ""), 1, 80),
              })
              seen[dedupeKey] = true
              if table.getn(rows) >= maxCount then
                break
              end
            end
          end
        end
      end
    end
  end

  return rows
end

function LeafVE:SerializeRaidSoftReserveEntries(reserves)
  local rows = {}
  if type(reserves) ~= "table" then
    return ""
  end
  for i = 1, table.getn(reserves) do
    local reserve = reserves[i]
    if type(reserve) == "table" then
      local itemId = tonumber(reserve.itemId)
      local bossKey = Trim(tostring(reserve.bossKey or ""))
      if bossKey ~= "" and itemId and itemId > 0 then
        table.insert(rows, table.concat({
          EncodeTalentField(bossKey),
          tostring(itemId),
          EncodeTalentField(reserve.itemName or ""),
          EncodeTalentField(reserve.icon or ""),
          tostring(tonumber(reserve.quality) or 0),
          EncodeTalentField(reserve.slot or ""),
          EncodeTalentField(reserve.bossName or ""),
        }, "~"))
      end
    end
  end
  return table.concat(rows, TALENT_RECORD_SEP)
end

function LeafVE:DeserializeRaidSoftReserveEntries(text)
  local rows = {}
  if not text or text == "" then
    return rows
  end
  local records = SplitByLiteralSep(text, TALENT_RECORD_SEP)
  for i = 1, table.getn(records) do
    local fields = SplitByLiteralSep(records[i], "~")
    local itemId = tonumber(fields[2])
    local bossKey = DecodeTalentField(fields[1] or "")
    if bossKey ~= "" and itemId and itemId > 0 then
      table.insert(rows, {
        bossKey = bossKey,
        itemId = itemId,
        itemName = DecodeTalentField(fields[3] or ""),
        icon = DecodeTalentField(fields[4] or ""),
        quality = tonumber(fields[5]) or 0,
        slot = DecodeTalentField(fields[6] or ""),
        bossName = DecodeTalentField(fields[7] or ""),
      })
    end
  end
  return rows
end

function LeafVE:GetRaidSoftReserveSummary(signup, eventRecord, shortText)
  local reserves = type(signup) == "table" and signup.softReserves or nil
  if type(reserves) ~= "table" or table.getn(reserves) == 0 then
    return ""
  end

  local lines = {}
  local maxName = shortText and 20 or 64
  local limit = self:GetEffectiveRaidSoftReserveCount(eventRecord)
  if limit <= 0 then
    limit = table.getn(reserves)
  end
  for i = 1, table.getn(reserves) do
    if i > limit then break end
    local reserve = reserves[i]
    local itemName = tostring(reserve and reserve.itemName or "")
    if string.len(itemName) > maxName then
      itemName = string.sub(itemName, 1, maxName - 3) .. "..."
    end
    if itemName ~= "" then
      table.insert(lines, itemName)
    end
  end
  return table.concat(lines, shortText and " / " or "\n")
end

function LeafVE:IsRaidEventActiveForAnnouncements(status)
  status = NormalizeRaidEventStatus(status)
  return status == "open" or status == "locked"
end

function LeafVE:BuildRaidEventAnnouncementLine(eventRecord)
  local title = tostring((type(eventRecord) == "table" and (eventRecord.title or eventRecord.raidName)) or "Raid Event")
  local postedBy = tostring((type(eventRecord) == "table" and eventRecord.postedBy) or "Unknown")
  local whenText = LeafVE_RaidUIFormatTime and LeafVE_RaidUIFormatTime(type(eventRecord) == "table" and eventRecord.startAt or 0) or date("%a %m/%d %H:%M", tonumber(type(eventRecord) == "table" and eventRecord.startAt or 0) or 0)
  return "|cFF88CCFFRaid Sign-Ups|r " .. title .. " posted by " .. postedBy .. " for " .. whenText .. "."
end

function LeafVE:AnnounceRaidEventIfNeeded(eventRecord, priorRecord)
  if type(eventRecord) ~= "table" then
    return
  end

  local status = NormalizeRaidEventStatus(eventRecord.status)
  if not self:IsRaidEventActiveForAnnouncements(status) then
    return
  end

  local priorActive = type(priorRecord) == "table" and self:IsRaidEventActiveForAnnouncements(priorRecord.status)
  if priorActive then
    return
  end

  local me = ShortName(UnitName("player"))
  if me and SamePlayerName(eventRecord.postedBy, me) then
    return
  end

  PrintRaidEventMessage(self:BuildRaidEventAnnouncementLine(eventRecord))
end

function LeafVE:NormalizeRaidEventRecord(record)
  if type(record) ~= "table" then return nil end

  local catalog = self:GetRaidCatalogEntry(record.raidKey)
  if not catalog then
    return nil
  end

  local raidSize = tonumber(record.raidSize) or tonumber(catalog.raidSize) or 20
  if raidSize < 5 then raidSize = 5 end
  if raidSize > 40 then raidSize = 40 end

  local defaultTargets = self:GetRaidDefaultRoleTargets(catalog.key, raidSize)
  local roleTargets = type(record.roleTargets) == "table" and record.roleTargets or {}
  local title = Trim(tostring(record.title or catalog.name))
  title = string.sub(title, 1, 40)
  if title == "" then
    title = catalog.name
  end

  local notes = Trim(tostring(record.notes or ""))
  notes = string.sub(notes, 1, 120)
  local consumables = Trim(tostring(record.consumables or ""))
  consumables = string.sub(consumables, 1, 120)

  local normalized = {
    id = Trim(tostring(record.id or "")),
    raidKey = catalog.key,
    raidName = catalog.name,
    title = title,
    postedBy = ShortName(record.postedBy or ""),
    postedAt = tonumber(record.postedAt) or Now(),
    updatedAt = tonumber(record.updatedAt) or tonumber(record.postedAt) or Now(),
    startAt = tonumber(record.startAt) or 0,
    signupCloseAt = tonumber(record.signupCloseAt) or tonumber(record.startAt) or 0,
    status = NormalizeRaidEventStatus(record.status),
    raidSize = raidSize,
    notes = notes,
    consumables = consumables,
    roleTargets = {
      tank = tonumber(roleTargets.tank) or defaultTargets.tank,
      healer = tonumber(roleTargets.healer) or defaultTargets.healer,
      melee = tonumber(roleTargets.melee) or defaultTargets.melee,
      ranged = tonumber(roleTargets.ranged) or defaultTargets.ranged,
      flex = tonumber(roleTargets.flex) or defaultTargets.flex,
    },
    softReserveCount = NormalizeRaidSoftReserveCount(record.softReserveCount),
  }

  if normalized.id == "" then
    return nil
  end
  if not normalized.postedBy or normalized.postedBy == "" then
    return nil
  end

  return normalized
end

function LeafVE:StoreRaidEventRecord(record)
  local normalized = self:NormalizeRaidEventRecord(record)
  if not normalized then return nil, false end

  local db = self:GetRaidEventsDB()
  local existing = db[normalized.id]
  local changed = true
  if type(existing) == "table" then
    local priorUpdatedAt = tonumber(existing.updatedAt or 0) or 0
    if priorUpdatedAt > normalized.updatedAt then
      return existing, false
    end
    changed = priorUpdatedAt ~= normalized.updatedAt or NormalizeRaidEventStatus(existing.status) ~= normalized.status
  end
  db[normalized.id] = normalized

  local eventSignups = self:GetRaidSignupsDB()[normalized.id]
  if type(eventSignups) == "table" then
    for playerKey, signupRecord in pairs(eventSignups) do
      if type(signupRecord) == "table" then
        signupRecord.softReserves = self:NormalizeRaidSoftReserveEntries(normalized, signupRecord.softReserves, normalized.softReserveCount)
        eventSignups[playerKey] = signupRecord
      end
    end
  end

  if changed then
    self:AnnounceRaidEventIfNeeded(normalized, existing)
  end

  if changed and LeafVE.UI and LeafVE.UI.panels and LeafVE.UI.panels.raidSignups and LeafVE.UI.panels.raidSignups:IsVisible() and LeafVE.UI.RefreshRaidSignupPanel then
    LeafVE.UI:RefreshRaidSignupPanel(true)
  end
  return normalized, changed
end

function LeafVE:StoreRaidSignupRecord(record)
  if type(record) ~= "table" then return nil, false end

  local player = ShortName(record.player or "")
  local eventId = Trim(tostring(record.eventId or ""))
  if not player or eventId == "" then return nil, false end

  local classTag = string.upper(Trim(record.classTag or self:GetClassTagForPlayer(player) or "UNKNOWN"))
  if classTag == "" then classTag = "UNKNOWN" end
  local specName = Trim(tostring(record.specName or ""))
  if specName == "" then
    local spec = self:GetSpecSnapshotForPlayer(player, classTag)
    specName = spec and spec.name or classTag
  end

  local normalized = {
    eventId = eventId,
    player = player,
    classTag = classTag,
    specName = string.sub(specName, 1, 32),
    signupStatus = NormalizeRaidSignupStatus(record.signupStatus),
    preferredRole = NormalizeRaidRole(record.preferredRole),
    rosterStatus = NormalizeRaidRosterStatus(record.rosterStatus),
    note = string.sub(Trim(tostring(record.note or "")), 1, 60),
    signedAt = tonumber(record.signedAt) or Now(),
    updatedAt = tonumber(record.updatedAt) or tonumber(record.signedAt) or Now(),
    softReserves = self:NormalizeRaidSoftReserveEntries(self:GetRaidEventsDB()[eventId], record.softReserves, nil),
  }

  local signupsDB = self:GetRaidSignupsDB()
  if type(signupsDB[eventId]) ~= "table" then
    signupsDB[eventId] = {}
  end

  local key = Lower(player)
  local existing = signupsDB[eventId][key]
  local changed = true
  if type(existing) == "table" then
    local priorUpdatedAt = tonumber(existing.updatedAt or 0) or 0
    if priorUpdatedAt > normalized.updatedAt then
      return existing, false
    end
    changed = priorUpdatedAt ~= normalized.updatedAt
  end
  signupsDB[eventId][key] = normalized

  if changed and LeafVE.UI and LeafVE.UI.panels and LeafVE.UI.panels.raidSignups and LeafVE.UI.panels.raidSignups:IsVisible() and LeafVE.UI.RefreshRaidSignupPanel then
    LeafVE.UI:RefreshRaidSignupPanel(true)
  end
  return normalized, changed
end

function LeafVE:BroadcastRaidEvent(eventRecord, messageType)
  if not InGuild() or type(eventRecord) ~= "table" then return end

  local payload = table.concat({
    EncodeTalentField(eventRecord.id or ""),
    EncodeTalentField(eventRecord.raidKey or ""),
    EncodeTalentField(eventRecord.title or ""),
    EncodeTalentField(eventRecord.postedBy or ""),
    tostring(tonumber(eventRecord.postedAt) or 0),
    tostring(tonumber(eventRecord.updatedAt) or 0),
    tostring(tonumber(eventRecord.startAt) or 0),
    tostring(tonumber(eventRecord.signupCloseAt) or 0),
    EncodeTalentField(NormalizeRaidEventStatus(eventRecord.status)),
    tostring(tonumber(eventRecord.raidSize) or 20),
    tostring(tonumber(eventRecord.roleTargets and eventRecord.roleTargets.tank) or 0),
    tostring(tonumber(eventRecord.roleTargets and eventRecord.roleTargets.healer) or 0),
    tostring(tonumber(eventRecord.roleTargets and eventRecord.roleTargets.melee) or 0),
    tostring(tonumber(eventRecord.roleTargets and eventRecord.roleTargets.ranged) or 0),
    tostring(tonumber(eventRecord.roleTargets and eventRecord.roleTargets.flex) or 0),
    EncodeTalentField(eventRecord.notes or ""),
    EncodeTalentField(eventRecord.consumables or ""),
    tostring(NormalizeRaidSoftReserveCount(eventRecord.softReserveCount)),
  }, SEP)

  SendAddonMessage("LeafVE", (messageType or "RAIDEVENT:") .. payload, "GUILD")
end

function LeafVE:BroadcastRaidSignup(signupRecord, messageType)
  if not InGuild() or type(signupRecord) ~= "table" then return end

  local payload = table.concat({
    EncodeTalentField(signupRecord.eventId or ""),
    EncodeTalentField(signupRecord.player or ""),
    EncodeTalentField(signupRecord.classTag or ""),
    EncodeTalentField(signupRecord.specName or ""),
    EncodeTalentField(NormalizeRaidSignupStatus(signupRecord.signupStatus)),
    EncodeTalentField(NormalizeRaidRole(signupRecord.preferredRole)),
    EncodeTalentField(NormalizeRaidRosterStatus(signupRecord.rosterStatus)),
    EncodeTalentField(signupRecord.note or ""),
    tostring(tonumber(signupRecord.signedAt) or 0),
    tostring(tonumber(signupRecord.updatedAt) or 0),
    EncodeTalentField(self:SerializeRaidSoftReserveEntries(signupRecord.softReserves)),
  }, SEP)

  SendAddonMessage("LeafVE", (messageType or "RAIDSIGNUP:") .. payload, "GUILD")
end

function LeafVE:BroadcastRaidEventSnapshot(force)
  if not InGuild() then return end
  local now = Now()
  self.lastRaidSyncRespondAt = self.lastRaidSyncRespondAt or 0
  if not force and (now - self.lastRaidSyncRespondAt) < 10 then
    return
  end
  self.lastRaidSyncRespondAt = now

  for _, eventRecord in pairs(self:GetRaidEventsDB()) do
    if type(eventRecord) == "table" then
      local updatedAt = tonumber(eventRecord.updatedAt or eventRecord.postedAt or 0) or 0
      if NormalizeRaidEventStatus(eventRecord.status) ~= "archived" and updatedAt >= (now - (14 * SECONDS_PER_DAY)) then
        self:BroadcastRaidEvent(eventRecord, "RAIDEVENTSYNC:")
      end
    end
  end
end

function LeafVE:BroadcastRaidSignupSnapshot(force)
  if not InGuild() then return end
  local now = Now()
  self.lastRaidSignupRespondAt = self.lastRaidSignupRespondAt or 0
  if not force and (now - self.lastRaidSignupRespondAt) < 10 then
    return
  end
  self.lastRaidSignupRespondAt = now

  for eventId, signupTable in pairs(self:GetRaidSignupsDB()) do
    if type(signupTable) == "table" then
      local eventRecord = self:GetRaidEventsDB()[eventId]
      if type(eventRecord) == "table" and NormalizeRaidEventStatus(eventRecord.status) ~= "archived" then
        for _, signupRecord in pairs(signupTable) do
          if type(signupRecord) == "table" then
            self:BroadcastRaidSignup(signupRecord, "RAIDSIGNUPSYNC:")
          end
        end
      end
    end
  end
end

function LeafVE:RequestRaidSignupSync(force)
  if not InGuild() then return end
  local now = Now()
  if not force and (now - (self.lastRaidSignupRequestAt or 0)) < 20 then
    return
  end
  self.lastRaidSignupRequestAt = now
  SendAddonMessage("LeafVE", force and "RAIDREQ_FORCE" or "RAIDREQ", "GUILD")
end

function LeafVE:HandleIncomingRaidEventMessage(payload)
  local fields = SplitByLiteralSep(payload or "", SEP)
  local consumables = ""
  local softReserveCount = 0
  if fields[18] ~= nil then
    consumables = DecodeTalentField(fields[17] or "")
    softReserveCount = tonumber(fields[18]) or 0
  else
    softReserveCount = tonumber(fields[17]) or 0
  end
  local record = {
    id = DecodeTalentField(fields[1] or ""),
    raidKey = DecodeTalentField(fields[2] or ""),
    title = DecodeTalentField(fields[3] or ""),
    postedBy = ShortName(DecodeTalentField(fields[4] or "")),
    postedAt = tonumber(fields[5]) or Now(),
    updatedAt = tonumber(fields[6]) or tonumber(fields[5]) or Now(),
    startAt = tonumber(fields[7]) or 0,
    signupCloseAt = tonumber(fields[8]) or tonumber(fields[7]) or 0,
    status = DecodeTalentField(fields[9] or "open"),
    raidSize = tonumber(fields[10]) or 20,
    roleTargets = {
      tank = tonumber(fields[11]) or 0,
      healer = tonumber(fields[12]) or 0,
      melee = tonumber(fields[13]) or 0,
      ranged = tonumber(fields[14]) or 0,
      flex = tonumber(fields[15]) or 0,
    },
    notes = DecodeTalentField(fields[16] or ""),
    consumables = consumables,
    softReserveCount = softReserveCount,
  }
  return self:StoreRaidEventRecord(record)
end

function LeafVE:HandleIncomingRaidSignupMessage(payload)
  local fields = SplitByLiteralSep(payload or "", SEP)
  local record = {
    eventId = DecodeTalentField(fields[1] or ""),
    player = ShortName(DecodeTalentField(fields[2] or "")),
    classTag = DecodeTalentField(fields[3] or ""),
    specName = DecodeTalentField(fields[4] or ""),
    signupStatus = DecodeTalentField(fields[5] or "going"),
    preferredRole = DecodeTalentField(fields[6] or "flex"),
    rosterStatus = DecodeTalentField(fields[7] or "signed"),
    note = DecodeTalentField(fields[8] or ""),
    signedAt = tonumber(fields[9]) or Now(),
    updatedAt = tonumber(fields[10]) or tonumber(fields[9]) or Now(),
    softReserves = self:DeserializeRaidSoftReserveEntries(DecodeTalentField(fields[11] or "")),
  }
  return self:StoreRaidSignupRecord(record)
end

function LeafVE:CreateRaidEvent(raidKey, title, startAt, signupCloseAt, raidSize, roleTargets, notes, consumables, softReserveCount)
  local me = ShortName(UnitName("player"))
  if not me then
    return nil, "Your player name could not be determined."
  end
  if not self:IsRaidEventCreatorRank(me) then
    return nil, "Only Anbu, Sannin, or Hokage can create raid events."
  end

  local now = Now()
  local eventRecord = {
    id = tostring(me) .. ":" .. tostring(startAt or now) .. ":" .. tostring(now),
    raidKey = raidKey,
    title = title,
    postedBy = me,
    postedAt = now,
    updatedAt = now,
    startAt = tonumber(startAt) or 0,
    signupCloseAt = tonumber(signupCloseAt) or tonumber(startAt) or 0,
    status = "open",
    raidSize = tonumber(raidSize) or 20,
    roleTargets = roleTargets or {},
    notes = notes or "",
    consumables = consumables or "",
    softReserveCount = NormalizeRaidSoftReserveCount(softReserveCount),
  }

  if eventRecord.startAt <= 0 then
    return nil, "Start time is invalid."
  end

  local stored = self:StoreRaidEventRecord(eventRecord)
  if not stored then
    return nil, "Unable to create raid event."
  end
  PrintRaidEventMessage(self:BuildRaidEventAnnouncementLine(stored))
  self:BroadcastRaidEvent(stored)
  return stored
end

function LeafVE:SetRaidEventStatus(eventId, status)
  local me = ShortName(UnitName("player"))
  if not me then
    return nil, "Your player name could not be determined."
  end

  local eventRecord = self:GetRaidEventsDB()[tostring(eventId or "")]
  if type(eventRecord) ~= "table" then
    return nil, "Raid event not found."
  end
  if not self:CanManageRaidEvent(eventRecord, me) then
    return nil, "Only the raid lead or Jonin+ can manage this event."
  end

  local updatedAt = Now()
  local priorUpdatedAt = tonumber(eventRecord.updatedAt or eventRecord.postedAt or 0) or 0
  if updatedAt <= priorUpdatedAt then
    updatedAt = priorUpdatedAt + 1
  end

  eventRecord.status = NormalizeRaidEventStatus(status)
  eventRecord.updatedAt = updatedAt
  local stored = self:StoreRaidEventRecord(eventRecord)
  if not stored then
    return nil, "Unable to update raid event."
  end
  self:BroadcastRaidEvent(stored)
  return stored
end

function LeafVE:SubmitRaidSignup(eventId, signupStatus, preferredRole, note, softReserves)
  local me = ShortName(UnitName("player"))
  if not me then
    return nil, "Your player name could not be determined."
  end

  local eventRecord = self:GetRaidEventsDB()[tostring(eventId or "")]
  if type(eventRecord) ~= "table" then
    return nil, "Raid event not found."
  end
  if NormalizeRaidEventStatus(eventRecord.status) == "completed" or NormalizeRaidEventStatus(eventRecord.status) == "cancelled" or NormalizeRaidEventStatus(eventRecord.status) == "archived" then
    return nil, "This raid event is no longer accepting signups."
  end
  if NormalizeRaidEventStatus(eventRecord.status) == "locked" and not self:CanManageRaidEvent(eventRecord, me) then
    return nil, "This raid event is locked."
  end

  local classTag = self:GetClassTagForPlayer(me)
  local spec = self:GetSpecSnapshotForPlayer(me, classTag)
  local role = NormalizeRaidRole(preferredRole or (LeafVE_DB.raidProfile and LeafVE_DB.raidProfile.defaultRole) or self:GetSuggestedRaidRoleForPlayer(me, classTag, spec and spec.name))
  local existing = self:FindRaidSignupRecord(eventId, me)
  local eventStatus = NormalizeRaidEventStatus(eventRecord.status)
  local updatedAt = Now()
  local signedAt = existing and (tonumber(existing.signedAt) or updatedAt) or updatedAt
  local priorUpdatedAt = existing and (tonumber(existing.updatedAt or existing.signedAt or 0) or 0) or 0
  if updatedAt <= priorUpdatedAt then
    updatedAt = priorUpdatedAt + 1
  end
  local normalizedSignupStatus = NormalizeRaidSignupStatus(signupStatus)
  local normalizedSoftReserves = {}
  if normalizedSignupStatus ~= "unavailable" then
    if eventStatus == "locked" then
      normalizedSoftReserves = self:NormalizeRaidSoftReserveEntries(eventRecord, existing and existing.softReserves or {}, eventRecord.softReserveCount)
    else
      normalizedSoftReserves = self:NormalizeRaidSoftReserveEntries(eventRecord, softReserves or (existing and existing.softReserves) or {}, eventRecord.softReserveCount)
      local reserveLimit = self:GetEffectiveRaidSoftReserveCount(eventRecord)
      if reserveLimit > 0 and table.getn(normalizedSoftReserves) < reserveLimit then
        return nil, "Select " .. tostring(reserveLimit) .. " soft reserve" .. (reserveLimit ~= 1 and "s" or "") .. " first."
      end
    end
  end

  local record = {
    eventId = tostring(eventId),
    player = me,
    classTag = classTag,
    specName = spec and spec.name or classTag,
    signupStatus = normalizedSignupStatus,
    preferredRole = role,
    rosterStatus = existing and existing.rosterStatus or "signed",
    note = note or "",
    signedAt = signedAt,
    updatedAt = updatedAt,
    softReserves = normalizedSoftReserves,
  }

  local stored = self:StoreRaidSignupRecord(record)
  if not stored then
    return nil, "Unable to save raid signup."
  end
  if LeafVE_DB and LeafVE_DB.raidProfile then
    LeafVE_DB.raidProfile.defaultRole = role
  end
  self:BroadcastRaidSignup(stored)
  return stored
end

function LeafVE:SetRaidRosterStatus(eventId, playerName, rosterStatus)
  local me = ShortName(UnitName("player"))
  if not me then
    return nil, "Your player name could not be determined."
  end

  local eventRecord = self:GetRaidEventsDB()[tostring(eventId or "")]
  if type(eventRecord) ~= "table" then
    return nil, "Raid event not found."
  end
  if not self:CanManageRaidEvent(eventRecord, me) then
    return nil, "Only the raid lead or Jonin+ can manage this roster."
  end

  local existing = self:FindRaidSignupRecord(eventId, playerName)
  if type(existing) ~= "table" then
    return nil, "Raid signup not found."
  end

  local updatedAt = Now()
  local priorUpdatedAt = tonumber(existing.updatedAt or existing.signedAt or 0) or 0
  if updatedAt <= priorUpdatedAt then
    updatedAt = priorUpdatedAt + 1
  end

  existing.rosterStatus = NormalizeRaidRosterStatus(rosterStatus)
  existing.updatedAt = updatedAt
  local stored = self:StoreRaidSignupRecord(existing)
  if not stored then
    return nil, "Unable to update roster status."
  end
  self:BroadcastRaidSignup(stored)
  return stored
end

LeafVE_GuildEventCategoryOrder = LeafVE_GuildEventCategoryOrder or {
  "Guild Meeting",
  "Dungeon Run",
  "PvP",
  "World Boss",
  "Farming",
  "Social",
  "Other",
}

function NormalizeGuildEventCategory(value)
  local category = Trim(tostring(value or ""))
  if category == "" then
    return LeafVE_GuildEventCategoryOrder[1]
  end
  for _, option in ipairs(LeafVE_GuildEventCategoryOrder) do
    if Lower(option) == Lower(category) then
      return option
    end
  end
  return string.sub(category, 1, 28)
end

function LeafVE:GetGuildEventsDB()
  EnsureDB()
  return LeafVE_GlobalDB.guildEvents
end

function LeafVE:GetGuildEventRSVPDB()
  EnsureDB()
  return LeafVE_GlobalDB.guildEventRSVPs
end

function LeafVE:FindGuildEventRSVP(eventId, playerName)
  local eventRSVPs = self:GetGuildEventRSVPDB()[tostring(eventId or "")]
  if type(eventRSVPs) ~= "table" then return nil end
  playerName = ShortName(playerName)
  if not playerName then return nil end
  return eventRSVPs[Lower(playerName)]
end

function LeafVE:GetGuildEventRSVPs(eventId, includeUnavailable)
  local rows = {}
  local eventRSVPs = self:GetGuildEventRSVPDB()[tostring(eventId or "")]
  if type(eventRSVPs) ~= "table" then
    return rows
  end

  for _, record in pairs(eventRSVPs) do
    if type(record) == "table" then
      local signupStatus = NormalizeRaidSignupStatus(record.signupStatus)
      if includeUnavailable or signupStatus ~= "unavailable" then
        table.insert(rows, record)
      end
    end
  end

  table.sort(rows, function(a, b)
    local aStatus = NormalizeRaidSignupStatus(a.signupStatus)
    local bStatus = NormalizeRaidSignupStatus(b.signupStatus)
    if aStatus == bStatus then
      return Lower(a.player or "") < Lower(b.player or "")
    end
    return aStatus < bStatus
  end)

  return rows
end

function LeafVE:GetGuildEventResponseCounts(eventId)
  local counts = { total = 0, going = 0, tentative = 0, late = 0, unavailable = 0 }
  for _, record in ipairs(self:GetGuildEventRSVPs(eventId, true)) do
    local status = NormalizeRaidSignupStatus(record.signupStatus)
    counts.total = counts.total + 1
    counts[status] = (counts[status] or 0) + 1
  end
  return counts
end

function LeafVE:GetVisibleGuildEvents(mode)
  local rows = {}
  local me = ShortName(UnitName("player"))
  local now = Now()

  for _, eventRecord in pairs(self:GetGuildEventsDB()) do
    if type(eventRecord) == "table" then
      local status = NormalizeRaidEventStatus(eventRecord.status)
      local isVisible = status ~= "archived" and status ~= "cancelled"
      if mode == "mine" then
        local myRSVP = me and self:FindGuildEventRSVP(eventRecord.id, me) or nil
        isVisible = isVisible and myRSVP ~= nil and NormalizeRaidSignupStatus(myRSVP.signupStatus) ~= "unavailable"
      end
      if isVisible and ((tonumber(eventRecord.startAt) or 0) + (14 * SECONDS_PER_DAY)) >= now then
        table.insert(rows, eventRecord)
      end
    end
  end

  table.sort(rows, function(a, b)
    local aStart = tonumber(a.startAt or 0) or 0
    local bStart = tonumber(b.startAt or 0) or 0
    if aStart == bStart then
      return Lower(a.title or "") < Lower(b.title or "")
    end
    return aStart < bStart
  end)

  return rows
end

function LeafVE:IsGuildEventActiveForAnnouncements(status)
  status = NormalizeRaidEventStatus(status)
  return status == "open" or status == "locked"
end

function LeafVE:BuildGuildEventAnnouncementLine(eventRecord)
  local title = tostring((type(eventRecord) == "table" and eventRecord.title) or "Guild Event")
  local postedBy = tostring((type(eventRecord) == "table" and eventRecord.postedBy) or "Unknown")
  local whenText = LeafVE_RaidUIFormatTime and LeafVE_RaidUIFormatTime(type(eventRecord) == "table" and eventRecord.startAt or 0) or date("%a %m/%d %H:%M", tonumber(type(eventRecord) == "table" and eventRecord.startAt or 0) or 0)
  return "|cFF88CCFFGuild Event|r " .. title .. " posted by " .. postedBy .. " for " .. whenText .. "."
end

function LeafVE:AnnounceGuildEventIfNeeded(eventRecord, priorRecord)
  if type(eventRecord) ~= "table" then
    return
  end

  local status = NormalizeRaidEventStatus(eventRecord.status)
  if not self:IsGuildEventActiveForAnnouncements(status) then
    return
  end

  local priorActive = type(priorRecord) == "table" and self:IsGuildEventActiveForAnnouncements(priorRecord.status)
  if priorActive then
    return
  end

  local me = ShortName(UnitName("player"))
  if me and SamePlayerName(eventRecord.postedBy, me) then
    return
  end

  PrintRaidEventMessage(self:BuildGuildEventAnnouncementLine(eventRecord))
end

function LeafVE:NormalizeGuildEventRecord(record)
  if type(record) ~= "table" then return nil end

  local title = Trim(tostring(record.title or ""))
  title = string.sub(title, 1, 50)
  if title == "" then
    return nil
  end

  local notes = Trim(tostring(record.notes or ""))
  notes = string.sub(notes, 1, 140)
  local rewards = Trim(tostring(record.rewards or ""))
  rewards = string.sub(rewards, 1, 140)

  local normalized = {
    id = Trim(tostring(record.id or "")),
    title = title,
    category = NormalizeGuildEventCategory(record.category),
    postedBy = ShortName(record.postedBy or ""),
    postedAt = tonumber(record.postedAt) or Now(),
    updatedAt = tonumber(record.updatedAt) or tonumber(record.postedAt) or Now(),
    startAt = tonumber(record.startAt) or 0,
    signupCloseAt = tonumber(record.signupCloseAt) or tonumber(record.startAt) or 0,
    status = NormalizeRaidEventStatus(record.status),
    notes = notes,
    rewards = rewards,
  }

  if normalized.id == "" or not normalized.postedBy or normalized.postedBy == "" then
    return nil
  end

  return normalized
end

function LeafVE:StoreGuildEventRecord(record)
  local normalized = self:NormalizeGuildEventRecord(record)
  if not normalized then return nil, false end

  local db = self:GetGuildEventsDB()
  local existing = db[normalized.id]
  local changed = true
  if type(existing) == "table" then
    local priorUpdatedAt = tonumber(existing.updatedAt or 0) or 0
    if priorUpdatedAt > normalized.updatedAt then
      return existing, false
    end
    changed = priorUpdatedAt ~= normalized.updatedAt or NormalizeRaidEventStatus(existing.status) ~= normalized.status
  end
  db[normalized.id] = normalized

  if normalized.status == "cancelled" or normalized.status == "archived" then
    local rsvpDB = self:GetGuildEventRSVPDB()
    rsvpDB[normalized.id] = nil
  end

  if changed then
    self:AnnounceGuildEventIfNeeded(normalized, existing)
  end
  if changed and LeafVE.UI and LeafVE.UI.panels and LeafVE.UI.panels.guildEvents and LeafVE.UI.panels.guildEvents:IsVisible() and LeafVE.UI.RefreshGuildEventsPanel then
    LeafVE.UI:RefreshGuildEventsPanel(true)
  end
  return normalized, changed
end

function LeafVE:StoreGuildEventRSVPRecord(record)
  if type(record) ~= "table" then return nil, false end

  local player = ShortName(record.player or "")
  local eventId = Trim(tostring(record.eventId or ""))
  if not player or eventId == "" then return nil, false end

  local classTag = string.upper(Trim(record.classTag or self:GetClassTagForPlayer(player) or "UNKNOWN"))
  if classTag == "" then classTag = "UNKNOWN" end
  local specName = Trim(tostring(record.specName or ""))
  if specName == "" then
    local spec = self:GetSpecSnapshotForPlayer(player, classTag)
    specName = spec and spec.name or classTag
  end

  local normalized = {
    eventId = eventId,
    player = player,
    classTag = classTag,
    specName = string.sub(specName, 1, 32),
    signupStatus = NormalizeRaidSignupStatus(record.signupStatus),
    note = string.sub(Trim(tostring(record.note or "")), 1, 80),
    signedAt = tonumber(record.signedAt) or Now(),
    updatedAt = tonumber(record.updatedAt) or tonumber(record.signedAt) or Now(),
  }

  local rsvpDB = self:GetGuildEventRSVPDB()
  local eventRecord = self:GetGuildEventsDB()[eventId]
  local eventStatus = type(eventRecord) == "table" and NormalizeRaidEventStatus(eventRecord.status) or nil
  if eventStatus == "cancelled" or eventStatus == "archived" then
    local key = Lower(player)
    local changed = false
    if type(rsvpDB[eventId]) == "table" and rsvpDB[eventId][key] then
      rsvpDB[eventId][key] = nil
      if next(rsvpDB[eventId]) == nil then
        rsvpDB[eventId] = nil
      end
      changed = true
    end
    if changed and LeafVE.UI and LeafVE.UI.panels and LeafVE.UI.panels.guildEvents and LeafVE.UI.panels.guildEvents:IsVisible() and LeafVE.UI.RefreshGuildEventsPanel then
      LeafVE.UI:RefreshGuildEventsPanel(true)
    end
    return nil, changed
  end

  if type(rsvpDB[eventId]) ~= "table" then
    rsvpDB[eventId] = {}
  end

  local key = Lower(player)
  local existing = rsvpDB[eventId][key]
  local changed = true
  if type(existing) == "table" then
    local priorUpdatedAt = tonumber(existing.updatedAt or existing.signedAt or 0) or 0
    if priorUpdatedAt > normalized.updatedAt then
      return existing, false
    end
    changed = priorUpdatedAt ~= normalized.updatedAt
  end
  rsvpDB[eventId][key] = normalized

  if changed and LeafVE.UI and LeafVE.UI.panels and LeafVE.UI.panels.guildEvents and LeafVE.UI.panels.guildEvents:IsVisible() and LeafVE.UI.RefreshGuildEventsPanel then
    LeafVE.UI:RefreshGuildEventsPanel(true)
  end
  return normalized, changed
end

function LeafVE:BroadcastGuildEvent(eventRecord, messageType)
  if not InGuild() or type(eventRecord) ~= "table" then return end

  local payload = table.concat({
    EncodeTalentField(eventRecord.id or ""),
    EncodeTalentField(eventRecord.title or ""),
    EncodeTalentField(eventRecord.category or ""),
    EncodeTalentField(eventRecord.postedBy or ""),
    tostring(tonumber(eventRecord.postedAt) or 0),
    tostring(tonumber(eventRecord.updatedAt) or 0),
    tostring(tonumber(eventRecord.startAt) or 0),
    tostring(tonumber(eventRecord.signupCloseAt) or 0),
    EncodeTalentField(NormalizeRaidEventStatus(eventRecord.status)),
    EncodeTalentField(eventRecord.notes or ""),
    EncodeTalentField(eventRecord.rewards or ""),
  }, SEP)

  SendAddonMessage("LeafVE", (messageType or "GUILDEVENT:") .. payload, "GUILD")
end

function LeafVE:BroadcastGuildEventRSVP(record, messageType)
  if not InGuild() or type(record) ~= "table" then return end

  local payload = table.concat({
    EncodeTalentField(record.eventId or ""),
    EncodeTalentField(record.player or ""),
    EncodeTalentField(record.classTag or ""),
    EncodeTalentField(record.specName or ""),
    EncodeTalentField(NormalizeRaidSignupStatus(record.signupStatus)),
    EncodeTalentField(record.note or ""),
    tostring(tonumber(record.signedAt) or 0),
    tostring(tonumber(record.updatedAt) or 0),
  }, SEP)

  SendAddonMessage("LeafVE", (messageType or "GUILDEVENTRSVP:") .. payload, "GUILD")
end

function LeafVE:BroadcastGuildEventSnapshot(force)
  if not InGuild() then return end
  local now = Now()
  self.lastGuildEventRespondAt = self.lastGuildEventRespondAt or 0
  if not force and (now - self.lastGuildEventRespondAt) < 10 then
    return
  end
  self.lastGuildEventRespondAt = now

  for _, eventRecord in pairs(self:GetGuildEventsDB()) do
    if type(eventRecord) == "table" then
      local updatedAt = tonumber(eventRecord.updatedAt or eventRecord.postedAt or 0) or 0
      if NormalizeRaidEventStatus(eventRecord.status) ~= "archived" and updatedAt >= (now - (30 * SECONDS_PER_DAY)) then
        self:BroadcastGuildEvent(eventRecord, "GUILDEVENTSYNC:")
      end
    end
  end
end

function LeafVE:BroadcastGuildEventRSVPSnapshot(force)
  if not InGuild() then return end
  local now = Now()
  self.lastGuildEventRSVPRespondAt = self.lastGuildEventRSVPRespondAt or 0
  if not force and (now - self.lastGuildEventRSVPRespondAt) < 10 then
    return
  end
  self.lastGuildEventRSVPRespondAt = now

  for eventId, signupTable in pairs(self:GetGuildEventRSVPDB()) do
    if type(signupTable) == "table" then
      local eventRecord = self:GetGuildEventsDB()[eventId]
      local eventStatus = type(eventRecord) == "table" and NormalizeRaidEventStatus(eventRecord.status) or nil
      if type(eventRecord) == "table" and eventStatus ~= "archived" and eventStatus ~= "cancelled" then
        for _, record in pairs(signupTable) do
          if type(record) == "table" then
            self:BroadcastGuildEventRSVP(record, "GUILDEVENTRSVPSYNC:")
          end
        end
      end
    end
  end
end

function LeafVE:RequestGuildEventSync(force)
  if not InGuild() then return end
  local now = Now()
  if not force and (now - (self.lastGuildEventRequestAt or 0)) < 20 then
    return
  end
  self.lastGuildEventRequestAt = now
  SendAddonMessage("LeafVE", force and "GUILDEVENTREQ_FORCE" or "GUILDEVENTREQ", "GUILD")
end

function LeafVE:HandleIncomingGuildEventMessage(payload)
  local fields = SplitByLiteralSep(payload or "", SEP)
  local record = {
    id = DecodeTalentField(fields[1] or ""),
    title = DecodeTalentField(fields[2] or ""),
    category = DecodeTalentField(fields[3] or ""),
    postedBy = ShortName(DecodeTalentField(fields[4] or "")),
    postedAt = tonumber(fields[5]) or Now(),
    updatedAt = tonumber(fields[6]) or tonumber(fields[5]) or Now(),
    startAt = tonumber(fields[7]) or 0,
    signupCloseAt = tonumber(fields[8]) or tonumber(fields[7]) or 0,
    status = DecodeTalentField(fields[9] or "open"),
    notes = DecodeTalentField(fields[10] or ""),
    rewards = DecodeTalentField(fields[11] or ""),
  }
  return self:StoreGuildEventRecord(record)
end

function LeafVE:HandleIncomingGuildEventRSVPMessage(payload)
  local fields = SplitByLiteralSep(payload or "", SEP)
  local record = {
    eventId = DecodeTalentField(fields[1] or ""),
    player = ShortName(DecodeTalentField(fields[2] or "")),
    classTag = DecodeTalentField(fields[3] or ""),
    specName = DecodeTalentField(fields[4] or ""),
    signupStatus = DecodeTalentField(fields[5] or "going"),
    note = DecodeTalentField(fields[6] or ""),
    signedAt = tonumber(fields[7]) or Now(),
    updatedAt = tonumber(fields[8]) or tonumber(fields[7]) or Now(),
  }
  return self:StoreGuildEventRSVPRecord(record)
end

function LeafVE:CreateGuildEvent(title, category, startAt, signupCloseAt, notes, rewards)
  local me = ShortName(UnitName("player"))
  if not me then
    return nil, "Your player name could not be determined."
  end
  if not self:IsRaidOrganizerRank(me) then
    return nil, "Only Jonin, Anbu, Sannin, or Hokage can create guild events."
  end

  local now = Now()
  local eventRecord = {
    id = tostring(me) .. ":GE:" .. tostring(startAt or now) .. ":" .. tostring(now),
    title = title,
    category = category,
    postedBy = me,
    postedAt = now,
    updatedAt = now,
    startAt = tonumber(startAt) or 0,
    signupCloseAt = tonumber(signupCloseAt) or tonumber(startAt) or 0,
    status = "open",
    notes = notes or "",
    rewards = rewards or "",
  }

  if eventRecord.startAt <= 0 then
    return nil, "Start time is invalid."
  end

  local stored = self:StoreGuildEventRecord(eventRecord)
  if not stored then
    return nil, "Unable to create guild event."
  end
  PrintRaidEventMessage(self:BuildGuildEventAnnouncementLine(stored))
  self:BroadcastGuildEvent(stored)
  return stored
end

function LeafVE:SetGuildEventStatus(eventId, status)
  local me = ShortName(UnitName("player"))
  if not me then
    return nil, "Your player name could not be determined."
  end

  local eventRecord = self:GetGuildEventsDB()[tostring(eventId or "")]
  if type(eventRecord) ~= "table" then
    return nil, "Guild event not found."
  end
  if not self:CanManageRaidEvent(eventRecord, me) then
    return nil, "Only the event lead or Jonin+ can manage this event."
  end

  local updatedAt = Now()
  local priorUpdatedAt = tonumber(eventRecord.updatedAt or eventRecord.postedAt or 0) or 0
  if updatedAt <= priorUpdatedAt then
    updatedAt = priorUpdatedAt + 1
  end

  eventRecord.status = NormalizeRaidEventStatus(status)
  eventRecord.updatedAt = updatedAt
  local stored = self:StoreGuildEventRecord(eventRecord)
  if not stored then
    return nil, "Unable to update guild event."
  end
  self:BroadcastGuildEvent(stored)
  return stored
end

function LeafVE:SubmitGuildEventRSVP(eventId, signupStatus, note)
  local me = ShortName(UnitName("player"))
  if not me then
    return nil, "Your player name could not be determined."
  end

  local eventRecord = self:GetGuildEventsDB()[tostring(eventId or "")]
  if type(eventRecord) ~= "table" then
    return nil, "Guild event not found."
  end
  if NormalizeRaidEventStatus(eventRecord.status) == "completed" or NormalizeRaidEventStatus(eventRecord.status) == "cancelled" or NormalizeRaidEventStatus(eventRecord.status) == "archived" then
    return nil, "This guild event is no longer accepting responses."
  end
  if NormalizeRaidEventStatus(eventRecord.status) == "locked" and not self:CanManageRaidEvent(eventRecord, me) then
    return nil, "This guild event is locked."
  end

  local classTag = self:GetClassTagForPlayer(me)
  local spec = self:GetSpecSnapshotForPlayer(me, classTag)
  local existing = self:FindGuildEventRSVP(eventId, me)
  local updatedAt = Now()
  local signedAt = existing and (tonumber(existing.signedAt) or updatedAt) or updatedAt
  local priorUpdatedAt = existing and (tonumber(existing.updatedAt or existing.signedAt or 0) or 0) or 0
  if updatedAt <= priorUpdatedAt then
    updatedAt = priorUpdatedAt + 1
  end

  local record = {
    eventId = tostring(eventId),
    player = me,
    classTag = classTag,
    specName = spec and spec.name or classTag,
    signupStatus = NormalizeRaidSignupStatus(signupStatus),
    note = note or "",
    signedAt = signedAt,
    updatedAt = updatedAt,
  }

  local stored = self:StoreGuildEventRSVPRecord(record)
  if not stored then
    return nil, "Unable to save guild event response."
  end
  self:BroadcastGuildEventRSVP(stored)
  return stored
end

-- Helper: compare two "major.minor" version strings numerically
local function VersionLessThan(a, b)
  local amaj, amin = string.match(a or "0.0", "(%d+)%.(%d+)")
  local bmaj, bmin = string.match(b or "0.0", "(%d+)%.(%d+)")
  amaj, amin = tonumber(amaj) or 0, tonumber(amin) or 0
  bmaj, bmin = tonumber(bmaj) or 0, tonumber(bmin) or 0
  if amaj ~= bmaj then return amaj < bmaj end
  return amin < bmin
end

function LeafVE:GetLatestKnownAddonVersion()
  EnsureDB()
  local latest = tostring(LATEST_VERSION or LeafVE.version or "0.0")
  local stored = tostring(LeafVE_DB.latestKnownAddonVersion or "")
  if stored ~= "" and VersionLessThan(latest, stored) then
    latest = stored
  end
  return latest
end

function LeafVE:RecordKnownAddonVersion(ver, sourceName)
  EnsureDB()
  local versionText = Trim(ver or "")
  if versionText == "" then
    return false
  end

  local latest = self:GetLatestKnownAddonVersion()
  if VersionLessThan(latest, versionText) then
    LeafVE_DB.latestKnownAddonVersion = versionText
    LeafVE_DB.latestKnownAddonVersionSource = ShortName(sourceName) or Trim(sourceName or "")
    return true
  end
  return false
end

function LeafVE:MaybeShowOutdatedVersionPopup(force)
  EnsureDB()
  local latestKnownVersion = self:GetLatestKnownAddonVersion()
  if not VersionLessThan(LeafVE.version, latestKnownVersion) then
    return false
  end

  local now = Now()
  local lastShownAt = tonumber(LeafVE_DB.lastOutdatedVersionPopupAt) or 0
  if not force and lastShownAt > 0 and (now - lastShownAt) < OUTDATED_VERSION_POPUP_COOLDOWN then
    return false
  end

  LeafVE_DB.lastOutdatedVersionPopupAt = now
  local sourceText = Trim(LeafVE_DB.latestKnownAddonVersionSource or "")
  local lines = {
    "|cFFFF4444Leaf Village Legends Update Required|r",
    "",
    "|cFFFFD700Your addon is out of date and may miss newer features or sync changes.|r",
    "",
    "|cFF888888Current version:|r " .. tostring(LeafVE.version),
    "|cFF888888Latest known version:|r " .. tostring(latestKnownVersion),
  }
  if sourceText ~= "" then
    table.insert(lines, "|cFF888888Seen from guildmate:|r " .. tostring(sourceText))
  end
  table.insert(lines, "")
  table.insert(lines, "|cFF2DD35CPlease update to the latest version.|r")
  self:ShowInfoPopup(table.concat(lines, "\n"))
  return true
end

-- Returns true when the sender is known to be compatible.
-- Unknown versions are accepted so live updates are not dropped while the
-- VERSIONREQ/VERSIONRSP handshake is still in flight.
local function IsSenderCompatible(sender)
  if not LeafVE.versionResponses then return true end
  local senderVer = LeafVE.versionResponses[sender]
  if not senderVer then return true end
  if VersionLessThan(senderVer, LeafVE.minCompatVersion) then return false end
  return true
end

function LeafVE:OnAddonMessage(prefix, message, channel, sender)
  if prefix ~= "LeafVE" then return end
  if channel ~= "GUILD" and channel ~= "PARTY" and channel ~= "RAID" then return end
  
  sender = ShortName(sender)
  if not sender then return end
  
  -- Handle version check request
  if message == "VERSIONREQ" then
    local me = ShortName(UnitName("player"))
    if me and sender ~= me then
      SendAddonMessage("LeafVE", "VERSIONRSP:"..LeafVE.version, "GUILD")
    end
    return
  end

  -- Handle version check response
  if string.sub(message, 1, 11) == "VERSIONRSP:" then
    local ver = string.sub(message, 12)
    if not LeafVE.versionResponses then LeafVE.versionResponses = {} end
    LeafVE.versionResponses[sender] = ver
    LeafVE:RecordKnownAddonVersion(ver, sender)
    -- Auto-nag if someone has a higher version than us
    local myVer = LeafVE.version
    if not LeafVE.shownVersionNag and VersionLessThan(myVer, ver) then
      LeafVE.shownVersionNag = true
      Print("|cFFFFAA00⚠ Your Leaf Village Legends addon is outdated! You have v"..myVer..", latest is v"..ver..". Please update!|r")
    end
    -- Warn once when a guildmate's version is below the minimum compatible version
    if VersionLessThan(ver, LeafVE.minCompatVersion) then
      if not LeafVE.warnedOldVersion then LeafVE.warnedOldVersion = {} end
      if not LeafVE.warnedOldVersion[sender] then
        LeafVE.warnedOldVersion[sender] = true
        Print("|cFFFF4444⚠ "..sender.." is running an outdated version (v"..ver..") and their synced data will not be accepted. Ask them to update to v"..LeafVE.minCompatVersion.."+.|r")
      end
    end
    return
  end

  -- Handle on-demand resync request
  if message == "LBOARDREQ" or message == "LBOARDREQ_FORCE" then
    local forceRespond = (message == "LBOARDREQ_FORCE")
    local me = ShortName(UnitName("player"))
    if me and sender ~= me then
      local now = Now()
      if forceRespond or (now - self.lastResyncRespondAt) >= LBOARD_RESPOND_COOLDOWN then
        self.lastResyncRespondAt = now
        -- Respond with owner-authenticated self snapshot (My Stats exact values).
        LeafVE:BroadcastLeaderboardData(false)
      end
      if forceRespond or (now - self.lastAchSyncRespondAt) >= LBOARD_RESPOND_COOLDOWN then
        self.lastAchSyncRespondAt = now
        LeafVE:BroadcastMyAchievements()
      end
    end
    return
  end

  -- Handle explicit request for each online player to rebroadcast only their
  -- own current point totals. This keeps Refresh lightweight and owner-authoritative.
  if message == "MYSTATSREQ" or message == "MYSTATSREQ_FORCE" then
    local forceRespond = (message == "MYSTATSREQ_FORCE")
    local me = ShortName(UnitName("player"))
    if me and sender ~= me then
      local now = Now()
      if forceRespond or (now - (self.lastMyStatsRespondAt or 0)) >= MYSTATS_RESPOND_COOLDOWN then
        self.lastMyStatsRespondAt = now
        -- Self-only payload: L/W snapshots sourced directly from this client.
        LeafVE:BroadcastLeaderboardData(false)
      end
    end
    return
  end

  -- Handle full data wipe broadcast (all points, badges, history, leaderboards)
  if string.sub(message, 1, 10) == "FULL_WIPE:" then
    local wipeVersion = tonumber(string.sub(message, 11)) or 0
    if wipeVersion > 0 then
      -- Accept any guild relay carrying a newer wipe version so wipe propagation
      -- is reliable even when the original admin packet is missed.
      EnsureDB()
      if ShouldApplyIncomingWipeVersion(wipeVersion) then
        local applied = LVE_ApplyFullWipeVersion(
          wipeVersion,
          "|cff00ff00[LVL]|r Your Leaf Point data has been reset by a guild admin."
        )
        if applied then
          self:BroadcastFullWipeVersion(wipeVersion)
        end
      end
    end
    return
  end

  -- Handle a player resetting their own data (spoof-protected: sender must match the declared name).
  if string.sub(message, 1, 22) == "LVE_PLAYER_DATA_RESET:" then
    local declaredName = ShortName(string.sub(message, 23))
    local shortSender = ShortName(sender)
    -- Only accept the message when the sender matches the declared name.
    if declaredName and Lower(declaredName) == Lower(shortSender or sender) then
      EnsureDB()
      LeafVE_DB.alltime[declaredName]           = nil
      LeafVE_DB.season[declaredName]            = nil
      LeafVE_DB.loginStreaks[declaredName]       = nil
      LeafVE_DB.loginTracking[declaredName]     = nil
      LeafVE_DB.groupSessions[declaredName]     = nil
      LeafVE_DB.groupPointsToday[declaredName]  = nil
      LeafVE_DB.guildieGroupHours[declaredName] = nil
      if LeafVE_DB.guildJoinDate then LeafVE_DB.guildJoinDate[declaredName] = nil end
      LeafVE_DB.attendance[declaredName]        = nil
      LeafVE_DB.pointHistory[declaredName]      = nil
      LeafVE_DB.instanceTracking[declaredName]  = nil
      LeafVE_DB.questTracking[declaredName]     = nil
      LeafVE_DB.questCompletions[declaredName]  = nil
      LeafVE_DB.badges[declaredName]            = nil
      LeafVE_DB.badgesAnnounced[declaredName]   = nil
      LeafVE_DB.lboard.alltime[declaredName]    = nil
      LeafVE_DB.lboard.updatedAt[declaredName]  = nil
      for _, wkData in pairs(LeafVE_DB.lboard.weekly) do
        if type(wkData) == "table" then wkData[declaredName] = nil end
      end
      if LeafVE_DB.lboard.season then
        LeafVE_DB.lboard.season[declaredName] = nil
      end
      for _, dayData in pairs(LeafVE_DB.global) do
        if type(dayData) == "table" then dayData[declaredName] = nil end
      end
      LeafVE_DB.shoutouts[declaredName] = nil
      for _, targets in pairs(LeafVE_DB.shoutouts) do
        if type(targets) == "table" then targets[declaredName] = nil end
      end
      if LeafVE_GlobalDB.achievementCache then
        LeafVE_GlobalDB.achievementCache[declaredName] = nil
      end
      if LeafVE_GlobalDB.lboardCache then
        if LeafVE_GlobalDB.lboardCache.alltime then
          LeafVE_GlobalDB.lboardCache.alltime[declaredName] = nil
        end
        if LeafVE_GlobalDB.lboardCache.weekly then
          for _, wkData in pairs(LeafVE_GlobalDB.lboardCache.weekly) do
            if type(wkData) == "table" then wkData[declaredName] = nil end
          end
        end
      end
      if LeafVE_GlobalDB.badgeProgressCache then
        LeafVE_GlobalDB.badgeProgressCache[declaredName] = nil
      end
      if LeafVE_GlobalDB.gearCache then
        LeafVE_GlobalDB.gearCache[Lower(declaredName)] = nil
      end
      if LeafVE_GlobalDB.specCache then
        LeafVE_GlobalDB.specCache[Lower(declaredName)] = nil
      end
      if LeafVE_GlobalDB.talentCache then
        LeafVE_GlobalDB.talentCache[Lower(declaredName)] = nil
      end
      if LeafVE.talentSyncBuffer then
        LeafVE.talentSyncBuffer[Lower(declaredName)] = nil
      end
      if LeafVE_GlobalDB.playerNotes then
        LeafVE_GlobalDB.playerNotes[declaredName] = nil
      end
      if LeafVE_GlobalDB.professionDesignations then
        LeafVE_GlobalDB.professionDesignations[Lower(declaredName)] = nil
      end
      if LeafVE_GlobalDB.workOrderCrafterSignups then
        LeafVE_GlobalDB.workOrderCrafterSignups[Lower(declaredName)] = nil
      end
      if LeafVE_GlobalDB.workOrderCrafterSignupMeta then
        LeafVE_GlobalDB.workOrderCrafterSignupMeta[Lower(declaredName)] = nil
      end
      if LeafVE.UI and LeafVE.UI.Refresh then
        LeafVE.UI:Refresh()
      end
    end
    return
  end

  -- Handle explicit remote-gear requests; only the requested player responds.
  if string.sub(message, 1, 8) == "GEARREQ:" then
    local requestedName = ShortName(string.sub(message, 9))
    local me = ShortName(UnitName("player"))
    if requestedName and me and Lower(requestedName) == Lower(me) then
      self:BroadcastMyGear(true)
    end
    return
  end

  -- Handle explicit remote-talent requests; only the requested player responds.
  if string.sub(message, 1, 7) == "TALREQ:" then
    local requestedName = ShortName(string.sub(message, 8))
    local me = ShortName(UnitName("player"))
    if requestedName and me and Lower(requestedName) == Lower(me) then
      self:BroadcastMyTalents(true)
    end
    return
  end

  if string.sub(message, 1, 8) == "PROFREQ:" then
    local requestedName = ShortName(string.sub(message, 9))
    local me = ShortName(UnitName("player"))
    if requestedName and me and Lower(requestedName) == Lower(me) then
      self:BroadcastMyProfessionDesignation(true)
    end
    return
  end

  if string.sub(message, 1, 8) == "PROFDES:" then
    local payload = string.sub(message, 9)
    local fields = SplitByLiteralSep(payload, SEP)
    local secondary = DecodeTalentField(fields[4] or "")
    local designation = NormalizeProfessionDesignationRecord(sender, {
      player = sender,
      updatedAt = tonumber(fields[1]) or Now(),
      main = {
        DecodeTalentField(fields[2] or ""),
        DecodeTalentField(fields[3] or ""),
      },
      secondary = secondary ~= "" and SplitByLiteralSep(secondary, ",") or {},
    })
    if designation then
      EnsureDB()
      LeafVE_GlobalDB.professionDesignations[Lower(designation.player)] = designation
      if LeafVE.UI and LeafVE.UI.cardCurrentPlayer and Lower(LeafVE.UI.cardCurrentPlayer) == Lower(designation.player) then
        if LeafVE.UI.professionPopup and LeafVE.UI.professionPopup:IsVisible() then
          LeafVE.UI:RefreshProfessionPopup(LeafVE.UI.cardCurrentPlayer)
        end
      end
      if LeafVE.UI and LeafVE.UI.workOrderPopup and LeafVE.UI.workOrderPopup:IsVisible() and LeafVE.UI.cardCurrentPlayer then
        LeafVE.UI:RefreshWorkOrderPopup(LeafVE.UI.cardCurrentPlayer)
      end
    end
    return
  end

  if message == "WORKCRAFTERREQ" or message == "WORKCRAFTERREQ_FORCE" then
    local forceRespond = (message == "WORKCRAFTERREQ_FORCE")
    local me = ShortName(UnitName("player"))
    if me and sender ~= me then
      self:BroadcastMyWorkOrderCrafterSignup(forceRespond)
    end
    return
  end

  if string.sub(message, 1, 17) == "WORKCRAFTERRESET:" then
    self:HandleIncomingWorkOrderCrafterSignupReset(string.sub(message, 18), sender)
    return
  end

  if string.sub(message, 1, 12) == "WORKCRAFTER:" then
    self:HandleIncomingWorkOrderCrafterSignup(string.sub(message, 13), sender)
    return
  end

  if message == "RAIDREQ" or message == "RAIDREQ_FORCE" then
    local forceRespond = (message == "RAIDREQ_FORCE")
    local me = ShortName(UnitName("player"))
    if me and sender ~= me then
      self:BroadcastRaidEventSnapshot(forceRespond)
      self:BroadcastRaidSignupSnapshot(forceRespond)
    end
    return
  end

  if message == "GUILDEVENTREQ" or message == "GUILDEVENTREQ_FORCE" then
    local forceRespond = (message == "GUILDEVENTREQ_FORCE")
    local me = ShortName(UnitName("player"))
    if me and sender ~= me then
      self:BroadcastGuildEventSnapshot(forceRespond)
      self:BroadcastGuildEventRSVPSnapshot(forceRespond)
    end
    return
  end

  if string.sub(message, 1, 11) == "GUILDEVENT:" then
    self:HandleIncomingGuildEventMessage(string.sub(message, 12))
    return
  end

  if string.sub(message, 1, 15) == "GUILDEVENTSYNC:" then
    self:HandleIncomingGuildEventMessage(string.sub(message, 16))
    return
  end

  if string.sub(message, 1, 15) == "GUILDEVENTRSVP:" then
    self:HandleIncomingGuildEventRSVPMessage(string.sub(message, 16))
    return
  end

  if string.sub(message, 1, 19) == "GUILDEVENTRSVPSYNC:" then
    self:HandleIncomingGuildEventRSVPMessage(string.sub(message, 20))
    return
  end

  if string.sub(message, 1, 10) == "RAIDEVENT:" then
    self:HandleIncomingRaidEventMessage(string.sub(message, 11))
    return
  end

  if string.sub(message, 1, 14) == "RAIDEVENTSYNC:" then
    self:HandleIncomingRaidEventMessage(string.sub(message, 15))
    return
  end

  if string.sub(message, 1, 11) == "RAIDSIGNUP:" then
    self:HandleIncomingRaidSignupMessage(string.sub(message, 12))
    return
  end

  if string.sub(message, 1, 15) == "RAIDSIGNUPSYNC:" then
    self:HandleIncomingRaidSignupMessage(string.sub(message, 16))
    return
  end

  if message == "WORKORDERREQ" or message == "WORKORDERREQ_FORCE" then
    local forceRespond = (message == "WORKORDERREQ_FORCE")
    local me = ShortName(UnitName("player"))
    if me and sender ~= me then
      self:BroadcastWorkOrderSnapshot(forceRespond)
    end
    return
  end

  if string.sub(message, 1, 10) == "WORKORDER:" then
    if not IsSenderCompatible(sender) then return end
    self:HandleIncomingWorkOrderMessage(string.sub(message, 11), sender, nil)
    return
  end

  if string.sub(message, 1, 14) == "WORKORDERSYNC:" then
    if not IsSenderCompatible(sender) then return end
    self:HandleIncomingWorkOrderMessage(string.sub(message, 15), sender, true)
    return
  end

  if message == "GBANKOWNERREQ" or message == "GBANKOWNERREQ_FORCE" then
    local forceRespond = (message == "GBANKOWNERREQ_FORCE")
    local me = ShortName(UnitName("player"))
    if me and sender ~= me then
      self:BroadcastGuildBankOwner(forceRespond)
    end
    return
  end

  if string.sub(message, 1, 11) == "GBANKOWNER:" then
    local payload = string.sub(message, 12)
    local fields = SplitByLiteralSep(payload, SEP)
    local ownerName = DecodeTalentField(fields[1] or "")
    local updatedAt = tonumber(fields[2]) or 0
    local updatedBy = DecodeTalentField(fields[3] or "")
    local priorOwner = self:GetGuildBankOwnerName()
    local config = self:SetGuildBankOwner(ownerName, true, updatedAt, updatedBy ~= "" and updatedBy or sender)
    if config and Lower(priorOwner or "") ~= Lower(config.owner or "") and LeafVE.UI and LeafVE.UI.RefreshVisibleGuildBankUI then
      LeafVE.UI:RefreshVisibleGuildBankUI(true)
    end
    return
  end

  if message == "GBANKREQ" or message == "GBANKREQ_FORCE" then
    local forceRespond = (message == "GBANKREQ_FORCE")
    local me = ShortName(UnitName("player"))
    if me and sender ~= me then
      if self:IsGuildBankOwner(me) then
        self:BroadcastGuildBankSnapshot(forceRespond)
      else
        self:BroadcastCachedGuildBankSnapshot(forceRespond)
      end
    end
    return
  end

  if string.sub(message, 1, 10) == "GBANKMETA:" then
    self:HandleIncomingGuildBankMetaPayload(string.sub(message, 11), sender, nil)
    return
  end

  if string.sub(message, 1, 6) == "GBANK:" then
    self:HandleIncomingGuildBankCountPayload(string.sub(message, 7), sender, nil)
    return
  end

  if string.sub(message, 1, 10) == "GBANKICON:" then
    self:HandleIncomingGuildBankIconPayload(string.sub(message, 11), sender, nil)
    return
  end

  if string.sub(message, 1, 15) == "GBANKRELAYMETA:" then
    self:HandleIncomingGuildBankMetaPayload(string.sub(message, 16), sender, true)
    return
  end

  if string.sub(message, 1, 11) == "GBANKRELAY:" then
    self:HandleIncomingGuildBankCountPayload(string.sub(message, 12), sender, true)
    return
  end

  if string.sub(message, 1, 15) == "GBANKRELAYICON:" then
    self:HandleIncomingGuildBankIconPayload(string.sub(message, 16), sender, true)
    return
  end

  if message == "GBANKITEMREQREQ" or message == "GBANKITEMREQREQ_FORCE" then
    local forceRespond = (message == "GBANKITEMREQREQ_FORCE")
    local me = ShortName(UnitName("player"))
    if me and sender ~= me then
      self:BroadcastGuildBankRequestSnapshot(forceRespond)
    end
    return
  end

  if string.sub(message, 1, 13) == "GBANKITEMREQ:" then
    self:HandleIncomingGuildBankRequestMessage(string.sub(message, 14))
    return
  end

  if string.sub(message, 1, 17) == "GBANKITEMREQSYNC:" then
    self:HandleIncomingGuildBankRequestMessage(string.sub(message, 18))
    return
  end

  if message == "GBANKCLASSREQ" or message == "GBANKCLASSREQ_FORCE" then
    local forceRespond = (message == "GBANKCLASSREQ_FORCE")
    local me = ShortName(UnitName("player"))
    if me and sender ~= me then
      self:BroadcastGuildBankCategoryOverrideSnapshot(forceRespond)
    end
    return
  end

  if string.sub(message, 1, 11) == "GBANKCLASS:" or string.sub(message, 1, 15) == "GBANKCLASSSYNC:" then
    local payload = string.sub(message, string.sub(message, 1, 15) == "GBANKCLASSSYNC:" and 16 or 12)
    local fields = SplitByLiteralSep(payload, SEP)
    local itemId = tonumber(fields[1])
    local tabKey = DecodeTalentField(fields[2] or "")
    local updatedAt = tonumber(fields[3]) or Now()
    local updatedBy = DecodeTalentField(fields[4] or "")
    self:SetGuildBankItemCategoryOverride(itemId, tabKey ~= "" and tabKey or nil, true, updatedAt, updatedBy ~= "" and updatedBy or sender)
    return
  end

  if message == "GBANKHVREQ" or message == "GBANKHVREQ_FORCE" then
    local forceRespond = (message == "GBANKHVREQ_FORCE")
    local me = ShortName(UnitName("player"))
    if me and sender ~= me then
      self:BroadcastGuildBankHighValueSnapshot(forceRespond)
    end
    return
  end

  if string.sub(message, 1, 8) == "GBANKHV:" or string.sub(message, 1, 12) == "GBANKHVSYNC:" then
    local payload = string.sub(message, string.sub(message, 1, 12) == "GBANKHVSYNC:" and 13 or 9)
    local fields = SplitByLiteralSep(payload, SEP)
    local itemId = tonumber(fields[1])
    local isHighValue = tonumber(fields[2]) == 1
    local updatedAt = tonumber(fields[3]) or Now()
    local updatedBy = DecodeTalentField(fields[4] or "")
    self:SetGuildBankItemHighValue(itemId, isHighValue, true, updatedAt, updatedBy ~= "" and updatedBy or sender)
    return
  end

  -- Handle chunked talent tree sync payload.
  if string.sub(message, 1, 9) == "GTALSYNC:" then
    local rest = string.sub(message, 10)
    local p1 = string.find(rest, ":")
    if not p1 then return end
    local declaredName = string.sub(rest, 1, p1 - 1)
    if Lower(sender) ~= Lower(ShortName(declaredName) or declaredName) then return end
    local rest2 = string.sub(rest, p1 + 1)
    local p2 = string.find(rest2, ":")
    if not p2 then return end
    local updatedAt = tonumber(string.sub(rest2, 1, p2 - 1)) or Now()
    local rest3 = string.sub(rest2, p2 + 1)
    local p3 = string.find(rest3, ":")
    if not p3 then return end
    local chunkInfo = string.sub(rest3, 1, p3 - 1)
    local payload = string.sub(rest3, p3 + 1)
    local slashPos = string.find(chunkInfo, "/")
    if not slashPos then return end
    local chunkNum = tonumber(string.sub(chunkInfo, 1, slashPos - 1))
    local totalChunks = tonumber(string.sub(chunkInfo, slashPos + 1))
    if not chunkNum or not totalChunks or chunkNum < 1 or totalChunks < 1 then return end

    self.talentSyncBuffer = self.talentSyncBuffer or {}
    local nameLower = Lower(sender)
    local buffered = self.talentSyncBuffer[nameLower]
    if not buffered or buffered.updatedAt ~= updatedAt or buffered.total ~= totalChunks then
      buffered = {updatedAt = updatedAt, total = totalChunks, chunks = {}}
      self.talentSyncBuffer[nameLower] = buffered
    end
    buffered.chunks[chunkNum] = payload

    local received = 0
    for i = 1, totalChunks do
      if buffered.chunks[i] then
        received = received + 1
      end
    end
    if received == totalChunks then
      local parts = {}
      for i = 1, totalChunks do
        table.insert(parts, buffered.chunks[i] or "")
      end
      self.talentSyncBuffer[nameLower] = nil
      EnsureDB()
      local existingTalent = LeafVE_GlobalDB.talentCache and LeafVE_GlobalDB.talentCache[nameLower]
      if existingTalent and updatedAt < (existingTalent.updatedAt or 0) then
        return
      end
      self:ApplyTalentPayload(sender, updatedAt, table.concat(parts, ""))

      if LeafVE.UI and LeafVE.UI.cardCurrentPlayer and Lower(LeafVE.UI.cardCurrentPlayer) == nameLower then
        local classTag = LeafVE:GetClassTagForPlayer(LeafVE.UI.cardCurrentPlayer)
        local spec = LeafVE:GetTalentSpecForPlayer(LeafVE.UI.cardCurrentPlayer, classTag)
        if LeafVE.UI.cardTalentBtn then
          local specName = spec and spec.name or classTag
          LeafVE.UI.cardTalentBtn:SetText("Talent Spec: " .. tostring(specName))
        end
        if LeafVE.UI.talentPopup and LeafVE.UI.talentPopup:IsVisible() then
          LeafVE.UI:RefreshTalentPopup(LeafVE.UI.cardCurrentPlayer, true)
        end
      end
    end
    return
  end

  -- Parse badge sync message
  if string.sub(message, 1, 7) == "BADGES:" then
    if not IsSenderCompatible(sender) then return end
    local badgeData = string.sub(message, 8)
    
    EnsureDB()
    if not LeafVE_DB.badges[sender] then
      LeafVE_DB.badges[sender] = {}
    end
    
    -- Parse badge data (Vanilla WoW compatible)
    local badges = {}
    local incomingBadgeBucket = 0
    local startPos = 1
    
    while startPos <= string.len(badgeData) do
      local commaPos = string.find(badgeData, ",", startPos)
      local badgeEntry
      
      if commaPos then
        badgeEntry = string.sub(badgeData, startPos, commaPos - 1)
        startPos = commaPos + 1
      else
        badgeEntry = string.sub(badgeData, startPos)
        startPos = string.len(badgeData) + 1
      end
      
      -- Parse individual badge: "badgeID:timestamp"
      local colonPos = string.find(badgeEntry, ":")
      if colonPos then
        local badgeId = string.sub(badgeEntry, 1, colonPos - 1)
        local timestamp = string.sub(badgeEntry, colonPos + 1)
        if badgeId == "__fw" then
          incomingBadgeBucket = tonumber(timestamp) or 0
        else
          badges[badgeId] = tonumber(timestamp)
        end
      end
    end

    local localBucket = CurrentWipeVersion()
    if incomingBadgeBucket > 0 then
      if incomingBadgeBucket ~= localBucket then
        return
      end
    elseif localBucket > 0 then
      -- Ignore legacy badge payloads without bucket marker after bucketized wipes.
      return
    end
    
    -- Owner snapshot for this season/bucket is authoritative.
    if not LeafVE_DB.badges[sender] then
      LeafVE_DB.badges[sender] = {}
    end
    LeafVE_DB.badges[sender] = {}
    for badgeId, timestamp in pairs(badges) do
      if timestamp and timestamp > 0 then
        LeafVE_DB.badges[sender][badgeId] = timestamp
      end
    end
    
    local count = 0
    for _ in pairs(badges) do count = count + 1 end
    
    -- Refresh UI if viewing this player
    if LeafVE.UI and LeafVE.UI.cardCurrentPlayer == sender then
      LeafVE.UI:UpdateCardRecentBadges(sender)
    end
    
    return

  -- Parse badge progress broadcast
  elseif string.sub(message, 1, 10) == "BADGEPROG:" then
    if not IsSenderCompatible(sender) then return end
    local me = ShortName(UnitName("player"))
    if me and SamePlayerName(sender, me) then return end
    local rest = string.sub(message, 11)
    local p1 = string.find(rest, SEP)
    if not p1 then return end
    local progName = string.sub(rest, 1, p1 - 1)
    local shortProgName = ShortName(progName)
    local normalizedProgName = shortProgName or progName
    if Lower(sender) ~= Lower(normalizedProgName) then return end
    local rest2 = string.sub(rest, p1 + 1)
    local p2 = string.find(rest2, SEP)
    if not p2 then return end
    local groupSessions = tonumber(string.sub(rest2, 1, p2 - 1)) or 0
    local rest3 = string.sub(rest2, p2 + 1)
    local p3 = string.find(rest3, SEP)
    if not p3 then return end
    local attendance = tonumber(string.sub(rest3, 1, p3 - 1)) or 0
    local rest4 = string.sub(rest3, p3 + 1)
    local p4 = string.find(rest4, SEP)
    if not p4 then return end
    local streak = tonumber(string.sub(rest4, 1, p4 - 1)) or 0
    local rest5 = string.sub(rest4, p4 + 1)
    -- Field 6 (guildieGroupHours) was added later; parse if present, else default to 0.
    local p5 = string.find(rest5, SEP)
    local joinDate, receivedGroupHours
    if p5 then
      joinDate = tonumber(string.sub(rest5, 1, p5 - 1)) or 0
      receivedGroupHours = tonumber(string.sub(rest5, p5 + 1)) or 0
    else
      joinDate = tonumber(rest5) or 0
      receivedGroupHours = 0
    end
    EnsureDB()
    if not LeafVE_DB.groupSessions[normalizedProgName] or LeafVE_DB.groupSessions[normalizedProgName] < groupSessions then
      LeafVE_DB.groupSessions[normalizedProgName] = groupSessions
    end
    if not LeafVE_DB.guildieGroupHours then LeafVE_DB.guildieGroupHours = {} end
    if not LeafVE_DB.guildieGroupHours[normalizedProgName] or LeafVE_DB.guildieGroupHours[normalizedProgName] < receivedGroupHours then
      LeafVE_DB.guildieGroupHours[normalizedProgName] = receivedGroupHours
    end
    if not LeafVE_DB.attendance[normalizedProgName] then LeafVE_DB.attendance[normalizedProgName] = {} end
    -- Pad attendance array to at least the reported count so badge milestone
    -- checks (which use table.getn) reflect the sender's real attendance tally.
    while table.getn(LeafVE_DB.attendance[normalizedProgName]) < attendance do
      table.insert(LeafVE_DB.attendance[normalizedProgName], {})
    end
    if not LeafVE_DB.loginStreaks[normalizedProgName] then LeafVE_DB.loginStreaks[normalizedProgName] = {current = 0} end
    if (LeafVE_DB.loginStreaks[normalizedProgName].current or 0) < streak then
      LeafVE_DB.loginStreaks[normalizedProgName].current = streak
    end
    if joinDate > 0 then
      if not LeafVE_DB.guildJoinDate then LeafVE_DB.guildJoinDate = {} end
      local existingJoinDate = LeafVE_DB.guildJoinDate[normalizedProgName]
      if not existingJoinDate or existingJoinDate <= 0 or joinDate < existingJoinDate then
        LeafVE_DB.guildJoinDate[normalizedProgName] = joinDate
      end
    end
    -- Progress sync is informational; badge awards only come from local events.
    self:CacheBadgeProgress(normalizedProgName)
    return
    
  -- Parse shoutout sync message
  elseif string.sub(message, 1, 9) == "SHOUTOUT:" then
    if not IsSenderCompatible(sender) then return end
    local shoutData = string.sub(message, 10)
    local colonPos = string.find(shoutData, ":")
    if colonPos then
      local msgGiver = string.sub(shoutData, 1, colonPos - 1)
      local targetName = string.sub(shoutData, colonPos + 1)
      -- Validate both names are non-empty
      if msgGiver ~= "" and targetName ~= "" then
        -- Verify sender matches the declared giver (security check)
        if Lower(sender) == Lower(msgGiver) then
          local me = ShortName(UnitName("player"))
          -- Skip if we are the giver (already recorded via AddPoints in GiveShoutout)
          if not (me and Lower(me) == Lower(msgGiver)) then
            EnsureDB()
            -- Deduplicate: only record if not already tracked for today
            local today = DayKey()
            local bucket = CurrentWipeVersion()
            local alreadyRecorded = false
            if LeafVE_DB.shoutouts[msgGiver] and LeafVE_DB.shoutouts[msgGiver][targetName] then
              local existingTs = tonumber(LeafVE_DB.shoutouts[msgGiver][targetName]) or 0
              local existingDay = DayKeyFromTS(existingTs)
              if (bucket <= 0 or existingTs >= bucket) and existingDay == today then
                alreadyRecorded = true
              end
            end
            if not alreadyRecorded then
              if not LeafVE_DB.shoutouts[msgGiver] then
                LeafVE_DB.shoutouts[msgGiver] = {}
              end
              LeafVE_DB.shoutouts[msgGiver][targetName] = Now()
              local shoutPtsIncoming = (LeafVE_DB.options and LeafVE_DB.options.shoutoutPoints) or 10
              self:AddPoints(targetName, "S", shoutPtsIncoming)
              LeafVE.UI:Refresh()
              self:BroadcastLeaderboardData()
            end
            -- If we are the shoutout recipient, award received badges on our machine
            if me and Lower(me) == Lower(targetName) then
              self:CheckAndAwardBadge(targetName, "first_shoutout_received")
              local rcvCount = 0
              local bucket = CurrentWipeVersion()
              for g, _ in pairs(LeafVE_DB.shoutouts) do
                for t, ts in pairs(LeafVE_DB.shoutouts[g]) do
                  local shoutTs = tonumber(ts) or 0
                  if Lower(t) == Lower(targetName) and (bucket <= 0 or shoutTs >= bucket) then rcvCount = rcvCount + 1 end
                end
              end
              if rcvCount >= 10 then self:CheckAndAwardBadge(targetName, "shoutout_received_10") end
              if rcvCount >= 50 then self:CheckAndAwardBadge(targetName, "shoutout_received_50") end
            end
          end
        end
      end
    end
    return

  -- Parse player note sync message
  elseif string.sub(message, 1, 5) == "NOTE:" then
    local noteText = string.sub(message, 6)
    
    -- Unescape special characters
    noteText = string.gsub(noteText, "||", "|")
    
    EnsureDB()
    if not LeafVE_GlobalDB.playerNotes then
      LeafVE_GlobalDB.playerNotes = {}
    end
    
    LeafVE_GlobalDB.playerNotes[sender] = noteText
    
    -- Refresh UI if viewing this player
    if LeafVE.UI and LeafVE.UI.cardCurrentPlayer == sender then
      if LeafVE.UI.cardNotesEdit then
        LeafVE.UI.cardNotesEdit:SetText(noteText)
      end
    end
    
    return
    
    -- **NEW: Parse leaderboard sync message**
  elseif string.sub(message, 1, 7) == "LBOARD:" then
    if not IsSenderCompatible(sender) then return end
    local me = ShortName(UnitName("player"))
    if me and SamePlayerName(sender, me) then
      return
    end
    local lboardData = string.sub(message, 8)

    -- Parse full-wipe version prefix carried on leaderboard payloads.
    local incomingWipeVersion = 0
    if string.sub(lboardData, 1, 3) == "FW:" then
      local commaPos = string.find(lboardData, ",")
      if not commaPos then return end
      incomingWipeVersion = tonumber(string.sub(lboardData, 4, commaPos - 1)) or 0
      lboardData = string.sub(lboardData, commaPos + 1)
    end

    -- Parse optional EPOCH:<timestamp>, prefix from older clients.
    if string.sub(lboardData, 1, 6) == "EPOCH:" then
      local commaPos = string.find(lboardData, ",")
      if not commaPos then return end  -- malformed epoch prefix; discard
      lboardData = string.sub(lboardData, commaPos + 1)
    end

    EnsureDB()
    local localWipeVersion = (LeafVE_GlobalDB and LeafVE_GlobalDB.fullWipeVersion) or 0
    local lastApplied = (LeafVE_DB and LeafVE_DB.lastWipeApplied) or 0
    local effectiveLocalVersion = math.max(localWipeVersion, lastApplied)
    if incomingWipeVersion > 0 then
      if ShouldApplyIncomingWipeVersion(incomingWipeVersion) then
        LVE_ApplyFullWipeVersion(incomingWipeVersion, "|cFFFFD700[LVL]|r Wipe sync applied from guild data.")
        localWipeVersion = (LeafVE_GlobalDB and LeafVE_GlobalDB.fullWipeVersion) or incomingWipeVersion
      else
        localWipeVersion = effectiveLocalVersion
      end
      -- Ignore snapshots that do not match the now-active wipe version.
      if incomingWipeVersion ~= localWipeVersion then
        return
      end
    elseif effectiveLocalVersion > 0 then
      -- We have wipe-versioned data locally; ignore legacy snapshots without FW.
      return
    end
    if lboardData == "" then
      return
    end

    -- Parse comma-separated player entries
    local startPos = 1
    while startPos <= string.len(lboardData) do
      local commaPos = string.find(lboardData, ",", startPos)
      local playerEntry
      
      if commaPos then
        playerEntry = string.sub(lboardData, startPos, commaPos - 1)
        startPos = commaPos + 1
      else
        playerEntry = string.sub(lboardData, startPos)
        startPos = string.len(lboardData) + 1
      end
      
      LeafVE:ReceiveLeaderboardData(sender, playerEntry)
    end  -- ← CLOSE THE WHILE LOOP
    
    -- Refresh leaderboards if open
    if LeafVE.UI and LeafVE.UI.panels then
      if LeafVE.UI.panels.leaderLife and LeafVE.UI.panels.leaderLife:IsVisible() then
        LeafVE.UI:RefreshLeaderboard("leaderLife")
      end
      if LeafVE.UI.panels.leaderWeek and LeafVE.UI.panels.leaderWeek:IsVisible() then
        LeafVE.UI:RefreshLeaderboard("leaderWeek")
      end
    end
    
    return

  -- Handle shoutout history sync request
  elseif message == "SHOUTSYNCREQ" or message == "SHOUTSYNCREQ_FORCE" then
    local forceRespond = (message == "SHOUTSYNCREQ_FORCE")
    local me = ShortName(UnitName("player"))
    if me and sender ~= me then
      local now = Now()
      if forceRespond or (now - self.lastShoutSyncRespondAt) >= SHOUT_SYNC_RESPOND_COOLDOWN then
        self.lastShoutSyncRespondAt = now
        LeafVE:BroadcastShoutoutHistory()
      end
    end
    return

  -- Handle chunked shoutout history sync payload
  elseif string.sub(message, 1, 10) == "SHOUTSYNC:" then
    if not IsSenderCompatible(sender) then return end
    local rest = string.sub(message, 11)
    local slashPos = string.find(rest, "/")
    if not slashPos then return end
    local chunkNum = tonumber(string.sub(rest, 1, slashPos - 1))
    local afterSlash = string.sub(rest, slashPos + 1)
    local colonPos2 = string.find(afterSlash, ":")
    if not colonPos2 then return end
    local totalChunks = tonumber(string.sub(afterSlash, 1, colonPos2 - 1))
    local payload = string.sub(afterSlash, colonPos2 + 1)
    if not chunkNum or not totalChunks or chunkNum < 1 or totalChunks < 1 then return end
    -- Buffer chunks per sender; reset if a new sync starts (different total)
    if not self.shoutSyncBuffer[sender] or self.shoutSyncBuffer[sender].total ~= totalChunks then
      self.shoutSyncBuffer[sender] = {total = totalChunks, chunks = {}}
    end
    self.shoutSyncBuffer[sender].chunks[chunkNum] = payload
    -- Check if all chunks have been received
    local received = 0
    for i = 1, totalChunks do
      if self.shoutSyncBuffer[sender].chunks[i] then received = received + 1 end
    end
    if received == totalChunks then
      local parts = {}
      for i = 1, totalChunks do
        table.insert(parts, self.shoutSyncBuffer[sender].chunks[i])
      end
      self.shoutSyncBuffer[sender] = nil
      self:MergeShoutoutHistory(table.concat(parts, ","))
    end
    return

  -- Handle admin config broadcast
  elseif string.sub(message, 1, 17) == "LVE_ADMIN_CONFIG:" then
    -- No longer used; configurable admin settings have been removed.
    return

  -- Handle achievement data sync from a guild member
  elseif string.sub(message, 1, 8) == "ACHSYNC:" then
    if not IsSenderCompatible(sender) then return end
    local achData = string.sub(message, 9)
    EnsureDB()
    if not LeafVE_GlobalDB.achievementCache then
      LeafVE_GlobalDB.achievementCache = {}
    end
    if not LeafVE_GlobalDB.achievementCache[sender] then
      LeafVE_GlobalDB.achievementCache[sender] = {}
    end
    -- Parse "achID:timestamp,achID:timestamp,..." entries
    local startPos = 1
    while startPos <= string.len(achData) do
      local commaPos = string.find(achData, ",", startPos)
      local entry
      if commaPos then
        entry = string.sub(achData, startPos, commaPos - 1)
        startPos = commaPos + 1
      else
        entry = string.sub(achData, startPos)
        startPos = string.len(achData) + 1
      end
      local colonPos = string.find(entry, ":")
      if colonPos then
        local achId = string.sub(entry, 1, colonPos - 1)
        local timestamp = tonumber(string.sub(entry, colonPos + 1))
        if achId ~= "" and timestamp then
          if not LeafVE_GlobalDB.achievementCache[sender][achId] then
            LeafVE_GlobalDB.achievementCache[sender][achId] = timestamp
          else
            LeafVE_GlobalDB.achievementCache[sender][achId] = math.min(
              LeafVE_GlobalDB.achievementCache[sender][achId], timestamp)
          end
        end
      end
    end
    -- After parsing all entries, compute and cache total points
    local totalPts = 0
    for achId, _ in pairs(LeafVE_GlobalDB.achievementCache[sender]) do
      if achId ~= "_totalPoints" then
        local meta = GetLegacyAchievementMeta(achId)
        local pts = (meta and meta.points) or DEFAULT_ACHIEVEMENT_POINTS
        totalPts = totalPts + pts
      end
    end
    LeafVE_GlobalDB.achievementCache[sender]._totalPoints = totalPts
    -- Refresh the achievement leaderboard panel if it is visible
    if LeafVE.UI and LeafVE.UI.panels then
      if LeafVE.UI.panels.achievements and LeafVE.UI.panels.achievements:IsVisible() then
        LeafVE.UI:RefreshAchievementsLeaderboard()
      end
    end
    return

  -- Handle gear cache broadcast from a guild member
  elseif string.sub(message, 1, 5) == "GEAR:" then
    local rest = string.sub(message, 6)
    local firstColon = string.find(rest, ":")
    if not firstColon then return end
    local declaredName = string.sub(rest, 1, firstColon - 1)
    if Lower(sender) ~= Lower(ShortName(declaredName) or declaredName) then return end
    rest = string.sub(rest, firstColon + 1)
    local secondColon = string.find(rest, ":")
    if not secondColon then return end
    local updatedAt = tonumber(string.sub(rest, 1, secondColon - 1)) or Now()
    local slotData = string.sub(rest, secondColon + 1)

    EnsureDB()
    if not LeafVE_GlobalDB.gearCache then LeafVE_GlobalDB.gearCache = {} end
    local nameLower = Lower(sender)
    if not LeafVE_GlobalDB.gearCache[nameLower] then LeafVE_GlobalDB.gearCache[nameLower] = {} end
    if not LeafVE_GlobalDB.gearCache[nameLower].broadcast then
      LeafVE_GlobalDB.gearCache[nameLower].broadcast = {updatedAt = 0, slots = {}, icons = {}, enchants = {}, stats = {}}
    end
    local broadcast = LeafVE_GlobalDB.gearCache[nameLower].broadcast
    if updatedAt > (broadcast.updatedAt or 0) then
      broadcast.slots = {}
      broadcast.icons = {}
      broadcast.enchants = {}
      broadcast.stats = {}
    end
    if updatedAt >= (broadcast.updatedAt or 0) then
      broadcast.updatedAt = updatedAt
      if not broadcast.slots then broadcast.slots = {} end
      local startPos = 1
      while startPos <= string.len(slotData) do
        local commaPos = string.find(slotData, ",", startPos)
        local entry
        if commaPos then
          entry = string.sub(slotData, startPos, commaPos - 1)
          startPos = commaPos + 1
        else
          entry = string.sub(slotData, startPos)
          startPos = string.len(slotData) + 1
        end
        local eqPos = string.find(entry, "=")
        if eqPos then
          local slotName = string.sub(entry, 1, eqPos - 1)
          local itemId = tonumber(string.sub(entry, eqPos + 1))
          if slotName ~= "" and itemId then
            broadcast.slots[slotName] = itemId
          end
        end
      end
    end
    if LeafVE.UI and LeafVE.UI.cardCurrentPlayer and Lower(LeafVE.UI.cardCurrentPlayer) == nameLower then
      if LeafVE.UI.gearPopup and LeafVE.UI.gearPopup:IsVisible() then
        LeafVE.UI:RefreshGearPopup(LeafVE.UI.cardCurrentPlayer)
      end
    end
    return

  -- Handle gear icon cache broadcast from a guild member
  elseif string.sub(message, 1, 7) == "GICONS:" then
    local rest = string.sub(message, 8)
    local firstColon = string.find(rest, ":")
    if not firstColon then return end
    local declaredName = string.sub(rest, 1, firstColon - 1)
    if Lower(sender) ~= Lower(ShortName(declaredName) or declaredName) then return end
    rest = string.sub(rest, firstColon + 1)
    local secondColon = string.find(rest, ":")
    if not secondColon then return end
    local updatedAt = tonumber(string.sub(rest, 1, secondColon - 1)) or Now()
    local iconData = string.sub(rest, secondColon + 1)

    EnsureDB()
    local nameLower = Lower(sender)
    if not LeafVE_GlobalDB.gearCache[nameLower] then LeafVE_GlobalDB.gearCache[nameLower] = {} end
    if not LeafVE_GlobalDB.gearCache[nameLower].broadcast then
      LeafVE_GlobalDB.gearCache[nameLower].broadcast = {updatedAt = 0, slots = {}, icons = {}, enchants = {}, stats = {}}
    end
    local broadcast = LeafVE_GlobalDB.gearCache[nameLower].broadcast
    if updatedAt > (broadcast.updatedAt or 0) then
      broadcast.icons = {}
    end
    if updatedAt >= (broadcast.updatedAt or 0) then
      broadcast.updatedAt = updatedAt
      if not broadcast.icons then broadcast.icons = {} end
      local startPos = 1
      while startPos <= string.len(iconData) do
        local commaPos = string.find(iconData, ",", startPos)
        local entry
        if commaPos then
          entry = string.sub(iconData, startPos, commaPos - 1)
          startPos = commaPos + 1
        else
          entry = string.sub(iconData, startPos)
          startPos = string.len(iconData) + 1
        end
        local eqPos = string.find(entry, "=")
        if eqPos then
          local slotName = string.sub(entry, 1, eqPos - 1)
          local iconPath = NormalizeIconPath(string.sub(entry, eqPos + 1))
          if slotName ~= "" and iconPath then
            broadcast.icons[slotName] = iconPath
          end
        end
      end
    end
    if LeafVE.UI and LeafVE.UI.cardCurrentPlayer and Lower(LeafVE.UI.cardCurrentPlayer) == nameLower then
      if LeafVE.UI.gearPopup and LeafVE.UI.gearPopup:IsVisible() then
        LeafVE.UI:RefreshGearPopup(LeafVE.UI.cardCurrentPlayer)
      end
    end
    return

  -- Handle gear enchant cache broadcast from a guild member
  elseif string.sub(message, 1, 6) == "GENCH:" then
    local rest = string.sub(message, 7)
    local firstColon = string.find(rest, ":")
    if not firstColon then return end
    local declaredName = string.sub(rest, 1, firstColon - 1)
    if Lower(sender) ~= Lower(ShortName(declaredName) or declaredName) then return end
    rest = string.sub(rest, firstColon + 1)
    local secondColon = string.find(rest, ":")
    if not secondColon then return end
    local updatedAt = tonumber(string.sub(rest, 1, secondColon - 1)) or Now()
    local enchData = string.sub(rest, secondColon + 1)

    EnsureDB()
    local nameLower = Lower(sender)
    if not LeafVE_GlobalDB.gearCache[nameLower] then LeafVE_GlobalDB.gearCache[nameLower] = {} end
    if not LeafVE_GlobalDB.gearCache[nameLower].broadcast then
      LeafVE_GlobalDB.gearCache[nameLower].broadcast = {updatedAt = 0, slots = {}, icons = {}, enchants = {}, stats = {}}
    end
    local broadcast = LeafVE_GlobalDB.gearCache[nameLower].broadcast
    if updatedAt > (broadcast.updatedAt or 0) then
      broadcast.enchants = {}
    end
    if updatedAt >= (broadcast.updatedAt or 0) then
      broadcast.updatedAt = updatedAt
      if not broadcast.enchants then broadcast.enchants = {} end
      local startPos = 1
      while startPos <= string.len(enchData) do
        local commaPos = string.find(enchData, ",", startPos)
        local entry
        if commaPos then
          entry = string.sub(enchData, startPos, commaPos - 1)
          startPos = commaPos + 1
        else
          entry = string.sub(enchData, startPos)
          startPos = string.len(enchData) + 1
        end
        local eqPos = string.find(entry, "=")
        if eqPos then
          local slotName = string.sub(entry, 1, eqPos - 1)
          local enchId = tonumber(string.sub(entry, eqPos + 1))
          if slotName ~= "" and enchId and enchId > 0 then
            broadcast.enchants[slotName] = enchId
          end
        end
      end
    end
    if LeafVE.UI and LeafVE.UI.cardCurrentPlayer and Lower(LeafVE.UI.cardCurrentPlayer) == nameLower then
      if LeafVE.UI.gearPopup and LeafVE.UI.gearPopup:IsVisible() then
        LeafVE.UI:RefreshGearPopup(LeafVE.UI.cardCurrentPlayer)
      end
    end
    return

  -- Handle gear stats cache broadcast from a guild member
  elseif string.sub(message, 1, 7) == "GSTATS:" then
    local rest = string.sub(message, 8)
    local firstColon = string.find(rest, ":")
    if not firstColon then return end
    local declaredName = string.sub(rest, 1, firstColon - 1)
    if Lower(sender) ~= Lower(ShortName(declaredName) or declaredName) then return end
    rest = string.sub(rest, firstColon + 1)
    local secondColon = string.find(rest, ":")
    if not secondColon then return end
    local updatedAt = tonumber(string.sub(rest, 1, secondColon - 1)) or Now()
    local statData = string.sub(rest, secondColon + 1)

    EnsureDB()
    local nameLower = Lower(sender)
    if not LeafVE_GlobalDB.gearCache[nameLower] then LeafVE_GlobalDB.gearCache[nameLower] = {} end
    if not LeafVE_GlobalDB.gearCache[nameLower].broadcast then
      LeafVE_GlobalDB.gearCache[nameLower].broadcast = {updatedAt = 0, slots = {}, icons = {}, enchants = {}, stats = {}}
    end
    local broadcast = LeafVE_GlobalDB.gearCache[nameLower].broadcast
    if updatedAt > (broadcast.updatedAt or 0) then
      broadcast.stats = {}
    end
    if updatedAt >= (broadcast.updatedAt or 0) then
      broadcast.updatedAt = updatedAt
      if not broadcast.stats then broadcast.stats = {} end
      local startPos = 1
      while startPos <= string.len(statData) do
        local commaPos = string.find(statData, ",", startPos)
        local entry
        if commaPos then
          entry = string.sub(statData, startPos, commaPos - 1)
          startPos = commaPos + 1
        else
          entry = string.sub(statData, startPos)
          startPos = string.len(statData) + 1
        end
        local eqPos = string.find(entry, "=")
        if eqPos then
          local statName = string.sub(entry, 1, eqPos - 1)
          local statValue = tonumber(string.sub(entry, eqPos + 1))
          if statName ~= "" and statValue then
            broadcast.stats[statName] = statValue
          end
        end
      end
    end
    if LeafVE.UI and LeafVE.UI.cardCurrentPlayer and Lower(LeafVE.UI.cardCurrentPlayer) == nameLower then
      if LeafVE.UI.gearPopup and LeafVE.UI.gearPopup:IsVisible() then
        LeafVE.UI:RefreshGearPopup(LeafVE.UI.cardCurrentPlayer)
      end
    end
    return

  -- Handle selected spec cache broadcast from a guild member
  elseif string.sub(message, 1, 6) == "GSPEC:" then
    local rest = string.sub(message, 7)
    local p1 = string.find(rest, ":")
    if not p1 then return end
    local declaredName = string.sub(rest, 1, p1 - 1)
    if Lower(sender) ~= Lower(ShortName(declaredName) or declaredName) then return end
    local rest2 = string.sub(rest, p1 + 1)
    local p2 = string.find(rest2, ":")
    if not p2 then return end
    local updatedAt = tonumber(string.sub(rest2, 1, p2 - 1)) or Now()
    local rest3 = string.sub(rest2, p2 + 1)
    local p3 = string.find(rest3, ":")
    if not p3 then return end
    local classTag = string.upper(string.sub(rest3, 1, p3 - 1))
    local specIndex = tonumber(string.sub(rest3, p3 + 1)) or 1

    EnsureDB()
    if not LeafVE_GlobalDB.specCache then LeafVE_GlobalDB.specCache = {} end
    local nameLower = Lower(sender)
    local oldSpec = LeafVE_GlobalDB.specCache[nameLower]
    if not oldSpec or updatedAt >= (oldSpec.updatedAt or 0) then
      LeafVE_GlobalDB.specCache[nameLower] = {
        class = classTag,
        index = specIndex,
        updatedAt = updatedAt,
      }
    end
    if not LeafVE_GlobalDB.gearCache[nameLower] then LeafVE_GlobalDB.gearCache[nameLower] = {} end
    if not LeafVE_GlobalDB.gearCache[nameLower].broadcast then
      LeafVE_GlobalDB.gearCache[nameLower].broadcast = {updatedAt = 0, slots = {}, icons = {}, enchants = {}, stats = {}}
    end
    LeafVE_GlobalDB.gearCache[nameLower].broadcast.spec = BuildSpecSnapshotFor(classTag, specIndex)

    if LeafVE.UI and LeafVE.UI.cardCurrentPlayer and Lower(LeafVE.UI.cardCurrentPlayer) == nameLower then
      LeafVE.UI:ShowPlayerCard(LeafVE.UI.cardCurrentPlayer)
      if LeafVE.UI.gearPopup and LeafVE.UI.gearPopup:IsVisible() then
        LeafVE.UI:RefreshGearPopup(LeafVE.UI.cardCurrentPlayer)
      end
    end
    return

  -- Handle point transaction broadcast from a guild member
  elseif string.sub(message, 1, 5) == "PTXN:" then
    if not IsSenderCompatible(sender) then return end
    local rest = string.sub(message, 6)
    -- Format: playerName\31amount\31timestamp\31type\31reason
    local p1 = string.find(rest, SEP)
    if not p1 then return end
    local txnName = string.sub(rest, 1, p1 - 1)
    -- Verify sender matches declared name (anti-spoof)
    local shortTxnName = ShortName(txnName)
    if Lower(sender) ~= Lower(shortTxnName or txnName) then return end
    local rest2 = string.sub(rest, p1 + 1)
    local p2 = string.find(rest2, SEP)
    if not p2 then return end
    local amount = tonumber(string.sub(rest2, 1, p2 - 1))
    local rest3 = string.sub(rest2, p2 + 1)
    local p3 = string.find(rest3, SEP)
    if not p3 then return end
    local timestamp = tonumber(string.sub(rest3, 1, p3 - 1))
    local rest4 = string.sub(rest3, p3 + 1)
    local p4 = string.find(rest4, SEP)
    if not p4 then return end
    local txnType = string.sub(rest4, 1, p4 - 1)
    local reason = string.sub(rest4, p4 + 1)
    if txnName ~= "" and amount and timestamp then
      EnsureDB()
      local me = ShortName(UnitName("player"))
      -- Don't duplicate our own transactions (we already stored locally)
      if not (me and Lower(me) == Lower(txnName)) then
        if not LeafVE_DB.pointHistory[txnName] then
          LeafVE_DB.pointHistory[txnName] = {}
        end

        -- Dedup by exact transaction signature to avoid double-applying retries.
        local isDuplicate = false
        for i = table.getn(LeafVE_DB.pointHistory[txnName]), 1, -1 do
          local e = LeafVE_DB.pointHistory[txnName][i]
          if e and e.timestamp == timestamp and (e.type or "") == (txnType or "")
            and (tonumber(e.amount) or 0) == (amount or 0) and (e.reason or "") == (reason or "") then
            isDuplicate = true
            break
          end
        end

        if not isDuplicate then
          local dateStr = date("%m/%d %H:%M", timestamp)
          table.insert(LeafVE_DB.pointHistory[txnName], {timestamp = timestamp, type = txnType, amount = amount or 0, reason = reason or "", dateStr = dateStr})
          while table.getn(LeafVE_DB.pointHistory[txnName]) > 500 do table.remove(LeafVE_DB.pointHistory[txnName], 1) end

          -- PTXN is owner-authenticated (sender == txnName), so use it to keep
          -- synced leaderboard totals moving in real time between full LBOARD syncs.
          if (txnType == "L" or txnType == "G" or txnType == "S") and amount > 0 then
            local life = LeafVE_DB.lboard.alltime[txnName] or {L = 0, G = 0, S = 0}
            local nL = life.L or 0
            local nG = life.G or 0
            local nS = life.S or 0
            if txnType == "L" then nL = nL + amount
            elseif txnType == "G" then nG = nG + amount
            else nS = nS + amount end

            StoreLifetimeSnapshot(txnName, nL, nG, nS, sender, true, true)
            self:UpsertSharedLeaderboard(txnName, {L = nL, G = nG, S = nS}, nil, WeekKey(timestamp))

            local wk = WeekKey(timestamp)
            if wk == WeekKey() then
              if type(LeafVE_DB.lboard.weekly[wk]) ~= "table" then LeafVE_DB.lboard.weekly[wk] = {} end
              local w = LeafVE_DB.lboard.weekly[wk][txnName] or {L = 0, G = 0, S = 0}
              if txnType == "L" then w.L = (w.L or 0) + amount
              elseif txnType == "G" then w.G = (w.G or 0) + amount
              else w.S = (w.S or 0) + amount end
              LeafVE_DB.lboard.weekly[wk][txnName] = w
              SetWeeklyEntryWipeVersion(wk, txnName, CurrentWipeVersion())
              self:UpsertSharedLeaderboard(txnName, nil, {L = w.L or 0, G = w.G or 0, S = w.S or 0}, wk)
            end
          end
        end

        -- Refresh live views if open
        if LeafVE.UI and LeafVE.UI.panels then
          if LeafVE.UI.panels.liveHistory and LeafVE.UI.panels.liveHistory:IsVisible() then
            LeafVE.UI:RefreshLiveHistory()
          end
          if LeafVE.UI.panels.leaderLife and LeafVE.UI.panels.leaderLife:IsVisible() then
            LeafVE.UI:RefreshLeaderboard("leaderLife")
          end
          if LeafVE.UI.panels.leaderWeek and LeafVE.UI.panels.leaderWeek:IsVisible() then
            LeafVE.UI:RefreshLeaderboard("leaderWeek")
          end
        end
      end
    end
    return

  -- Handle group award broadcast from guildie broadcaster
  elseif string.sub(message, 1, 9) == "GRPAWARD:" then
    -- Parse "GRPAWARD:pointsPerGuildie|numGuildies|guildie1,guildie2,..."
    local rest = string.sub(message, 10)
    local p1 = string.find(rest, "|")
    if not p1 then return end
    local pointsPerGuildie = tonumber(string.sub(rest, 1, p1 - 1))
    local rest2 = string.sub(rest, p1 + 1)
    local p2 = string.find(rest2, "|")
    if not p2 then return end
    local numGuildies = tonumber(string.sub(rest2, 1, p2 - 1))
    local guildieNames = string.sub(rest2, p2 + 1)
    if not pointsPerGuildie or not numGuildies then return end
    if numGuildies <= 0 then return end
    -- Verify sender is the expected guildie broadcaster: alphabetically-first among
    -- {sender} ∪ {guildies in message}.  This mirrors the election in OnGroupUpdate.
    local broadcasterCandidates = {sender}
    local bpos = 1
    local bsearch = guildieNames .. ","
    while bpos <= string.len(bsearch) do
      local bcomma = string.find(bsearch, ",", bpos)
      if not bcomma then break end
      table.insert(broadcasterCandidates, string.sub(bsearch, bpos, bcomma - 1))
      bpos = bcomma + 1
    end
    table.sort(broadcasterCandidates)
    if Lower(sender) ~= Lower(broadcasterCandidates[1]) then return end
    local playerName = ShortName(UnitName("player"))
    if not playerName then return end
    -- Ignore if we are the broadcaster (we already awarded ourselves in OnGroupUpdate)
    if Lower(playerName) == Lower(sender) then return end
    -- Verify this player is in the guildie list broadcast by the guildie broadcaster
    local inList = false
    local pos = 1
    local searchStr = guildieNames .. ","
    while pos <= string.len(searchStr) do
      local commaPos = string.find(searchStr, ",", pos)
      if not commaPos then break end
      local entry = string.sub(searchStr, pos, commaPos - 1)
      if Lower(entry) == Lower(playerName) then inList = true break end
      pos = commaPos + 1
    end
    if not inList then return end
    local now = Now()
    local groupInterval = self:GetConfiguredGroupInterval()
    local incomingTick = math.floor(now / groupInterval)
    if self.lastGroupAwardTick and incomingTick <= self.lastGroupAwardTick then
      self.grpAwardFallbackAt = nil
      return
    end
    -- AFK check (each member's own state still matters)
    if self:IsPlayerInactive(false) then
      self.lastGroupAwardTick = incomingTick
      self.lastGroupAwardTime = now
      self.grpAwardFallbackAt = nil
      Print("|cFFFF4444Group points skipped - you appear to be AFK!|r")
      return
    end
    -- Apply points with local daily-cap enforcement via shared helper
    self:ApplyGroupPointAward(playerName, pointsPerGuildie, numGuildies, guildieNames)
    -- Mark this tick as done and clear the fallback timer
    self.lastGroupAwardTick = incomingTick
    self.lastGroupAwardTime = now
    self.grpAwardFallbackAt = nil
    return

  end  -- ← CLOSE THE OnAddonMessage FUNCTION
end
      
      function LeafVE:ReceiveLeaderboardData(sender, playerData)
  EnsureDB()
  PruneLeaderboardForCurrentWipe()

  -- Parse "L:PlayerName:L:G:S" (lifetime) or "W<weekKey>:PlayerName:L:G:S" (weekly, new format)
  -- Also accepts old "W:PlayerName:L:G:S" (unknown week -> stored under current week key)
  local colonPos1 = string.find(playerData, ":")
  if not colonPos1 then return end

  local dataType = string.sub(playerData, 1, colonPos1 - 1) -- "L", "W", or "W20260217"
  local rest = string.sub(playerData, colonPos1 + 1)

  local colonPos2 = string.find(rest, ":")
  if not colonPos2 then return end

  local playerName = ShortName(string.sub(rest, 1, colonPos2 - 1))
  if not playerName then return end
  local rest2 = string.sub(rest, colonPos2 + 1)

  local colonPos3 = string.find(rest2, ":")
  if not colonPos3 then return end

  local L = tonumber(string.sub(rest2, 1, colonPos3 - 1)) or 0
  local rest3 = string.sub(rest2, colonPos3 + 1)

  local colonPos4 = string.find(rest3, ":")
  if not colonPos4 then return end

  local G = tonumber(string.sub(rest3, 1, colonPos4 - 1)) or 0
  local S = tonumber(string.sub(rest3, colonPos4 + 1)) or 0
  local senderIsOwner = SamePlayerName(sender, playerName)

  if dataType == "L" then
    local newTotal = L + G + S
    local existingEntry = LeafVE_DB.lboard.alltime[playerName]
    local existingTotal = existingEntry and ((existingEntry.L or 0) + (existingEntry.G or 0) + (existingEntry.S or 0)) or 0
    local meta = LeafVE_DB.lboard.updatedAt[playerName]
    local existingAuthoritative = (type(meta) == "table" and meta.lifetimeAuthoritative == true) and true or false

    if senderIsOwner then
      -- Owner snapshots are authoritative and can overwrite stale highs/lows.
      if newTotal > 0 then
        StoreLifetimeSnapshot(playerName, L, G, S, sender, true, true)
        self:UpsertSharedLeaderboard(playerName, {L = L, G = G, S = S}, nil, WeekKey(), true)
      else
        ClearLifetimeSnapshot(playerName, sender, true)
      end
    elseif (newTotal > 0) and (not existingAuthoritative) and newTotal > existingTotal then
      StoreLifetimeSnapshot(playerName, L, G, S, sender, false, false)
      self:UpsertSharedLeaderboard(playerName, {L = L, G = G, S = S}, nil, WeekKey())
    end

  elseif string.sub(dataType, 1, 1) == "W" then
    local wk = string.sub(dataType, 2)
    if wk == "" then wk = WeekKey() end
    local currentWk = WeekKey()
    if wk ~= currentWk then return end

    local newTotal = L + G + S
    local existingEntry = type(LeafVE_DB.lboard.weekly[wk]) == "table" and LeafVE_DB.lboard.weekly[wk][playerName]
    local existingTotal = existingEntry and ((existingEntry.L or 0) + (existingEntry.G or 0) + (existingEntry.S or 0)) or 0

    if type(LeafVE_DB.lboard.weekly[wk]) ~= "table" then LeafVE_DB.lboard.weekly[wk] = {} end
    if senderIsOwner then
      if newTotal > 0 then
        LeafVE_DB.lboard.weekly[wk][playerName] = {L = L, G = G, S = S}
        SetWeeklyEntryWipeVersion(wk, playerName, CurrentWipeVersion())
        self:UpsertSharedLeaderboard(playerName, nil, {L = L, G = G, S = S}, wk, true)
      else
        LeafVE_DB.lboard.weekly[wk][playerName] = nil
        ClearWeeklyEntryWipeVersion(wk, playerName)
        if LeafVE_GlobalDB.lboardCache and type(LeafVE_GlobalDB.lboardCache.weekly[wk]) == "table" then
          LeafVE_GlobalDB.lboardCache.weekly[wk][playerName] = nil
        end
      end
    elseif newTotal > 0 and newTotal > existingTotal then
      LeafVE_DB.lboard.weekly[wk][playerName] = {L = L, G = G, S = S}
      SetWeeklyEntryWipeVersion(wk, playerName, CurrentWipeVersion())
      self:UpsertSharedLeaderboard(playerName, nil, {L = L, G = G, S = S}, wk)
    end

    -- Weekly totals are a hard lower bound for lifetime totals.
    -- If lifetime is missing/stale below this week's value, promote it.
    local lifeTotal = LboardEntryTotal(LeafVE_DB.lboard.alltime[playerName])
    if newTotal > lifeTotal then
      if senderIsOwner then
        StoreLifetimeSnapshot(playerName, L, G, S, sender, true, true)
        self:UpsertSharedLeaderboard(playerName, {L = L, G = G, S = S}, nil, wk, true)
      else
        StoreLifetimeSnapshot(playerName, L, G, S, sender, false, false)
        self:UpsertSharedLeaderboard(playerName, {L = L, G = G, S = S}, nil, wk)
      end
    end
  end
  -- Leaderboard sync must never award badges; it only reconciles point snapshots.
  self:CacheBadgeProgress(playerName)
end

function FindUnitToken(playerName)
  if UnitName("player") == playerName then return "player" end
  if UnitExists("target") and UnitName("target") == playerName then return "target" end
  for i = 1, 4 do local unit = "party"..i if UnitExists(unit) and UnitName(unit) == playerName then return unit end end
  for i = 1, 40 do local unit = "raid"..i if UnitExists(unit) and UnitName(unit) == playerName then return unit end end
  return nil
end

function LeafVE:PurgeStaleWeeklyData()
  EnsureDB()
  local currentWk = WeekKey()
  local staleWeeks = {}

  for wk in pairs(LeafVE_DB.lboard.weekly or {}) do
    if wk ~= currentWk then
      staleWeeks[wk] = true
    end
  end

  local sharedWeekly = LeafVE_GlobalDB and LeafVE_GlobalDB.lboardCache and LeafVE_GlobalDB.lboardCache.weekly
  if type(sharedWeekly) == "table" then
    for wk in pairs(sharedWeekly) do
      if wk ~= currentWk then
        staleWeeks[wk] = true
      end
    end
  end

  for wk in pairs(staleWeeks) do
    self:SnapshotWeeklyLeaderboardWinner(wk, Now())
    LeafVE_DB.lboard.weekly[wk] = nil
    if LeafVE_DB.lboard.weeklyVersion then
      LeafVE_DB.lboard.weeklyVersion[wk] = nil
    end
    if sharedWeekly then
      sharedWeekly[wk] = nil
    end
  end
end

function AggForWeekKey(wk)
  EnsureDB()
  local startTS = WeekStartTSFromKey(wk)
  local agg = {}
  local bucket = CurrentWipeVersion()
  if not startTS then
    return agg, nil
  end

  for d = 0, 6 do
    local dk = DayKeyFromTS(startTS + d * SECONDS_PER_DAY)
    if LeafVE_DB.global[dk] then
      for name, t in pairs(LeafVE_DB.global[dk]) do
        if PointBucketForEntry(t) == bucket then
          if not agg[name] then agg[name] = {L = 0, G = 0, S = 0} end
          agg[name].L = agg[name].L + (t.L or 0)
          agg[name].G = agg[name].G + (t.G or 0)
          agg[name].S = agg[name].S + (t.S or 0)
        end
      end
    end
  end

  return agg, startTS
end

function AggForThisWeek()
  EnsureDB() local startTS = WeekStartTS(Now()) local agg = {}
  local bucket = CurrentWipeVersion()
  for d = 0, 6 do
    local dk = DayKeyFromTS(startTS + d * SECONDS_PER_DAY)
    if LeafVE_DB.global[dk] then
      for name, t in pairs(LeafVE_DB.global[dk]) do
        if PointBucketForEntry(t) == bucket then
          if not agg[name] then agg[name] = {L = 0, G = 0, S = 0} end
          agg[name].L = agg[name].L + (t.L or 0)
          agg[name].G = agg[name].G + (t.G or 0)
          agg[name].S = agg[name].S + (t.S or 0)
        end
      end
    end
  end
  return agg, startTS
end

function LeafVE:GetWeeklyLeaderboardLeadersForWeek(wk)
  EnsureDB()
  wk = tostring(wk or WeekKey())

  local mergedSyncedWeek = {}
  local localWeekly = type(LeafVE_DB.lboard.weekly[wk]) == "table" and LeafVE_DB.lboard.weekly[wk] or {}
  local sharedWeekly = LeafVE_GlobalDB and LeafVE_GlobalDB.lboardCache and type(LeafVE_GlobalDB.lboardCache.weekly[wk]) == "table"
    and LeafVE_GlobalDB.lboardCache.weekly[wk] or {}

  for name, pts in pairs(sharedWeekly) do
    mergedSyncedWeek[name] = {L = pts.L or 0, G = pts.G or 0, S = pts.S or 0}
  end
  for name, pts in pairs(localWeekly) do
    if LboardEntryTotal(pts) > LboardEntryTotal(mergedSyncedWeek[name]) then
      mergedSyncedWeek[name] = {L = pts.L or 0, G = pts.G or 0, S = pts.S or 0}
    end
  end

  local localWeek = nil
  if wk == WeekKey() then
    localWeek = AggForThisWeek()
  else
    localWeek = AggForWeekKey(wk)
  end

  local me = ShortName(UnitName("player"))
  local leaders = {}
  local seen = {}

  for name in pairs(localWeek or {}) do
    seen[name] = true
  end
  for name in pairs(mergedSyncedWeek) do
    seen[name] = true
  end

  for name in pairs(seen) do
    local localPts = localWeek and localWeek[name] or nil
    local syncedPts = mergedSyncedWeek[name]
    local pts = nil
    if SamePlayerName(name, me) then
      pts = localPts or syncedPts
    else
      pts = syncedPts or localPts
    end

    local total = LboardEntryTotal(pts)
    if total > 0 then
      table.insert(leaders, {
        name = name,
        total = total,
        L = pts and (pts.L or 0) or 0,
        G = pts and (pts.G or 0) or 0,
        S = pts and (pts.S or 0) or 0,
      })
    end
  end

  table.sort(leaders, function(a, b)
    if a.total == b.total then
      return Lower(a.name or "") < Lower(b.name or "")
    end
    return a.total > b.total
  end)

  return leaders
end

function LeafVE:GetWeeklyRecapRewards()
  EnsureDB()
  return {
    tonumber(LeafVE_DB.options and LeafVE_DB.options.seasonReward1) or SEASON_REWARD_1,
    tonumber(LeafVE_DB.options and LeafVE_DB.options.seasonReward2) or SEASON_REWARD_2,
    tonumber(LeafVE_DB.options and LeafVE_DB.options.seasonReward3) or SEASON_REWARD_3,
    tonumber(LeafVE_DB.options and LeafVE_DB.options.seasonReward4) or SEASON_REWARD_4,
    tonumber(LeafVE_DB.options and LeafVE_DB.options.seasonReward5) or SEASON_REWARD_5,
  }
end

function GetWeeklyRecapMessageVariantIndex(seedText, variantCount)
  local count = tonumber(variantCount) or 0
  if count < 2 then
    return 1
  end

  local hash = 0
  local seed = tostring(seedText or "")
  for i = 1, string.len(seed) do
    hash = math.mod((hash * 31) + string.byte(seed, i), 2147483647)
  end
  return math.mod(hash, count) + 1
end

function LeafVE:BuildWeeklyRecapPersonalMessage(entry, weekKey)
  if type(entry) ~= "table" then
    return ""
  end

  local rank = tonumber(entry.rank) or 0
  local templates = LeafVE.weeklyRecapRankMessageTemplates and LeafVE.weeklyRecapRankMessageTemplates[rank]
  if type(templates) ~= "table" or table.getn(templates) < 1 then
    return ""
  end

  local variantIndex = GetWeeklyRecapMessageVariantIndex(
    tostring(weekKey or "") .. ":" .. tostring(entry.name or "") .. ":" .. tostring(rank),
    table.getn(templates)
  )
  local template = templates[variantIndex] or templates[1] or ""
  if template == "" then
    return ""
  end
  return string.format(template, tostring(entry.name or "Shinobi"), tonumber(entry.reward) or 0)
end

function LeafVE:GetWeeklyRecapEntryForPlayer(snapshot, playerName)
  playerName = ShortName(playerName)
  if not playerName or type(snapshot) ~= "table" or type(snapshot.entries) ~= "table" then
    return nil
  end

  for i = 1, table.getn(snapshot.entries) do
    local entry = snapshot.entries[i]
    if type(entry) == "table" and SamePlayerName(entry.name, playerName) then
      return entry
    end
  end
  return nil
end

function LeafVE:BuildWeeklyRecapPopupMessage(playerName, snapshot)
  playerName = ShortName(playerName)
  if type(snapshot) ~= "table" or type(snapshot.entries) ~= "table" or table.getn(snapshot.entries) < 1 then
    return ""
  end

  local lines = {
    "|cFF2DD35CLeaf Legends Weekly Recap|r",
    "Last week's winner: |cFFFFD700" .. tostring(snapshot.name or "Unknown") .. "|r with |cFFFFD700" .. tostring(snapshot.total or 0) .. " LP|r.",
    "Top rewards:",
  }

  for i = 1, table.getn(snapshot.entries) do
    local entry = snapshot.entries[i]
    if type(entry) == "table" then
      table.insert(
        lines,
        string.format("%d. %s - %d LP - Prize: %d", tonumber(entry.rank) or i, tostring(entry.name or "Unknown"), tonumber(entry.total) or 0, tonumber(entry.reward) or 0)
      )
    end
  end

  table.insert(lines, "")
  table.insert(lines, tostring(LeafVE.weeklyRecapNoteText or "These are the Leaf Legends."))

  local playerEntry = self:GetWeeklyRecapEntryForPlayer(snapshot, playerName)
  if playerEntry and Trim(playerEntry.message or "") ~= "" then
    table.insert(lines, "")
    table.insert(lines, "|cFFFFD700Your Weekly Message|r")
    table.insert(lines, tostring(playerEntry.message))
  end

  return table.concat(lines, "\n")
end

function LeafVE:BuildWeeklyTopShinobisText(snapshot)
  if type(snapshot) ~= "table" then
    return "|cFF888888No data available|r"
  end

  local rankLabels = {"|cFFFFD7001st|r", "|cFFC0C0C02nd|r", "|cFFCD7F323rd|r", "|cFFFFFFFF4th|r", "|cFFFFFFFF5th|r"}

  local entries = type(snapshot.entries) == "table" and snapshot.entries or nil
  if not entries or table.getn(entries) < 1 then
    if snapshot.name and (tonumber(snapshot.total) or 0) > 0 then
      return string.format("%s %s - |cFFFFD700%d pts|r", rankLabels[1], tostring(snapshot.name), tonumber(snapshot.total) or 0)
    end
    return "|cFF888888No data available|r"
  end

  local lines = {}
  for i = 1, math.min(5, table.getn(entries)) do
    local entry = entries[i]
    if type(entry) == "table" and entry.name and (tonumber(entry.total) or 0) > 0 then
      table.insert(lines, string.format("%s %s - |cFFFFD700%d pts|r", rankLabels[i] or tostring(i), tostring(entry.name), tonumber(entry.total) or 0))
    end
  end

  if table.getn(lines) < 1 then
    return "|cFF888888No data available|r"
  end
  return table.concat(lines, "\n")
end

function LeafVE:MaybeShowWeeklyRecapPopup(force)
  EnsureDB()
  local me = ShortName(UnitName("player"))
  if not me then
    return false
  end

  local currentWeekKey = WeekKey()
  local previousWeekKey = PreviousWeekKey()
  local recap = type(LeafVE_DB.weeklyRecap) == "table" and LeafVE_DB.weeklyRecap or {}
  if type(recap.noticeSeenByPlayer) ~= "table" then
    recap.noticeSeenByPlayer = {}
  end

  if not force and tostring(recap.noticeSeenByPlayer[Lower(me)] or "") == currentWeekKey then
    return false
  end

  local snapshot = self:GetCachedWeeklyWinnerSnapshot(previousWeekKey)
  if type(snapshot) ~= "table" or type(snapshot.entries) ~= "table" or table.getn(snapshot.entries) < 1 then
    snapshot = self:SnapshotWeeklyLeaderboardWinner(previousWeekKey, Now(), true)
  end
  if type(snapshot) ~= "table" or type(snapshot.entries) ~= "table" or table.getn(snapshot.entries) < 1 then
    return false
  end

  recap.noticeSeenByPlayer[Lower(me)] = currentWeekKey
  local message = self:BuildWeeklyRecapPopupMessage(me, snapshot)
  if Trim(message or "") == "" then
    return false
  end
  self:ShowInfoPopup(message)
  return true
end

function LeafVE:SnapshotWeeklyLeaderboardWinner(wk, capturedAt, forceReplace)
  EnsureDB()
  wk = tostring(wk or WeekKey())
  if wk == "" then
    return nil
  end

  local recap = type(LeafVE_DB.weeklyRecap) == "table" and LeafVE_DB.weeklyRecap or {}
  LeafVE_DB.weeklyRecap = recap
  if type(recap.byWeek) ~= "table" then
    recap.byWeek = {}
  end

  local existing = recap.byWeek[wk]
  if type(existing) == "table"
    and type(existing.entries) == "table"
    and table.getn(existing.entries) > 0
    and not forceReplace then
    local lastWinnerWeek = tonumber(recap.lastWinnerWeek) or 0
    if (tonumber(wk) or 0) >= lastWinnerWeek then
      recap.lastWinner = existing
      recap.lastWinnerWeek = wk
    end
    return existing
  end

  local leaders = self:GetWeeklyLeaderboardLeadersForWeek(wk)
  local winner = leaders[1]
  if not winner then
    return nil
  end

  local rewards = self:GetWeeklyRecapRewards()
  local entries = {}
  for i = 1, math.min(5, table.getn(leaders)) do
    local leader = leaders[i]
    local entry = {
      rank = i,
      name = leader.name,
      total = leader.total,
      L = leader.L or 0,
      G = leader.G or 0,
      S = leader.S or 0,
      reward = tonumber(rewards[i]) or 0,
    }
    entry.message = self:BuildWeeklyRecapPersonalMessage(entry, wk)
    entries[i] = entry
  end

  local snapshot = {
    weekKey = wk,
    name = winner.name,
    total = winner.total,
    L = winner.L or 0,
    G = winner.G or 0,
    S = winner.S or 0,
    reward = tonumber(rewards[1]) or 0,
    entries = entries,
    capturedAt = tonumber(capturedAt) or Now(),
  }

  recap.byWeek[wk] = snapshot
  local lastWinnerWeek = tonumber(recap.lastWinnerWeek) or 0
  if (tonumber(wk) or 0) >= lastWinnerWeek then
    recap.lastWinner = snapshot
    recap.lastWinnerWeek = wk
  end

  return snapshot
end

function LeafVE:GetCachedWeeklyWinnerSnapshot(wk)
  EnsureDB()
  wk = tostring(wk or PreviousWeekKey())
  local recap = type(LeafVE_DB.weeklyRecap) == "table" and LeafVE_DB.weeklyRecap or {}
  local byWeek = type(recap.byWeek) == "table" and recap.byWeek or nil
  local snapshot = byWeek and byWeek[wk] or nil
  if not snapshot and type(recap.lastWinner) == "table" and tostring(recap.lastWinner.weekKey or "") == wk then
    snapshot = recap.lastWinner
  end
  return snapshot
end

function LeafVE:ToggleUI()
  EnsureDB()
  
  if not LeafVE.UI or not LeafVE.UI.Build then 
    Print("ERROR: UI not loaded. Check addon file!") 
    return 
  end
  
  if not LeafVE.UI.frame then 
    LeafVE.UI:Build()
  end
  
  if not LeafVE.UI.frame then
    Print("ERROR: UI frame failed to build!")
    return
  end

  LeafVE:HideStaleUIFrames(LeafVE.UI.frame)
  
  if LeafVE.UI.frame:IsVisible() then 
    LeafVE.UI.frame:Hide()
  else 
    LeafVE.UI.frame:Show()
    LeafVE.UI:Refresh()
  end
end

