end

local function FormatShellAgeText(secondsAgo)
  local age = tonumber(secondsAgo) or 0
  if age < 5 then return "just now" end
  if age < 60 then return tostring(math.floor(age)) .. "s ago" end
  if age < SECONDS_PER_HOUR then
    return tostring(math.floor(age / 60)) .. "m ago"
  end
  if age < SECONDS_PER_DAY then
    return tostring(math.floor(age / SECONDS_PER_HOUR)) .. "h ago"
  end
  return tostring(math.floor(age / SECONDS_PER_DAY)) .. "d ago"
end

local function FindBestPlayerSearchMatch(queryText)
  local query = Lower(Trim(tostring(queryText or "")))
  if query == "" then
    return nil
  end

  LeafVE:UpdateGuildRosterCache()

  local bestName = nil
  local bestScore = nil
  local seen = {}

  local function ConsiderCandidate(name)
    name = ShortName(name)
    if not name then return end
    local lowerName = Lower(name)
    if seen[lowerName] then return end
    seen[lowerName] = true

    local score = nil
    if lowerName == query then
      score = 0
    elseif string.find(lowerName, query, 1, true) == 1 then
      score = 1
    elseif string.find(lowerName, query, 1, true) then
      score = 2
    end

    if score and (bestScore == nil or score < bestScore or (score == bestScore and lowerName < Lower(bestName or ""))) then
      bestScore = score
      bestName = name
    end
  end

  for lowerName, info in pairs(LeafVE.guildRosterCache or {}) do
    ConsiderCandidate((type(info) == "table" and info.name) or lowerName)
  end
  for lowerName, info in pairs((LeafVE_DB and LeafVE_DB.persistentRoster) or {}) do
    ConsiderCandidate((type(info) == "table" and info.name) or lowerName)
  end

  return bestName
end

local function GetLegacyAchievementAddon()
  return type(LeafVE_AchTest) == "table" and LeafVE_AchTest or nil
end

local function GetLegacyAchievementAPI()
  local addon = GetLegacyAchievementAddon()
  return addon and type(addon.API) == "table" and addon.API or nil
end

local function GetLegacyAchievementDB()
  return type(LeafVE_AchTest_DB) == "table" and LeafVE_AchTest_DB or nil
end

local function GetLegacyAchievementMeta(achId)
  local addon = GetLegacyAchievementAddon()
  if addon and type(addon.GetAchievementMeta) == "function" then
    local ok, meta = pcall(addon.GetAchievementMeta, achId)
    if ok and type(meta) == "table" then
      return meta
    end
  end
  return nil
end

local function GetLegacyAchievementPoints(playerName)
  local api = GetLegacyAchievementAPI()
  if api and type(api.GetPlayerPoints) == "function" then
    local ok, points = pcall(api.GetPlayerPoints, playerName)
    if ok then
      return tonumber(points) or 0
    end
  end
  return 0
end

local function GetLegacyRecentAchievements(playerName, maxCount)
  local api = GetLegacyAchievementAPI()
  if api and type(api.GetRecentAchievements) == "function" then
    local ok, recent = pcall(api.GetRecentAchievements, playerName, maxCount)
    if ok and type(recent) == "table" then
      return recent
    end
  end
  return {}
end

local function GetLegacyAchievementEquippedTitle(playerName)
  local db = GetLegacyAchievementDB()
  local record = db and db[playerName]
  local title = type(record) == "table" and Trim(tostring(record.equippedTitle or "")) or ""
  if title == "" then
    return nil
  end
  return title
end

local function GetLegacyAchievementStoreForPlayer(playerName)
  local db = GetLegacyAchievementDB()
  local achievements = db and db.achievements
  if type(achievements) ~= "table" then
    return nil
  end

  local perPlayer = achievements[playerName]
  if type(perPlayer) == "table" then
    return perPlayer
  end

  local me = ShortName(UnitName("player"))
  if me and SamePlayerName(playerName, me) then
    return achievements
  end

  return nil
end

local function GetLegacyBroadcastableAchievements()
  local me = ShortName(UnitName("player"))
  if not me then
    return nil
  end
  return GetLegacyAchievementStoreForPlayer(me)
end

