function LeafVE.UI:GetGroupedNavCategoryLabel(categoryKey)
  local category = self:GetGroupedNavCategory(categoryKey)
  return category and category.label or "Leaf Village"
end

function LeafVE.UI:RefreshShellChrome()
  if self.shellTitle then
    local categoryKey = self:GetGroupedNavCategoryForTab(self.activeTab) or self.activeCategory or "profile"
    self.shellTitle:SetText("|cFFFFD700Leaf Village Legends|r")
    if self.shellSection then
      self.shellSection:SetText("|cFF88CCFF" .. self:GetGroupedNavCategoryLabel(categoryKey) .. "|r")
    end
  end

  if self.shellStatusText then
    local now = Now()
    local onlineCount = 0
    LeafVE:UpdateGuildRosterCache()
    for _, info in pairs(LeafVE.guildRosterCache or {}) do
      if type(info) == "table" and info.online then
        onlineCount = onlineCount + 1
      end
    end

    local rosterAge = "waiting"
    if LeafVE.guildRosterCacheTime and LeafVE.guildRosterCacheTime > 0 then
      rosterAge = FormatShellAgeText(now - LeafVE.guildRosterCacheTime)
    end

    local seasonBucket = tonumber(CurrentWipeVersion()) or 0
    local seasonText = seasonBucket > 0 and "Season Active" or "Initial Season"
    local weekResetAt = WeekStartTS(now) + (7 * SECONDS_PER_DAY)
    local resetText = FormatCompactCountdownText(weekResetAt - now)

    self.shellStatusText:SetText(
      string.format(
        "|cFF88CCFF%d online|r   |   Guild sync %s   |   %s   |   Weekly reset %s",
        onlineCount,
        rosterAge,
        seasonText,
        resetText
      )
    )
  end
end

function LeafVE.UI:ApplyShellSearch(queryText)
  local query = Trim(tostring(queryText or ""))
  if query == "" then
    if self.shellSearchBox and self.shellSearchBox.ClearFocus then
      self.shellSearchBox:ClearFocus()
    end
    return
  end

  local matchedPlayer = FindBestPlayerSearchMatch(query)
  if matchedPlayer then
    self.activeTab = "roster"
    self.activeCategory = "guild"
    self.activeNavSubTab = nil
    self.inspectedPlayer = matchedPlayer
    self:Refresh()
    if self.panels and self.panels.roster and self.panels.roster.searchBox and self.panels.roster.searchBox.SetText then
      self.panels.roster.searchBox:SetText(query)
    end
    if self.RefreshRoster then
      self:RefreshRoster()
    end
    self:ShowPlayerCard(matchedPlayer)
    return
  end

  Print("|cFFFFAA00LeafVE|r shell search currently resolves player names first. Full badge, order, and achievement routing is the next pass.")
end

function LeafVE.UI:LayoutLegacyMainTabs()
  local frame = self and self.frame
  if not frame then
    return
  end

  local firstRow = {
    {btn = self.tabWelcome, width = 65},
    {btn = self.tabMe, width = 70},
    {btn = self.tabRoster, width = 60},
    {btn = self.tabLeaderWeek, width = 60},
    {btn = self.tabLeaderLife, width = 65},
    {btn = self.tabAchievements, width = 95},
    {btn = self.tabShoutouts, width = 80},
    {btn = self.tabGuildEvents, width = 88},
    {btn = self.tabHistory, width = 60},
    {btn = self.tabLiveHistory, width = 80},
    {btn = self.tabBadges, width = 65},
    {btn = self.tabOptions, width = 56},
  }

  local previousButton = nil
  for i = 1, table.getn(firstRow) do
    local entry = firstRow[i]
    local button = entry.btn
    if button then
      button:ClearAllPoints()
      button:SetWidth(entry.width)
      if previousButton then
        button:SetPoint("LEFT", previousButton, "RIGHT", 4, 0)
      else
        button:SetPoint("TOPLEFT", frame, "TOPLEFT", 14, -52)
      end
      previousButton = button
    end
  end

  if self.tabAdmin then
    self.tabAdmin:ClearAllPoints()
    self.tabAdmin:SetWidth(50)
    self.tabAdmin:SetPoint("TOPLEFT", self.tabWelcome, "BOTTOMLEFT", 0, -6)
  end

  if self.tabWorkOrderRep then
    self.tabWorkOrderRep:ClearAllPoints()
    self.tabWorkOrderRep:SetWidth(142)
    if self.tabAdmin and self.tabAdmin:IsShown() then
      self.tabWorkOrderRep:SetPoint("LEFT", self.tabAdmin, "RIGHT", 4, 0)
    else
      self.tabWorkOrderRep:SetPoint("TOPLEFT", self.tabWelcome, "BOTTOMLEFT", 0, -6)
    end
  end

  if self.tabJoin then
    self.tabJoin:ClearAllPoints()
    self.tabJoin:SetPoint("TOPLEFT", frame, "TOPLEFT", 14, -52)
    self.tabJoin:SetWidth(300)
  end
end

