function CreateGuildBankRequestButton(parent)
  local btn = CreateFrame("Button", nil, parent)
  btn:SetWidth(240)
  btn:SetHeight(58)
  btn:SetBackdrop({
    bgFile = "Interface\\Buttons\\WHITE8X8",
    edgeFile = "Interface\\Tooltips\\UI-Tooltip-Border",
    tile = false, tileSize = 8, edgeSize = 10,
    insets = {left = 2, right = 2, top = 2, bottom = 2}
  })

  local icon = btn:CreateTexture(nil, "ARTWORK")
  icon:SetPoint("LEFT", btn, "LEFT", 6, 0)
  icon:SetWidth(24)
  icon:SetHeight(24)
  icon:SetTexture(LEAF_FALLBACK)
  btn.icon = icon

  local actionBtn = CreateFrame("Button", nil, btn, "UIPanelButtonTemplate")
  actionBtn:SetWidth(54)
  actionBtn:SetHeight(20)
  actionBtn:SetPoint("RIGHT", btn, "RIGHT", -8, 0)
  SkinButtonAccent(actionBtn)
  SetLeafButtonTextColor(actionBtn, THEME.gold[1], THEME.gold[2], THEME.gold[3], 1, 0.96, 0.7)
  actionBtn.owner = btn
  actionBtn:SetScript("OnClick", function()
    local owner = this.owner
    local request = owner and owner.requestData
    local changed, err
    if not request or not owner.actionType then return end
    if owner.actionType == "cancel" then
      changed, err = LeafVE:CancelGuildBankItemRequest(request.id)
    elseif owner.actionType == "fulfill" then
      changed, err = LeafVE:FulfillGuildBankItemRequest(request.id)
    end
    if changed and LeafVE and LeafVE.UI and LeafVE.UI.RefreshVisibleGuildBankUI then
      LeafVE.UI:RefreshVisibleGuildBankUI(true)
    end
  end)
  btn.actionBtn = actionBtn

  local nameText = btn:CreateFontString(nil, "OVERLAY", "GameFontNormalSmall")
  nameText:SetPoint("TOPLEFT", icon, "TOPRIGHT", 8, 5)
  nameText:SetPoint("RIGHT", actionBtn, "LEFT", -8, 0)
  nameText:SetJustifyH("LEFT")
  nameText:SetJustifyV("TOP")
  btn.nameText = nameText

  local detailText = btn:CreateFontString(nil, "OVERLAY", "GameFontHighlightSmall")
  detailText:SetPoint("TOPLEFT", nameText, "BOTTOMLEFT", 0, -2)
  detailText:SetPoint("RIGHT", actionBtn, "LEFT", -8, 0)
  detailText:SetJustifyH("LEFT")
  detailText:SetJustifyV("TOP")
  btn.detailText = detailText

  local statusText = btn:CreateFontString(nil, "OVERLAY", "GameFontHighlightSmall")
  statusText:SetPoint("TOPLEFT", detailText, "BOTTOMLEFT", 0, -2)
  statusText:SetPoint("RIGHT", actionBtn, "LEFT", -8, 0)
  statusText:SetJustifyH("LEFT")
  statusText:SetJustifyV("TOP")
  btn.statusText = statusText
  btn.popup = parent and parent.popup

  btn:SetScript("OnEnter", function()
    local request = this.requestData
    if not request then return end
    UpdateGuildBankItemButtonVisual(this, true)
    GameTooltip:SetOwner(this, "ANCHOR_RIGHT")
    GameTooltip:ClearLines()
    GameTooltip:SetHyperlink("item:" .. tostring(request.itemId))
    GameTooltip:AddLine(" ")
    GameTooltip:AddLine("Requester: " .. tostring(request.requester or "Unknown"), 0.85, 0.95, 1.0)
    GameTooltip:AddLine("Requested Quantity: " .. tostring(request.quantity or 1), 1, 0.92, 0.55)
    GameTooltip:AddLine("Requested: " .. FormatGuildBankRequestAge(request.updatedAt or request.createdAt), 0.88, 0.88, 0.88)
    GameTooltip:Show()
  end)
  btn:SetScript("OnLeave", function()
    GameTooltip:Hide()
    UpdateGuildBankItemButtonVisual(this, false)
  end)

  UpdateGuildBankItemButtonVisual(btn, false)
  return btn
end

function UpdateWorkOrderModeButtonVisual(btn, selected)
  if not btn then return end
  ApplyLeafButtonSkin(btn, "mode")
  btn.isSelected = selected and true or nil
  if selected then
    btn:SetBackdropColor(0.09, 0.12, 0.11, 0.94)
    btn:SetBackdropBorderColor(THEME.leaf[1], THEME.leaf[2], THEME.leaf[3], 0.82)
    if btn.text then
      btn.text:SetTextColor(0.95, 0.97, 0.95)
    end
    if btn._leafSelectionFill then
      btn._leafSelectionFill:SetVertexColor(THEME.leaf[1], THEME.leaf[2], THEME.leaf[3], 0.18)
      btn._leafSelectionFill:Show()
    end
    if btn._leafGlow then
      btn._leafGlow:SetVertexColor(THEME.leaf[1], THEME.leaf[2], THEME.leaf[3], 0.24)
      btn._leafGlow:Show()
    end
  else
    btn:SetBackdropColor(0.06, 0.07, 0.09, 0.90)
    btn:SetBackdropBorderColor(0.28, 0.30, 0.35, 0.60)
    if btn.text then
      btn.text:SetTextColor(0.86, 0.88, 0.91)
    end
    if btn._leafSelectionFill then
      btn._leafSelectionFill:Hide()
    end
    if btn._leafGlow then
      btn._leafGlow:Hide()
    end
  end
end

function CreateWorkOrderModeButton(parent, label)
  local btn = CreateFrame("Button", nil, parent)
  btn:SetWidth(104)
  btn:SetHeight(22)
  btn.leafButtonStyle = "mode"
  btn:SetBackdrop({
    bgFile = LEAFVE_TEXTURES.tooltipBG,
    edgeFile = LEAFVE_TEXTURES.tooltipBorder,
    tile = true, tileSize = 16, edgeSize = 16,
    insets = {left = 4, right = 4, top = 4, bottom = 4}
  })
  btn:SetBackdropColor(0.06, 0.07, 0.09, 0.90)
  btn:SetBackdropBorderColor(0.28, 0.30, 0.35, 0.60)

  local text = btn:CreateFontString(nil, "OVERLAY", "GameFontNormalSmall")
  text:SetPoint("CENTER", btn, "CENTER", 0, 0)
  text:SetText(label or "")
  btn.text = text
  text:SetTextColor(0.86, 0.88, 0.91)

  ApplyLeafButtonSkin(btn, "mode")

  btn:SetScript("OnEnter", function()
    if not this:IsEnabled() or this.isSelected then return end
    this:SetBackdropColor(0.08, 0.10, 0.12, 0.96)
    if this._leafGlow then
      this._leafGlow:SetVertexColor(THEME.gold[1], THEME.gold[2], THEME.gold[3], 0.18)
      this._leafGlow:Show()
    end
  end)
  btn:SetScript("OnLeave", function()
    if not this:IsEnabled() then return end
    UpdateWorkOrderModeButtonVisual(this, this.isSelected)
  end)

  UpdateWorkOrderModeButtonVisual(btn, false)
  return btn
end

function CreateLeafVEStaticMoneyFrame(parent, frameName)
  if not frameName or frameName == "" then
    if not LeafVE then
      LeafVE = {}
    end
    LeafVE.staticMoneyFrameSerial = (LeafVE.staticMoneyFrameSerial or 0) + 1
    frameName = "LeafVE_StaticMoneyFrame" .. tostring(LeafVE.staticMoneyFrameSerial)
  end
  local display = CreateFrame("Frame", frameName, parent, "SmallMoneyFrameTemplate")
  display:SetWidth(120)
  display:SetHeight(16)
  display.small = 1
  display.staticMoney = 0

  local prevThis = this
  this = display
  if SmallMoneyFrame_OnLoad then
    SmallMoneyFrame_OnLoad()
  end
  if MoneyFrame_SetType then
    MoneyFrame_SetType("STATIC")
  end
  this = prevThis
  return display
end

